            recipientMap.put("suffix", "@s.whatsapp.net");
        } else if (parts.length >= 2) {
            recipientMap.put("phone", parts[0].trim());
            recipientMap.put("suffix", parts[1].trim());
        }

        if (!recipientMap.isEmpty()) {
            defaultRecipientsList.add(recipientMap);
        }
    }
}

if (inputPathsString != null && inputPathsString.length() > 0) {
    String[] newPaths = inputPathsString.split(",");

    for (int i = 0; i < newPaths.length; i++) {
        String path = newPaths[i].trim();
        if (path.length() == 0) {
            continue;
        }

        // Validate image extension
        String lowerPath = path.toLowerCase();
        boolean isValidImage = lowerPath.endsWith(".jpg") || lowerPath.endsWith(".jpeg") || 
                               lowerPath.endsWith(".png") || lowerPath.endsWith(".gif") || 
                               lowerPath.endsWith(".bmp") || lowerPath.endsWith(".webp");

        if (!isValidImage) {
            tasker.log("Invalid image format (only JPG, JPEG, PNG, GIF, BMP, WEBP): " + path);
            continue;
        }

        boolean pathExists = false;
        for (int j = 0; j < itemsList.size(); j++) {
            Map existingItem = (Map) itemsList.get(j);
            String existingPath = (String) existingItem.get("path");
            if (existingPath != null && path.equals(existingPath)) {
                pathExists = true;
                break;
            }
        }

        if (!pathExists) {
            Map newItem = new HashMap();

            // Add recipients (use provided or empty list)
            if (defaultRecipientsList.size() > 0) {
                newItem.put("recipients", defaultRecipientsList);
            } else {
                newItem.put("recipients", new ArrayList());
            }

            newItem.put("type", "image_message");
            newItem.put("caption", inputCaption);
            newItem.put("is_forwarded", Boolean.parseBoolean(inputIsForwarded));
            newItem.put("view_once", Boolean.parseBoolean(inputViewOnce));
            newItem.put("duration", 0);

            Map schedule = new HashMap();
            schedule.put("days", new ArrayList());
            schedule.put("times", new ArrayList());
            newItem.put("schedule", schedule);

            newItem.put("path", path);

            itemsList.add(newItem);
            tasker.log("New image added: " + path);
        } else {
            tasker.log("Image already exists, ignored: " + path);
        }
    }
}

rootData.put("items", itemsList);

String updatedJson = tasker.toJson(rootData, true);

writeJsonFile(jsonStatusPath, updatedJson);

return "Image(s) added successfully! Total items: " + itemsList.size();

import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Iterator;
import java.util.ArrayList;
import org.json.JSONException;
import org.json.JSONObject;
import org.json.JSONArray;

/* Helper function to recursively parse JSON objects and arrays into Java Maps and Lists. */
Object parseJsonValue(Object jsonValue) {
    if (jsonValue instanceof JSONObject) {
        Map map = new HashMap();
        JSONObject obj = (JSONObject) jsonValue;
        Iterator keys = obj.keys();
        while (keys.hasNext()) {
            String key = (String) keys.next();
            map.put(key, parseJsonValue(obj.get(key))); /* Recursive call for nested values. */
        }
        return map;
    } else if (jsonValue instanceof JSONArray) {
        List list = new ArrayList();
        JSONArray array = (JSONArray) jsonValue;
        for (int i = 0; i < array.length(); i++) {
            list.add(parseJsonValue(array.get(i))); /* Recursive call for array elements. */
        }
        return list;
    } else {
        return jsonValue; /* Return primitives, strings, etc. as is. */
    }
}

phone = tasker.getVariable("device_id");
if (phone == null) {
    throw new JavaCodeException("Tasker variable 'device_id' is null. Please ensure it is set.");
}
phone = phone.replaceAll("\\D", "");

httpDataString = tasker.getVariable("http_data");
if (httpDataString == null) {
    throw new JavaCodeException("Tasker variable 'http_data' is null. Please ensure it is set.");
}

data = null;
try {
    /* Parse the entire JSON string using the helper function to convert to Map/List. */
    JSONObject jsonObject = new JSONObject(httpDataString);
    data = (Map) parseJsonValue(jsonObject);
} catch (JSONException e) {
    /* Catch JSON parsing errors and report to Tasker. */
    throw new JavaCodeException("Failed to parse HTTP data as JSON: " + e.getMessage());
}

result = "";

/* Proceed only if data was successfully parsed and contains expected keys. */
if (data != null && data.containsKey("code") && "SUCCESS".equals(data.get("code"))) {
    /* 'results' will now be a java.util.List due to the parseJsonValue helper. */
    results = (List) data.get("results");
    if (results != null) {
        for (i = 0; i < results.size(); i++) {
            d = (Map) results.get(i);
            if (d.containsKey("jid")) {
                jid = (String) d.get("jid");
                if (jid != null) {
                    parts = jid.split("@");
                    if (parts.length > 0) {
                        jidPhone = parts[0].replaceAll("\\D", "");
                        if (jidPhone.equals(phone)) {
                            result = (String) d.get("id");
                            break;
                        }
                    }
                }
            }
        }
    }
}

tasker.setVariable("device_id_output", result);

