formattedBirthday = null;
if (birthday != null && birthday.length() > 0) {
    cleanBirthday = birthday.replaceAll("[^0-9]", "");

    if (cleanBirthday.length() == 8) {
        day = cleanBirthday.substring(0, 2);
        month = cleanBirthday.substring(2, 4);
        year = cleanBirthday.substring(4, 8);
        formattedBirthday = year + "-" + month + "-" + day;
    } else if (cleanBirthday.length() == 6) {
        day = cleanBirthday.substring(0, 2);
        month = cleanBirthday.substring(2, 4);
        year = "20" + cleanBirthday.substring(4, 6);
        formattedBirthday = year + "-" + month + "-" + day;
    } else {
        if (birthday.indexOf("-") > 0) {
            parts = birthday.split("-");
            if (parts.length == 3) {
                day = parts[0];
                month = parts[1];
                year = parts[2];
                if (day.length() == 2 && month.length() == 2 && year.length() == 4) {
                    formattedBirthday = year + "-" + month + "-" + day;
                }
            }
        } else if (birthday.indexOf("/") > 0) {
            parts = birthday.split("/");
            if (parts.length == 3) {
                day = parts[0];
                month = parts[1];
                year = parts[2];
                if (day.length() == 2 && month.length() == 2 && year.length() == 4) {
                    formattedBirthday = year + "-" + month + "-" + day;
                }
            }
        }
    }
}

formatPhoneNumber(rawNumber) {
    cleaned = rawNumber.replaceAll("[^0-9]", "");

    isBrazilian = false;
    numberToFormat = cleaned;

    if (cleaned.startsWith("55")) {
        isBrazilian = true;
        numberToFormat = cleaned.substring(2);
    } else if ((cleaned.length() == 10 || cleaned.length() == 11) && !cleaned.startsWith("55")) {
        isBrazilian = true;
        numberToFormat = cleaned;
    }

    if (isBrazilian && numberToFormat.length() >= 10) {
        ddd = numberToFormat.substring(0, 2);
        numberPart = numberToFormat.substring(2);

        if (numberPart.length() == 8) {
            part1 = numberPart.substring(0, 4);
            part2 = numberPart.substring(4, 8);
            formatted = "+55 " + ddd + " 9" + part1 + "-" + part2;
            return formatted;
        } else if (numberPart.length() == 9) {
            if (numberPart.substring(0, 1).equals("9")) {
                mainNumber = numberPart.substring(1);
                part1 = mainNumber.substring(0, 4);
                part2 = mainNumber.substring(4, 8);
                formatted = "+55 " + ddd + " 9" + part1 + "-" + part2;
                return formatted;
            } else {
                part1 = numberPart.substring(0, 4);
                part2 = numberPart.substring(4, 8);
                formatted = "+55 " + ddd + " 9" + part1 + "-" + part2;
                return formatted;
            }
        } else if (numberPart.length() > 9) {
            if (numberPart.length() >= 9) {
                last9 = numberPart.substring(numberPart.length() - 9);
                if (last9.substring(0, 1).equals("9")) {
                    mainNumber = last9.substring(1);
                    part1 = mainNumber.substring(0, 4);
                    part2 = mainNumber.substring(4, 8);
                    formatted = "+55 " + ddd + " 9" + part1 + "-" + part2;
                    return formatted;
                } else {
                    part1 = numberPart.substring(numberPart.length() - 8, numberPart.length() - 4);
                    part2 = numberPart.substring(numberPart.length() - 4);
                    formatted = "+55 " + ddd + " 9" + part1 + "-" + part2;
                    return formatted;
                }
            }
        }
    }

    for (i = 1; i <= 3; i++) {
        if (cleaned.length() > i + 8) {
            countryCode = cleaned.substring(0, i);
            remaining = cleaned.substring(i);
            if (remaining.length() >= 8) {
                for (j = 1; j <= 3; j++) {
                    if (remaining.length() > j + 8) {
                        areaCode = remaining.substring(0, j);
                        numberPart = remaining.substring(j);
                        if (numberPart.length() >= 8) {
                            part1 = numberPart.substring(0, 4);
                            part2 = numberPart.substring(4, 8);
                            formatted = "+" + countryCode + " " + areaCode + " " + part1 + "-" + part2;
                            return formatted;
                        }
                    }
                }
                numberPart = remaining.substring(remaining.length() - 8);
                areaCode = remaining.substring(0, remaining.length() - 8);
                part1 = numberPart.substring(0, 4);
                part2 = numberPart.substring(4, 8);
                formatted = "+" + countryCode + " " + areaCode + " " + part1 + "-" + part2;
                return formatted;
            }
        }
    }

    return rawNumber;
}

