photoBytes = null;
photoStatus = "No photo provided";
if (photoPath != null && photoPath.length() > 0) {
    try {
        if (photoPath.startsWith("http://") || photoPath.startsWith("https://")) {
            url = new java.net.URL(photoPath);
            connection = url.openConnection();
            connection.setConnectTimeout(10000);
            connection.setReadTimeout(10000);
            inputStream = connection.getInputStream();

            outputStream = new java.io.ByteArrayOutputStream();
            buffer = new byte[4096];
            bytesRead = 0;
            while ((bytesRead = inputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
            }
            photoBytes = outputStream.toByteArray();
            outputStream.close();
            inputStream.close();

            photoStatus = "Photo downloaded from URL";
        } else {
            photoFile = new java.io.File(photoPath);
            if (photoFile.exists()) {
                fis = new java.io.FileInputStream(photoFile);
                photoBytes = new byte[(int) photoFile.length()];
                fis.read(photoBytes);
                fis.close();
                photoStatus = "Photo loaded from local file";
            } else {
                error = "ERROR: Photo file not found: " + photoPath;
                tasker.setVariable("error", error);
                return error;
            }
        }

        if (photoBytes == null || photoBytes.length == 0) {
            error = "ERROR: Failed to load photo from: " + photoPath;
            tasker.setVariable("error", error);
            return error;
        }
    } catch (java.net.UnknownHostException e) {
        error = "ERROR: Network error - unable to download photo from URL: " + photoPath;
        tasker.setVariable("error", error);
        return error;
    } catch (java.io.FileNotFoundException e) {
        error = "ERROR: File not found: " + photoPath;
        tasker.setVariable("error", error);
        return error;
    } catch (Exception e) {
        error = "ERROR: Failed to load photo: " + e.getMessage();
        tasker.setVariable("error", error);
        return error;
    }
}

