String readJsonFile(String filePath) {
    try {
        File file = new File(filePath);
        if (file.exists()) {
            return new String(Files.readAllBytes(Paths.get(filePath)), "UTF-8");
        }
    } catch (Exception e) {
        addLog("Error reading: " + e.getMessage());
    }
    return null;
}

void writeJsonFile(String filePath, String content) {
    try {
        Files.write(Paths.get(filePath), content.getBytes("UTF-8"));
    } catch (Exception e) {
        addLog("Error writing: " + e.getMessage());
    }
}

String getFileContentType(String filePath) {
    if (filePath.toLowerCase().endsWith(".jpg") || filePath.toLowerCase().endsWith(".jpeg")) {
        return "image/jpeg";
    } else if (filePath.toLowerCase().endsWith(".png")) {
        return "image/png";
    } else if (filePath.toLowerCase().endsWith(".gif")) {
        return "image/gif";
    } else if (filePath.toLowerCase().endsWith(".mp4")) {
        return "video/mp4";
    } else if (filePath.toLowerCase().endsWith(".pdf")) {
        return "application/pdf";
    } else if (filePath.toLowerCase().endsWith(".txt")) {
        return "text/plain";
    }
    return "application/octet-stream";
}

/* Fixed phone validation - accepts normal numbers, group IDs, and @lid IDs */
boolean isValidPhone(String phone) {
    if (phone == null || phone.length() == 0) return false;
    String cleanPhone = phone.split("@")[0];

    /* Accepts normal phone numbers (10-15 digits) */
    if (cleanPhone.matches("\\d{10,15}")) return true;

    /* Accepts WhatsApp group IDs (start with 120363, ~18 digits) */
    if (cleanPhone.matches("\\d{16,20}")) return true;

    /* Accepts linked device IDs (@lid) */
    if (cleanPhone.matches("\\d+")) return cleanPhone.length() >= 10;

    return false;
}

boolean isValidFilePath(String filePath) {
    if (filePath == null || filePath.length() == 0) return false;
    File file = new File(filePath);
    return file.exists() && file.isFile();
}

boolean hasValidSchedule(JSONObject schedule) {
    if (schedule == null) return false;

    JSONArray days = schedule.optJSONArray("days");
    JSONArray times = schedule.optJSONArray("times");

    boolean hasDays = (days != null && days.length() > 0);
    boolean hasTimes = (times != null && times.length() > 0);

    return (hasDays || hasTimes);
}

/* Simplified day normalization - supports only Seg, Ter, Qua, Qui, Sex, Sáb, Dom */
String normalizeDay(String day) {
    if (day == null) return "";

    if (day.equals("Seg")) return "Mon";
    if (day.equals("Ter")) return "Tue";
    if (day.equals("Qua")) return "Wed";
    if (day.equals("Qui")) return "Thu";
    if (day.equals("Sex")) return "Fri";
    if (day.equals("Sáb")) return "Sat";
    if (day.equals("Dom")) return "Sun";

    return day;
}

boolean isDayMatch(JSONArray days, String currentDay) {
    if (days == null || days.length() == 0) {
        return true;
    }

    for (int d = 0; d < days.length(); d++) {
        String scheduleDay = days.getString(d);
        String normalizedScheduleDay = normalizeDay(scheduleDay);
        if (normalizedScheduleDay.equals(currentDay)) {
            return true;
        }
    }
    return false;
}

boolean isTimeMatch(JSONArray times, String currentTime) {
    if (times == null || times.length() == 0) {
        return true;
    }

    for (int t = 0; t < times.length(); t++) {
        String scheduleTime = times.getString(t);
        if (currentTime.compareTo(scheduleTime) >= 0) {
            return true;
        }
    }
    return false;
}

String encodeRFC5987(String s) {
    try {
        StringBuilder encoded = new StringBuilder();
        byte[] bytes = s.getBytes("UTF-8");
        for (int i = 0; i < bytes.length; i++) {
            int b = bytes[i] & 0xFF;
            if (b >= 0x20 && b <= 0x7E && b != 0x22 && b != 0x25 && b != 0x3B && b != 0x3D && b != 0x5C) {
                encoded.append((char) b);
            } else {
                encoded.append(String.format("%%%02X", b));
            }
        }
        return encoded.toString();
    } catch (Exception e) {
        return s;
    }
}

String makeHttpRequest(String endpoint, String method, String body, String deviceId) {
    try {
        String fullUrl = apiBaseUrl + endpoint;
        addLog("Request: " + method + " " + fullUrl);

        URL url = new URL(fullUrl);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod(method);
        conn.setRequestProperty("Authorization", authBasic);
        conn.setRequestProperty("Content-Type", "application/json; charset=UTF-8");
        conn.setRequestProperty("Accept", "application/json");
        conn.setRequestProperty("User-Agent", "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36");
        if (deviceId != null && deviceId.length() > 0) {
            conn.setRequestProperty("X-Device-Id", deviceId);
        }
        conn.setConnectTimeout(30000);
        conn.setReadTimeout(30000);

        if (body != null && body.length() > 0 && (method.equals("POST") || method.equals("PUT"))) {
            conn.setDoOutput(true);
            OutputStream os = conn.getOutputStream();
            os.write(body.getBytes("UTF-8"));
            os.flush();
            os.close();
        } else {
            conn.setDoOutput(false);
        }

        int responseCode = conn.getResponseCode();
        addLog("Response code: " + responseCode);

        BufferedReader br;
        if (responseCode >= 200 && responseCode < 300) {
            br = new BufferedReader(new InputStreamReader(conn.getInputStream(), "UTF-8"));
        } else {
            br = new BufferedReader(new InputStreamReader(conn.getErrorStream(), "UTF-8"));
        }

        String responseLine;
        StringBuilder response = new StringBuilder();
        while ((responseLine = br.readLine()) != null) {
            response.append(responseLine);
        }
        br.close();

        String responseStr = response.toString();
        addLog("Response: " + responseStr.substring(0, Math.min(200, responseStr.length())));

        return responseStr;
    } catch (Exception e) {
        addLog("HTTP Error: " + e.toString());
        addLog("Message: " + e.getMessage());
        return null;
    }
}

String sendMultipartFile(String endpoint, String deviceId, String phone, String caption, String filePath, String fieldName, boolean isForwarded) {
    try {
        String fullUrl = apiBaseUrl + endpoint;
        String boundary = "*****" + System.currentTimeMillis() + "*****";
        String lineEnd = "\r\n";
        String twoHyphens = "--";

        File file = new File(filePath);
        if (!file.exists()) {
            addLog("File not found: " + filePath);
            return null;
        }

        String contentType = getFileContentType(filePath);
        addLog("Sending multipart to: " + fullUrl);
        addLog("File: " + filePath + " (" + file.length() + " bytes)");
        addLog("Content-Type: " + contentType);
        addLog("Field name: " + fieldName);
        addLog("Is forwarded: " + isForwarded);

        String originalFileName = file.getName();
        String encodedFileName = encodeRFC5987(originalFileName);

        addLog("Original filename: " + originalFileName);
        addLog("RFC5987 encoded filename: " + encodedFileName);

        URL url = new URL(fullUrl);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        conn.setRequestMethod("POST");
        conn.setRequestProperty("Authorization", authBasic);
        conn.setRequestProperty("X-Device-Id", deviceId);
        conn.setRequestProperty("User-Agent", "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36");
        conn.setRequestProperty("Referer", "http://127.0.0.1:3000/");
        conn.setRequestProperty("Accept", "application/json, text/plain, */*");
        conn.setRequestProperty("Content-Type", "multipart/form-data; boundary=" + boundary);
        conn.setDoOutput(true);
        conn.setDoInput(true);
        conn.setConnectTimeout(30000);
        conn.setReadTimeout(60000);

        DataOutputStream outputStream = new DataOutputStream(conn.getOutputStream());

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"phone\"" + lineEnd);
        outputStream.writeBytes(lineEnd);
        outputStream.writeBytes(phone + lineEnd);

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"is_forwarded\"" + lineEnd);
        outputStream.writeBytes(lineEnd);
        outputStream.writeBytes(String.valueOf(isForwarded) + lineEnd);

        if (caption != null && caption.length() > 0) {
            outputStream.writeBytes(twoHyphens + boundary + lineEnd);
            outputStream.writeBytes("Content-Disposition: form-data; name=\"caption\"" + lineEnd);
            outputStream.writeBytes(lineEnd);
            outputStream.writeBytes(caption + lineEnd);
        }

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"" + fieldName + "\"; filename*=\"utf-8''" + encodedFileName + "\"" + lineEnd);
        outputStream.writeBytes("Content-Type: " + contentType + lineEnd);
        outputStream.writeBytes("Content-Transfer-Encoding: binary" + lineEnd);
        outputStream.writeBytes(lineEnd);

        FileInputStream fileInputStream = new FileInputStream(file);
        byte[] buffer = new byte[4096];
        int bytesRead;
        while ((bytesRead = fileInputStream.read(buffer)) != -1) {
            outputStream.write(buffer, 0, bytesRead);
        }
        fileInputStream.close();
        outputStream.writeBytes(lineEnd);

        outputStream.writeBytes(twoHyphens + boundary + twoHyphens + lineEnd);
        outputStream.flush();
        outputStream.close();

        int responseCode = conn.getResponseCode();
        addLog("Response code: " + responseCode);

        BufferedReader br;
        if (responseCode >= 200 && responseCode < 300) {
            br = new BufferedReader(new InputStreamReader(conn.getInputStream(), "UTF-8"));
        } else {
            br = new BufferedReader(new InputStreamReader(conn.getErrorStream(), "UTF-8"));
        }

        String responseLine;
        StringBuilder response = new StringBuilder();
        while ((responseLine = br.readLine()) != null) {
            response.append(responseLine);
        }
        br.close();

        String responseStr = response.toString();
        addLog("Response: " + responseStr.substring(0, Math.min(200, responseStr.length())));

        return responseStr;
    } catch (Exception e) {
        addLog("Multipart Error: " + e.toString());
        addLog("Message: " + e.getMessage());
        return null;
    }
}

