String readJsonFile(String filePath) {
    try {
        File file = new File(filePath);
        if (file.exists()) {
            return new String(Files.readAllBytes(Paths.get(filePath)), "UTF-8");
        }
    } catch (Exception e) {
        addLog("Error reading: " + e.getMessage());
    }
    return null;
}

void writeJsonFile(String filePath, String content) {
    try {
        Files.write(Paths.get(filePath), content.getBytes("UTF-8"));
    } catch (Exception e) {
        addLog("Error writing: " + e.getMessage());
    }
}

void saveToHistory(Map historyEntry) {
    try {
        JSONArray historyArray = new JSONArray();
        File historyFile = new File(historyPath);
        if (historyFile.exists()) {
            String existingContent = readJsonFile(historyPath);
            if (existingContent != null && existingContent.length() > 0) {
                historyArray = new JSONArray(existingContent);
            }
        }

        JSONObject entry = new JSONObject();
        for (java.util.Iterator it = historyEntry.keySet().iterator(); it.hasNext();) {
            String key = (String) it.next();
            entry.put(key, historyEntry.get(key));
        }

        historyArray.put(entry);
        writeJsonFile(historyPath, historyArray.toString(2));
        addLog("History saved: " + entry.getString("id"));
    } catch (Exception e) {
        addLog("Error saving to history: " + e.getMessage());
    }
}

String generateHistoryId() {
