        conn.setRequestProperty("User-Agent", "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36");
        conn.setRequestProperty("Referer", "http://127.0.0.1:3000/");
        conn.setRequestProperty("Accept", "application/json, text/plain, */*");
        conn.setRequestProperty("Content-Type", "multipart/form-data; boundary=" + boundary);
        conn.setDoOutput(true);
        conn.setDoInput(true);
        conn.setConnectTimeout(30000);
        conn.setReadTimeout(60000);

        DataOutputStream outputStream = new DataOutputStream(conn.getOutputStream());

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"phone\"" + lineEnd);
        outputStream.writeBytes(lineEnd);
        outputStream.writeBytes(phone + lineEnd);

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"is_forwarded\"" + lineEnd);
        outputStream.writeBytes(lineEnd);
        outputStream.writeBytes(String.valueOf(isForwarded) + lineEnd);

        if (caption != null && caption.length() > 0) {
            outputStream.writeBytes(twoHyphens + boundary + lineEnd);
            outputStream.writeBytes("Content-Disposition: form-data; name=\"caption\"" + lineEnd);
            outputStream.writeBytes(lineEnd);
            outputStream.writeBytes(caption + lineEnd);
        }

        outputStream.writeBytes(twoHyphens + boundary + lineEnd);
        outputStream.writeBytes("Content-Disposition: form-data; name=\"" + fieldName + "\"; filename*=\"utf-8''" + encodedFileName + "\"" + lineEnd);
        outputStream.writeBytes("Content-Type: " + contentType + lineEnd);
        outputStream.writeBytes("Content-Transfer-Encoding: binary" + lineEnd);
        outputStream.writeBytes(lineEnd);

        FileInputStream fileInputStream = new FileInputStream(file);
        byte[] buffer = new byte[4096];
        int bytesRead;
        while ((bytesRead = fileInputStream.read(buffer)) != -1) {
            outputStream.write(buffer, 0, bytesRead);
        }
        fileInputStream.close();
        outputStream.writeBytes(lineEnd);

        outputStream.writeBytes(twoHyphens + boundary + twoHyphens + lineEnd);
        outputStream.flush();
        outputStream.close();

        int responseCode = conn.getResponseCode();
        addLog("Response code: " + responseCode);

        BufferedReader br;
        if (responseCode >= 200 && responseCode < 300) {
            br = new BufferedReader(new InputStreamReader(conn.getInputStream(), "UTF-8"));
        } else {
            br = new BufferedReader(new InputStreamReader(conn.getErrorStream(), "UTF-8"));
        }

        String responseLine;
        StringBuilder response = new StringBuilder();
        while ((responseLine = br.readLine()) != null) {
            response.append(responseLine);
        }
        br.close();

        String responseStr = response.toString();
        addLog("Response: " + responseStr.substring(0, Math.min(200, responseStr.length())));

        return responseStr;
    } catch (Exception e) {
        addLog("Multipart Error: " + e.toString());
        addLog("Message: " + e.getMessage());
        return null;
    }
}

String sendImage(String deviceId, String phone, String caption, String imagePath, boolean isStatus, boolean isForwarded) {
    String endpoint = "/send/image";
    String fieldName = "image";
    if (isStatus) {
        phone = "status@broadcast";
    }
    return sendMultipartFile(endpoint, deviceId, phone, caption, imagePath, fieldName, isForwarded);
}

String sendVideo(String deviceId, String phone, String caption, String videoPath, boolean isStatus, boolean isForwarded) {
    String endpoint = "/send/video";
    String fieldName = "video";
    if (isStatus) {
        phone = "status@broadcast";
    }
    return sendMultipartFile(endpoint, deviceId, phone, caption, videoPath, fieldName, isForwarded);
}

String sendFile(String deviceId, String phone, String caption, String filePath, boolean isForwarded) {
    String endpoint = "/send/file";
    String fieldName = "file";
    return sendMultipartFile(endpoint, deviceId, phone, caption, filePath, fieldName, isForwarded);
}

String sendMessage(String deviceId, String phone, String message, boolean isForwarded, int duration) {
    try {
        JSONObject body = new JSONObject();
        body.put("phone", phone);
        body.put("message", message);
        body.put("is_forwarded", isForwarded);
        body.put("duration", duration);

        String response = makeHttpRequest("/send/message", "POST", body.toString(), deviceId);
        return response;
    } catch (Exception e) {
        addLog("Error sending message: " + e.getMessage());
        return null;
    }
}

String sendPoll(String deviceId, String phone, String question, JSONArray options, int maxAnswer) {
    try {
        JSONObject body = new JSONObject();
        body.put("phone", phone);
        body.put("question", question);
        body.put("options", options);
        body.put("max_answer", maxAnswer);

        String response = makeHttpRequest("/send/poll", "POST", body.toString(), deviceId);
        return response;
    } catch (Exception e) {
        addLog("Error sending poll: " + e.getMessage());
        return null;
    }
}

String sendTextStatus(String deviceId, String message, boolean isForwarded) {
    try {
        JSONObject body = new JSONObject();
        body.put("phone", "status@broadcast");
        body.put("message", message);
        body.put("is_forwarded", isForwarded);

        String response = makeHttpRequest("/send/message", "POST", body.toString(), deviceId);
        return response;
    } catch (Exception e) {
        addLog("Error sending text status: " + e.getMessage());
        return null;
    }
}

boolean isResponseSuccess(String response) {
    if (response == null) return false;
    try {
        JSONObject jsonResponse = new JSONObject(response);
        String code = jsonResponse.optString("code", "");
        return code.equals("SUCCESS");
    } catch (Exception e) {
        return response.contains("SUCCESS");
    }
}

Map getDevicesFromLocalApi() {
    Map deviceMap = new HashMap();

    addLog("=== Getting devices from local API ===");
    try {
        String response = makeHttpRequest("/devices", "GET", null, null);
        if (response != null) {
            JSONObject jsonResponse = new JSONObject(response);
            if (jsonResponse.has("results")) {
                JSONArray results = jsonResponse.getJSONArray("results");
                addLog("Found " + results.length() + " devices from API");

                for (int i = 0; i < results.length(); i++) {
                    JSONObject device = results.getJSONObject(i);
                    String state = device.optString("state", "");

                    if (state.equals("logged_in")) {
                        String id = device.getString("id");
                        String jid = device.getString("jid");
                        String phone = jid.replace("@s.whatsapp.net", "");
                        deviceMap.put(id, phone);
                        addLog("✓ Logged device: " + id + " -> " + phone);
                    } else {
                        addLog("✗ Device ignored (state=" + state + ")");
                    }
                }
            }
        } else {
            addLog("No response from API - is the API running?");
        }
    } catch (Exception e) {
        addLog("Error getting devices from API: " + e.getMessage());
    }

    addLog("Total available devices: " + deviceMap.size());
    return deviceMap;
}

String getSectionFromFileName(String fileName) {
    if (fileName.equals("json-status.json")) return "status";
    if (fileName.equals("json-polls.json")) return "polls";
    if (fileName.equals("json-messages.json")) return "messages";
    if (fileName.equals("json-images.json")) return "images";
    if (fileName.equals("json-files.json")) return "files";
    return "unknown";
}

String getCurrentDateTimeISO() {
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
    sdf.setTimeZone(Calendar.getInstance().getTimeZone());
    return sdf.format(Calendar.getInstance().getTime());
}

String getCurrentDate() {
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
    return sdf.format(Calendar.getInstance().getTime());
}

String getCurrentDay() {
    SimpleDateFormat sdf = new SimpleDateFormat("EEEE");
    String day = sdf.format(Calendar.getInstance().getTime());

    if (day.equalsIgnoreCase("Monday") || day.equalsIgnoreCase("segunda-feira")) return "Mon";
    if (day.equalsIgnoreCase("Tuesday") || day.equalsIgnoreCase("terça-feira")) return "Tue";
    if (day.equalsIgnoreCase("Wednesday") || day.equalsIgnoreCase("quarta-feira")) return "Wed";
    if (day.equalsIgnoreCase("Thursday") || day.equalsIgnoreCase("quinta-feira")) return "Thu";
    if (day.equalsIgnoreCase("Friday") || day.equalsIgnoreCase("sexta-feira")) return "Fri";
    if (day.equalsIgnoreCase("Saturday") || day.equalsIgnoreCase("sábado")) return "Sat";
    if (day.equalsIgnoreCase("Sunday") || day.equalsIgnoreCase("domingo")) return "Sun";

    return day;
}

String getCurrentTime() {
    SimpleDateFormat sdf = new SimpleDateFormat("HH:mm");
    return sdf.format(Calendar.getInstance().getTime());
}

/* ============ MAIN ============ */
debugLog = "";
logErrors = "";

addLog("========================================");
addLog("Starting Broadcast Sender");
addLog("========================================");

addLog("API URL: " + apiBaseUrl);

Map deviceMap = getDevicesFromLocalApi();

if (deviceMap.isEmpty()) {
    addLog("WARNING: No devices available! Check if API is running.");
    addError("No devices found to send messages");
} else {
    addLog("Devices loaded successfully: " + deviceMap.size());
}

String currentDate = getCurrentDate();
String currentDay = getCurrentDay();
String currentTime = getCurrentTime();
addLog("Current Date: " + currentDate);
addLog("Current Day: " + currentDay);
addLog("Current Time: " + currentTime);

Map cache = new HashMap();
File cacheFile = new File(cachePath);
if (cacheFile.exists()) {
    String cacheContent = readJsonFile(cachePath);
    if (cacheContent != null) {
        try {
            JSONObject cacheJson = new JSONObject(cacheContent);
            JSONArray sentItems = cacheJson.getJSONArray("sent_items");
            for (int i = 0; i < sentItems.length(); i++) {
                JSONObject sentItem = sentItems.getJSONObject(i);
                cache.put(sentItem.getString("key"), sentItem);
            }
            addLog("Cache loaded: " + cache.size() + " items");
        } catch (Exception e) {
            addLog("Error loading cache: " + e.getMessage());
        }
    }
}

addLog("========================================");

List sentKeys = new ArrayList();
int totalSent = 0;
int totalErrors = 0;

for (int f = 0; f < jsonFiles.length; f++) {
    String jsonFilePath = jsonFiles[f];
    String fileName = fileNames[f];
    String section = getSectionFromFileName(fileName);
    String jsonContent = readJsonFile(jsonFilePath);
    if (jsonContent == null) {
        addLog("File not found: " + fileName);
        continue;
    }

    try {
        JSONObject root = new JSONObject(jsonContent);
        if (!root.has("items")) {
            addLog("No items array in: " + fileName);
            continue;
        }

        JSONArray items = root.getJSONArray("items");
        addLog("Checking file: " + fileName + " (" + items.length() + " items)");

        for (int i = 0; i < items.length(); i++) {
            JSONObject item = items.getJSONObject(i);
            String itemType = item.optString("type", "unknown");

            if (!item.has("schedule")) {
                addLog("  Item " + (i+1) + ": NO schedule object - skipping");
                continue;
            }

            JSONObject schedule = item.getJSONObject("schedule");

            if (!hasValidSchedule(schedule)) {
                addLog("  Item " + (i+1) + ": Empty schedule (no days AND no times configured) - skipping");
                continue;
            }

            JSONArray days = schedule.optJSONArray("days");
            JSONArray times = schedule.optJSONArray("times");

            if (!isDayMatch(days, currentDay)) {
                addLog("  Item " + (i+1) + ": Day mismatch (current day: " + currentDay + ") - skipping");
                continue;
            }

            if (!isTimeMatch(times, currentTime)) {
                addLog("  Item " + (i+1) + ": Time mismatch (current time: " + currentTime + ") - skipping");
                continue;
            }

            boolean hasRequiredFields = true;
            String missingFields = "";

            if (itemType.equals("message") || itemType.equals("text")) {
                if (!item.has("message") || item.getString("message").length() == 0) {
                    hasRequiredFields = false;
                    missingFields = "message";
                }
            } else if (itemType.equals("image") || itemType.equals("image_message")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("video") || itemType.equals("video_message")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("file")) {
                if (!item.has("path")) {
                    hasRequiredFields = false;
                    missingFields = "path";
                } else if (!isValidFilePath(item.getString("path"))) {
                    hasRequiredFields = false;
                    missingFields = "invalid file path: " + item.getString("path");
                }
            } else if (itemType.equals("poll")) {
                if (!item.has("question")) {
                    hasRequiredFields = false;
                    missingFields = "question";
                }
                if (!item.has("options") || item.getJSONArray("options").length() == 0) {
                    hasRequiredFields = false;
                    missingFields = missingFields + (missingFields.length() > 0 ? ", options" : "options");
                }
            }

            if (!hasRequiredFields) {
                addError("Item " + (i+1) + " missing " + missingFields);
                totalErrors++;
                continue;
            }

            String uniqueItemId = "";
            if (item.has("path")) {
                uniqueItemId = item.getString("path");
            } else if (item.has("message")) {
                uniqueItemId = item.getString("message");
            } else if (item.has("question")) {
                uniqueItemId = item.getString("question");
            } else {
                uniqueItemId = String.valueOf(i);
            }

            String itemKey = fileName + "_" + itemType + "_" + String.valueOf(uniqueItemId.hashCode()) + "_" + currentDate;

            if (cache.containsKey(itemKey)) {
                addLog("  Item " + (i+1) + ": Already sent today - skipping");
                continue;
            }

            addLog(">>> SENDING: " + fileName + " - " + itemType);

            JSONArray recipients = item.optJSONArray("recipients");
            JSONArray deviceIds = item.optJSONArray("device_ids");
            boolean isStatus = (fileName.equals("json-status.json"));
            boolean isForwarded = item.optBoolean("is_forwarded", false);
            List allTargets = new ArrayList();
            boolean allSuccess = true;

            if (isStatus) {
                String target = "status@broadcast";
                allTargets.add(target);

                if (itemType.equals("text") || itemType.equals("message")) {
                    String message = item.getString("message");

                    if (deviceIds != null && deviceIds.length() > 0) {
                        for (int d = 0; d < deviceIds.length(); d++) {
                            JSONObject deviceObj = deviceIds.getJSONObject(d);
                            String deviceId = deviceObj.getString("device_id");
                            if (!deviceMap.containsKey(deviceId)) {
                                addError("Device " + deviceId + " not available");
                                allSuccess = false;
                                continue;
                            }
                            String response = sendTextStatus(deviceId, message, isForwarded);
                            if (!isResponseSuccess(response)) {
                                allSuccess = false;
                            }
                        }
                    } else {
                        java.util.Iterator it = deviceMap.keySet().iterator();
                        while (it.hasNext()) {
                            String deviceId = it.next().toString();
                            String response = sendTextStatus(deviceId, message, isForwarded);
                            if (!isResponseSuccess(response)) {
                                allSuccess = false;
                            }
                        }
                    }

                    if (allSuccess) {
                        Map historyEntry = new HashMap();
                        historyEntry.put("section", section);
                        historyEntry.put("type", itemType);
                        historyEntry.put("action", "send");
                        historyEntry.put("status", "success");
                        historyEntry.put("target", target);
                        historyEntry.put("detail", message);
                        historyEntry.put("broadcastId", "st-" + i);
                        historyEntry.put("message", message);
                        historyEntry.put("is_forwarded", isForwarded);
                        historyEntry.put("id", generateHistoryId());
                        historyEntry.put("timestamp", getCurrentDateTimeISO());
                        saveToHistory(historyEntry);
                    }
                }
                else if (itemType.equals("image") || itemType.equals("image_message")) {
                    String path = item.optString("path", "");
                    if (path.length() == 0) {
                        addError("Missing path for image status");
                        allSuccess = false;
                    } else if (!isValidFilePath(path)) {
                        addError("File not found: " + path);
                        allSuccess = false;
                    } else {
                        String caption = item.optString("caption", "");
                        if (deviceIds != null && deviceIds.length() > 0) {
                            for (int d = 0; d < deviceIds.length(); d++) {
                                JSONObject deviceObj = deviceIds.getJSONObject(d);
                                String deviceId = deviceObj.getString("device_id");
                                if (!deviceMap.containsKey(deviceId)) {
                                    addError("Device " + deviceId + " not available");
                                    allSuccess = false;
                                    continue;
                                }
                                String response = sendImage(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            }
                        } else {
                            java.util.Iterator it = deviceMap.keySet().iterator();
                            while (it.hasNext()) {
                                String deviceId = it.next().toString();
                                String response = sendImage(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            }
                        }

                        if (allSuccess) {
                            Map historyEntry = new HashMap();
                            historyEntry.put("section", section);
                            historyEntry.put("type", itemType);
                            historyEntry.put("action", "send");
                            historyEntry.put("status", "success");
                            historyEntry.put("target", target);
                            historyEntry.put("detail", caption.length() > 0 ? caption : "Image status");
                            historyEntry.put("broadcastId", "st-" + i);
                            historyEntry.put("is_forwarded", isForwarded);
                            historyEntry.put("caption", caption);
                            historyEntry.put("path", path);
                            historyEntry.put("id", generateHistoryId());
                            historyEntry.put("timestamp", getCurrentDateTimeISO());
                            saveToHistory(historyEntry);
                        }
                    }
                }
                else if (itemType.equals("video") || itemType.equals("video_message")) {
                    String path = item.optString("path", "");
                    if (path.length() == 0) {
                        addError("Missing path for video status");
                        allSuccess = false;
                    } else if (!isValidFilePath(path)) {
                        addError("File not found: " + path);
                        allSuccess = false;
                    } else {
                        String caption = item.optString("caption", "");
                        if (deviceIds != null && deviceIds.length() > 0) {
                            for (int d = 0; d < deviceIds.length(); d++) {
                                JSONObject deviceObj = deviceIds.getJSONObject(d);
                                String deviceId = deviceObj.getString("device_id");
                                if (!deviceMap.containsKey(deviceId)) {
                                    addError("Device " + deviceId + " not available");
                                    allSuccess = false;
                                    continue;
                                }
                                String response = sendVideo(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            }
                        } else {
                            java.util.Iterator it = deviceMap.keySet().iterator();
                            while (it.hasNext()) {
                                String deviceId = it.next().toString();
                                String response = sendVideo(deviceId, "", caption, path, true, isForwarded);
                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            }
                        }

                        if (allSuccess) {
                            Map historyEntry = new HashMap();
                            historyEntry.put("section", section);
                            historyEntry.put("type", itemType);
                            historyEntry.put("action", "send");
                            historyEntry.put("status", "success");
                            historyEntry.put("target", target);
                            historyEntry.put("detail", caption.length() > 0 ? caption : "Video status");
                            historyEntry.put("broadcastId", "st-" + i);
                            historyEntry.put("is_forwarded", isForwarded);
                            historyEntry.put("caption", caption);
                            historyEntry.put("path", path);
                            historyEntry.put("id", generateHistoryId());
                            historyEntry.put("timestamp", getCurrentDateTimeISO());
                            saveToHistory(historyEntry);
                        }
                    }
                } else {
                    addError("Unknown status type: " + itemType);
                    allSuccess = false;
                }
            }
            else if (recipients != null && recipients.length() > 0) {
                for (int r = 0; r < recipients.length(); r++) {
                    JSONObject recipient = recipients.getJSONObject(r);
                    String recipientPhone = recipient.getString("phone");
                    String recipientSuffix = recipient.optString("suffix", "@s.whatsapp.net");
                    String fullPhone = recipientPhone + recipientSuffix;

                    if (!isValidPhone(recipientPhone)) {
                        addError("Invalid phone number: " + recipientPhone);
                        allSuccess = false;
                        continue;
                    }

                    allTargets.add(fullPhone);

                    if (deviceIds != null && deviceIds.length() > 0) {
                        for (int d = 0; d < deviceIds.length(); d++) {
                            JSONObject deviceObj = deviceIds.getJSONObject(d);
                            String deviceId = deviceObj.getString("device_id");
                            if (!deviceMap.containsKey(deviceId)) {
                                addError("Device " + deviceId + " not available for " + fullPhone);
                                allSuccess = false;
                                continue;
                            }

                            String response = null;
                            try {
                                if (itemType.equals("message") || itemType.equals("text")) {
                                    String message = item.getString("message");
                                    int duration = item.optInt("duration", 0);
                                    response = sendMessage(deviceId, fullPhone, message, isForwarded, duration);
                                } else if (itemType.equals("image") || itemType.equals("image_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendImage(deviceId, fullPhone, caption, path, false, isForwarded);
                                } else if (itemType.equals("video") || itemType.equals("video_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendVideo(deviceId, fullPhone, caption, path, false, isForwarded);
                                } else if (itemType.equals("file")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendFile(deviceId, fullPhone, caption, path, isForwarded);
                                } else if (itemType.equals("poll")) {
                                    String question = item.getString("question");
                                    JSONArray options = item.getJSONArray("options");
                                    int maxAnswer = item.optInt("max_answer", 1);
                                    response = sendPoll(deviceId, fullPhone, question, options, maxAnswer);
                                }

                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            } catch (Exception e) {
                                addError("Exception: " + e.getMessage());
                                allSuccess = false;
                            }
                        }
                    } else {
                        java.util.Iterator it = deviceMap.keySet().iterator();
                        while (it.hasNext()) {
                            String deviceId = it.next().toString();
                            String response = null;
                            try {
                                if (itemType.equals("message") || itemType.equals("text")) {
                                    String message = item.getString("message");
                                    int duration = item.optInt("duration", 0);
                                    response = sendMessage(deviceId, fullPhone, message, isForwarded, duration);
                                } else if (itemType.equals("image") || itemType.equals("image_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendImage(deviceId, fullPhone, caption, path, false, isForwarded);
                                } else if (itemType.equals("video") || itemType.equals("video_message")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendVideo(deviceId, fullPhone, caption, path, false, isForwarded);
                                } else if (itemType.equals("file")) {
                                    String path = item.getString("path");
                                    if (!isValidFilePath(path)) {
                                        addError("File not found: " + path);
                                        allSuccess = false;
                                        continue;
                                    }
                                    String caption = item.optString("caption", "");
                                    response = sendFile(deviceId, fullPhone, caption, path, isForwarded);
                                } else if (itemType.equals("poll")) {
                                    String question = item.getString("question");
                                    JSONArray options = item.getJSONArray("options");
                                    int maxAnswer = item.optInt("max_answer", 1);
                                    response = sendPoll(deviceId, fullPhone, question, options, maxAnswer);
                                }

                                if (!isResponseSuccess(response)) {
                                    allSuccess = false;
                                }
                            } catch (Exception e) {
                                addError("Exception: " + e.getMessage());
                                allSuccess = false;
                            }
                        }
                    }
                }
            } else if (!isStatus) {
                addError("No recipients found for item " + (i+1));
                totalErrors++;
                continue;
            }

            if (allSuccess) {
                JSONObject cacheItem = new JSONObject();
                cacheItem.put("key", itemKey);
                cacheItem.put("file", fileName);
                cacheItem.put("type", itemType);
                cacheItem.put("date", getCurrentDateTimeISO());
                sentKeys.add(cacheItem);
                totalSent++;
                addLog("  Item " + (i+1) + ": SEND SUCCESS");

                /* Save to history for non-status items if not already saved */
                if (!isStatus) {
                    Map historyEntry = new HashMap();
                    historyEntry.put("section", section);
                    historyEntry.put("type", itemType);
                    historyEntry.put("action", "send");
                    historyEntry.put("status", "success");
                    historyEntry.put("targets", allTargets);
                    if (allTargets.size() > 0) {
                        historyEntry.put("target", allTargets.get(0));
                    }

                    if (itemType.equals("message") || itemType.equals("text")) {
                        historyEntry.put("detail", item.getString("message"));
                        historyEntry.put("broadcastId", "msg-" + i);
                        historyEntry.put("message", item.getString("message"));
                        historyEntry.put("is_forwarded", isForwarded);
                    } else if (itemType.equals("image") || itemType.equals("image_message")) {
                        String caption = item.optString("caption", "");
                        historyEntry.put("detail", caption.length() > 0 ? caption : "Image");
                        historyEntry.put("broadcastId", "img-" + i);
                        historyEntry.put("is_forwarded", isForwarded);
                        historyEntry.put("duration", item.optInt("duration", 0));
                        historyEntry.put("caption", caption);
                        historyEntry.put("path", item.getString("path"));
                    } else if (itemType.equals("video") || itemType.equals("video_message")) {
                        String caption = item.optString("caption", "");
                        historyEntry.put("detail", caption.length() > 0 ? caption : "Video");
                        historyEntry.put("broadcastId", "vid-" + i);
                        historyEntry.put("is_forwarded", isForwarded);
                        historyEntry.put("duration", item.optInt("duration", 0));
                        historyEntry.put("caption", caption);
                        historyEntry.put("path", item.getString("path"));
                    } else if (itemType.equals("file")) {
                        String caption = item.optString("caption", "");
                        historyEntry.put("detail", caption.length() > 0 ? caption : "File");
                        historyEntry.put("broadcastId", "file-" + i);
                        historyEntry.put("path", item.getString("path"));
                    } else if (itemType.equals("poll")) {
                        historyEntry.put("detail", item.getString("question"));
                        historyEntry.put("broadcastId", "poll-" + i);
                        historyEntry.put("question", item.getString("question"));
                        historyEntry.put("options", item.getJSONArray("options"));
                    }

                    historyEntry.put("id", generateHistoryId());
                    historyEntry.put("timestamp", getCurrentDateTimeISO());
                    saveToHistory(historyEntry);
                }
            } else {
                addError("Item " + (i+1) + " send failed");
                totalErrors++;
            }
        }

    } catch (Exception e) {
        addError("Error processing " + fileName + ": " + e.getMessage());
        totalErrors++;
    }
}

if (sentKeys.size() > 0) {
    JSONArray sentItemsArray = new JSONArray();
    java.util.Iterator it = cache.keySet().iterator();
    while (it.hasNext()) {
        String key = it.next().toString();
        Object value = cache.get(key);
        if (value instanceof JSONObject) {
            sentItemsArray.put((JSONObject) value);
        }
    }
    for (int i = 0; i < sentKeys.size(); i++) {
        sentItemsArray.put((JSONObject) sentKeys.get(i));
    }
    JSONObject cacheJson = new JSONObject();
    cacheJson.put("sent_items", sentItemsArray);
    writeJsonFile(cachePath, cacheJson.toString(2));
    addLog("Cache saved: " + sentItemsArray.length() + " items");
}

tasker.setVariable("send_log", debugLog);
tasker.setVariable("send_errors", logErrors);

addLog("========================================");
addLog("EXECUTION SUMMARY");
addLog("========================================");
addLog("Successfully sent: " + totalSent);
addLog("Errors: " + totalErrors);
addLog("========================================");

return "Successfully sent: " + totalSent + " items (Errors: " + totalErrors + ")";

import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Iterator;
import java.util.ArrayList;
import org.json.JSONException;
import org.json.JSONObject;
import org.json.JSONArray;

/* Helper function to recursively parse JSON objects and arrays into Java Maps and Lists. */
Object parseJsonValue(Object jsonValue) {
    if (jsonValue instanceof JSONObject) {
        Map map = new HashMap();
        JSONObject obj = (JSONObject) jsonValue;
        Iterator keys = obj.keys();
        while (keys.hasNext()) {
            String key = (String) keys.next();
            map.put(key, parseJsonValue(obj.get(key))); /* Recursive call for nested values. */
        }
        return map;
    } else if (jsonValue instanceof JSONArray) {
        List list = new ArrayList();
        JSONArray array = (JSONArray) jsonValue;
        for (int i = 0; i < array.length(); i++) {
            list.add(parseJsonValue(array.get(i))); /* Recursive call for array elements. */
        }
        return list;
    } else {
        return jsonValue; /* Return primitives, strings, etc. as is. */
    }
}

phone = tasker.getVariable("device_id");
if (phone == null) {
    throw new JavaCodeException("Tasker variable 'device_id' is null. Please ensure it is set.");
}
phone = phone.replaceAll("\\D", "");

httpDataString = tasker.getVariable("http_data");
if (httpDataString == null) {
    throw new JavaCodeException("Tasker variable 'http_data' is null. Please ensure it is set.");
}

data = null;
try {
    /* Parse the entire JSON string using the helper function to convert to Map/List. */
    JSONObject jsonObject = new JSONObject(httpDataString);
    data = (Map) parseJsonValue(jsonObject);
} catch (JSONException e) {
    /* Catch JSON parsing errors and report to Tasker. */
    throw new JavaCodeException("Failed to parse HTTP data as JSON: " + e.getMessage());
}

result = "";

/* Proceed only if data was successfully parsed and contains expected keys. */
if (data != null && data.containsKey("code") && "SUCCESS".equals(data.get("code"))) {
    /* 'results' will now be a java.util.List due to the parseJsonValue helper. */
    results = (List) data.get("results");
    if (results != null) {
        for (i = 0; i < results.size(); i++) {
            d = (Map) results.get(i);
            if (d.containsKey("jid")) {
                jid = (String) d.get("jid");
                if (jid != null) {
                    parts = jid.split("@");
                    if (parts.length > 0) {
                        jidPhone = parts[0].replaceAll("\\D", "");
                        if (jidPhone.equals(phone)) {
                            result = (String) d.get("id");
                            break;
                        }
                    }
                }
            }
        }
    }
}

tasker.setVariable("device_id_output", result);

import org.json.JSONObject;
import org.json.JSONArray;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

httpRequestBody = tasker.getVariable("http_request_body");

try {
    data = new JSONObject(httpRequestBody);

    // Campos principais do nível raiz
    if (data.has("recebido_em")) {
        tasker.setVariable("recebido_em", data.optString("recebido_em", ""));
    } else {
        tasker.setVariable("recebido_em", "");
    }

    if (data.has("origem")) {
        tasker.setVariable("origem", data.optString("origem", ""));
    } else {
        tasker.setVariable("origem", "");
    }

    if (data.has("metodo")) {
        tasker.setVariable("metodo", data.optString("metodo", ""));
    } else {
        tasker.setVariable("metodo", "");
    }

    if (data.has("url_original")) {
        tasker.setVariable("url_original", data.optString("url_original", ""));
    } else {
        tasker.setVariable("url_original", "");
    }

    if (data.has("porta_origem")) {
        tasker.setVariable("porta_origem", data.optString("porta_origem", ""));
    } else {
        tasker.setVariable("porta_origem", "");
    }

    if (data.has("porta_destino")) {
        tasker.setVariable("porta_destino", data.optString("porta_destino", ""));
    } else {
        tasker.setVariable("porta_destino", "");
    }

    // Processa o body principal
    if (data.has("body")) {
        body = data.optJSONObject("body");
        if (body != null) {

            // DeviceID
            if (body.has("DeviceID")) {
                String rawDeviceId = body.optString("DeviceID", "");
                String cleanDeviceId = rawDeviceId;
                if (rawDeviceId.contains("@")) {
                    cleanDeviceId = rawDeviceId.substring(0, rawDeviceId.indexOf("@"));
                }
                tasker.setVariable("device_id", cleanDeviceId);
                tasker.setVariable("phone", cleanDeviceId);
            } else {
                tasker.setVariable("device_id", "");
                tasker.setVariable("phone", "");
            }

            // Event
            event = body.optString("Event", "");
            if (body.has("Event")) {
                tasker.setVariable("event", event);
            } else {
                tasker.setVariable("event", "");
            }

            // Timestamp do body
            if (body.has("Timestamp")) {
                tasker.setVariable("timestamp_body", body.optString("Timestamp", ""));
            } else {
                tasker.setVariable("timestamp_body", "");
            }

            // Processa o payload
            if (body.has("Payload")) {
                p = body.optJSONObject("Payload");
                if (p != null) {

                    // ChatID
                    if (p.has("ChatID")) {
                        String chatIdValue = p.optString("ChatID", "");
                        tasker.setVariable("chat_id", chatIdValue);

                        String recipientNumberRaw = chatIdValue;
                        if (recipientNumberRaw.endsWith("@s.whatsapp.net")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (recipientNumberRaw.endsWith("@g.us")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("recipient_number", recipientNumberRaw);
                    } else {
                        tasker.setVariable("chat_id", "");
                        tasker.setVariable("recipient_number", "");
                    }

                    // ChatLid / FromLid
                    if (p.has("ChatLid")) {
                        tasker.setVariable("from_lid", p.optString("ChatLid", ""));
                    } else if (p.has("FromLid")) {
                        tasker.setVariable("from_lid", p.optString("FromLid", ""));
                    } else {
                        tasker.setVariable("from_lid", "");
                    }

                    // From
                    if (p.has("From")) {
                        String fromRaw = p.optString("From", "");
                        String senderNumberRaw = fromRaw;
                        if (senderNumberRaw.endsWith("@s.whatsapp.net")) {
                            senderNumberRaw = senderNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (senderNumberRaw.endsWith("@g.us")) {
                            senderNumberRaw = senderNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("sender_number", senderNumberRaw);
                    } else {
                        tasker.setVariable("sender_number", "");
                    }

                    // FromName
                    if (p.has("FromName")) {
                        tasker.setVariable("sender_name", p.optString("FromName", ""));
                    } else {
                        tasker.setVariable("sender_name", "");
                    }

                    // IsFromMe
                    if (p.has("IsFromMe")) {
                        tasker.setVariable("is_from_me", String.valueOf(p.optBoolean("IsFromMe")));
                    } else {
                        tasker.setVariable("is_from_me", "false");
                    }

                    // IsGroup
                    if (p.has("IsGroup")) {
                        boolean isGroupBoolean = p.optBoolean("IsGroup");
                        tasker.setVariable("is_group", String.valueOf(isGroupBoolean));

                        if (isGroupBoolean) {
                            String groupJidValue = p.optString("ChatID", "");
                            if (groupJidValue.endsWith("@g.us")) {
                                groupJidValue = groupJidValue.replace("@g.us", "");
