                    } else {
                        tasker.setVariable("document_path", "");
                        tasker.setVariable("caption_document", "");
                    }

                    // Audio
                    if (p.has("Audio")) {
                        tasker.setVariable("audio_path", p.optString("Audio", ""));
                        tasker.setVariable("caption_audio", "");
                    } else {
                        tasker.setVariable("audio_path", "");
                        tasker.setVariable("caption_audio", "");
                    }

                    // ========================================
                    // LOCATION
                    // ========================================
                    tasker.setVariable("location_latitude", "");
                    tasker.setVariable("location_longitude", "");

                    if (p.has("Latitude") && p.has("Longitude")) {
                        tasker.setVariable("location_latitude", String.valueOf(p.optDouble("Latitude")));
                        tasker.setVariable("location_longitude", String.valueOf(p.optDouble("Longitude")));
                    } else if (p.has("Location")) {
                        JSONObject locationObj = p.optJSONObject("Location");
                        if (locationObj != null) {
                            if (locationObj.has("degreesLatitude") && locationObj.has("degreesLongitude")) {
                                tasker.setVariable("location_latitude", String.valueOf(locationObj.optDouble("degreesLatitude", 0.0)));
                                tasker.setVariable("location_longitude", String.valueOf(locationObj.optDouble("degreesLongitude", 0.0)));
                            }
                            if (locationObj.has("JPEGThumbnail")) {
                                tasker.setVariable("thumbnail_base64", locationObj.optString("JPEGThumbnail", ""));
                            }
                        }
                    } else if (p.has("LiveLocation")) {
                        JSONObject liveLocationObj = p.optJSONObject("LiveLocation");
                        if (liveLocationObj != null) {
                            if (liveLocationObj.has("degreesLatitude") && liveLocationObj.has("degreesLongitude")) {
                                tasker.setVariable("location_latitude", String.valueOf(liveLocationObj.optDouble("degreesLatitude", 0.0)));
                                tasker.setVariable("location_longitude", String.valueOf(liveLocationObj.optDouble("degreesLongitude", 0.0)));
                            }
                            if (liveLocationObj.has("sequenceNumber")) {
                                tasker.setVariable("live_location_sequence_number", String.valueOf(liveLocationObj.optLong("sequenceNumber", 0)));
                            } else {
                                tasker.setVariable("live_location_sequence_number", "");
                            }
                            if (liveLocationObj.has("JPEGThumbnail")) {
                                tasker.setVariable("thumbnail_base64", liveLocationObj.optString("JPEGThumbnail", ""));
                            }
                        }
                    }

                    // Contact
                    if (p.has("ContactsArray")) {
                        JSONArray contactsArray = p.optJSONArray("ContactsArray");
                        if (contactsArray != null && contactsArray.length() > 0) {
                            tasker.setVariable("contacts_json", contactsArray.toString());
                            tasker.setVariable("contacts_count", String.valueOf(contactsArray.length()));
                        } else {
                            tasker.setVariable("contacts_json", "");
                            tasker.setVariable("contacts_count", "0");
                        }
                    } else {
                        tasker.setVariable("contacts_json", "");
                        tasker.setVariable("contacts_count", "0");
                    }

                    if (p.has("Contact")) {
                        JSONObject contactObj = p.optJSONObject("Contact");
                        if (contactObj != null) {
                            tasker.setVariable("contact_display_name", contactObj.optString("DisplayName", ""));
                            tasker.setVariable("contact_vcard", contactObj.optString("VCard", ""));
                        } else {
                            tasker.setVariable("contact_display_name", "");
                            tasker.setVariable("contact_vcard", "");
                        }
                    } else {
                        tasker.setVariable("contact_display_name", "");
                        tasker.setVariable("contact_vcard", "");
                    }

                    // Receipt
                    if (p.has("ReceiptType")) {
                        String receiptType = p.optString("ReceiptType", "");
                        tasker.setVariable("receipt_type", receiptType);
                        tasker.setVariable("is_receipt", "true");

                        if (receiptType.equals("delivered")) {
                            tasker.setVariable("is_delivered", "true");
                            tasker.setVariable("is_read", "false");
                        } else if (receiptType.equals("read")) {
                            tasker.setVariable("is_delivered", "false");
                            tasker.setVariable("is_read", "true");
                        } else {
                            tasker.setVariable("is_delivered", "false");
                            tasker.setVariable("is_read", "false");
                        }
                    } else {
                        tasker.setVariable("receipt_type", "");
                        tasker.setVariable("is_receipt", "false");
                        tasker.setVariable("is_delivered", "false");
                        tasker.setVariable("is_read", "false");
                    }

                    if (p.has("ReceiptTypeDescription")) {
                        tasker.setVariable("receipt_type_description", p.optString("ReceiptTypeDescription", ""));
                    } else {
                        tasker.setVariable("receipt_type_description", "");
                    }

                    // Presence
                    if (p.has("State")) {
                        tasker.setVariable("state", p.optString("State", ""));
                    } else {
                        tasker.setVariable("state", "");
                    }

                    if (p.has("Media")) {
                        tasker.setVariable("media_type", p.optString("Media", ""));
                    } else {
                        tasker.setVariable("media_type", "");
                    }

                    // Context Info
                    if (p.has("contextInfo")) {
                        JSONObject contextInfo = p.optJSONObject("contextInfo");
                        if (contextInfo != null) {
                            tasker.setVariable("context_info", contextInfo.toString());
                            if (contextInfo.has("expiration")) {
                                tasker.setVariable("expiration", String.valueOf(contextInfo.optLong("expiration")));
                            }
                            if (contextInfo.has("ephemeralSettingTimestamp")) {
                                tasker.setVariable("ephemeral_timestamp", String.valueOf(contextInfo.optLong("ephemeralSettingTimestamp")));
                            }
                        } else {
                            tasker.setVariable("context_info", "");
                            tasker.setVariable("expiration", "");
                            tasker.setVariable("ephemeral_timestamp", "");
                        }
                    } else {
                        tasker.setVariable("context_info", "");
                        tasker.setVariable("expiration", "");
                        tasker.setVariable("ephemeral_timestamp", "");
                    }
                }
            }

            // ========================================
            // CALL EVENTS
            // ========================================
            if (event.equals("call.offer") || event.equals("call.terminate")) {
                if (body.has("Payload")) {
                    callPayload = body.optJSONObject("Payload");
                    if (callPayload != null) {
                        if (callPayload.has("CallID")) tasker.setVariable("call_id", callPayload.optString("CallID", ""));
                        else tasker.setVariable("call_id", "");

                        if (callPayload.has("CallStatus")) tasker.setVariable("call_status", callPayload.optString("CallStatus", ""));
                        else tasker.setVariable("call_status", "");

                        if (callPayload.has("CallType")) tasker.setVariable("call_type", callPayload.optString("CallType", ""));
                        else tasker.setVariable("call_type", "");

                        if (callPayload.has("From")) {
                            String callFrom = callPayload.optString("From", "");
                            if (callFrom.contains("@")) {
                                callFrom = callFrom.substring(0, callFrom.indexOf("@"));
                            }
                            tasker.setVariable("call_sender_number", callFrom);
                        } else {
                            tasker.setVariable("call_sender_number", "");
                        }

                        if (callPayload.has("IsGroup")) tasker.setVariable("call_is_group", String.valueOf(callPayload.optBoolean("IsGroup")));
                        else tasker.setVariable("call_is_group", "false");

                        if (callPayload.has("ShutdownCauser")) tasker.setVariable("call_shutdown_causer", callPayload.optString("ShutdownCauser", ""));
                        else tasker.setVariable("call_shutdown_causer", "");

                        if (callPayload.has("TerminatedBy")) {
                            String terminatedBy = callPayload.optString("TerminatedBy", "");
                            if (terminatedBy.contains("@")) {
                                terminatedBy = terminatedBy.substring(0, terminatedBy.indexOf("@"));
                            }
                            tasker.setVariable("call_terminated_by", terminatedBy);
                        } else {
                            tasker.setVariable("call_terminated_by", "");
                        }

                        if (callPayload.has("AutoRejected")) tasker.setVariable("call_auto_rejected", String.valueOf(callPayload.optBoolean("AutoRejected")));
                        else tasker.setVariable("call_auto_rejected", "false");

                        if (callPayload.has("Type")) tasker.setVariable("call_type_message", callPayload.optString("Type", ""));
                        else tasker.setVariable("call_type_message", "");
                    }
                }
            }
        }
    }

    tasker.setVariable("parse_success", "true");
    tasker.setVariable("parse_error", "");

} catch (Exception e) {
    tasker.setVariable("parse_success", "false");
    tasker.setVariable("parse_error", e.getMessage());
    throw new JavaCodeException("Erro ao analisar JSON: " + e.getMessage());
}

import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.ResponseBody;
import java.io.File;
import java.io.FileOutputStream;
import java.io.InputStream;
import java.io.IOException;
import java.util.HashMap;
import org.json.JSONObject;
import org.json.JSONArray;

String urlApi = tasker.getVariable("url_project_wca");
if (urlApi == null || urlApi.equals("")) {
    tasker.showToast("URL do projeto não definida");
    return "Error: URL_PROJECT_WCA não definida";
}

String filePath1 = "/data/data/net.dinglisch.android.taskerm/files/WCA/go_port_wca-aarch64.bin";
String filePath2 = "/data/data/net.dinglisch.android.taskerm/files/WCA/whatsapp-wca-aarch64.bin";
String filePath3 = "/data/data/net.dinglisch.android.taskerm/files/WCA/ffmpeg-wca-aarch64.bin";

String jsonValue = tasker.getVariable("json");
if (jsonValue == null || jsonValue.equals("")) {
    jsonValue = "";
}
tasker.setVariable("temp_json", jsonValue);

OkHttpClient client = new OkHttpClient();

String releaseJson = null;
try {
    Request request = new Request.Builder().url(urlApi).build();
    Response response = client.newCall(request).execute();
    if (response.isSuccessful()) {
        releaseJson = response.body().string();
    } else {
        tasker.showToast("Erro ao buscar release: " + response.code());
        return "Error: Falha ao buscar release";
    }
    response.close();
} catch (Exception e) {
    tasker.showToast("Erro na requisição: " + e.getMessage());
    return "Error: " + e.getMessage();
}

JSONObject release = new JSONObject(releaseJson);
JSONArray assets = release.getJSONArray("assets");

String url1 = null;
String url2 = null;
String url3 = null;
long size1 = 0;
long size2 = 0;
long size3 = 0;

for (int i = 0; i < assets.length(); i++) {
    JSONObject asset = assets.getJSONObject(i);
    String name = asset.getString("name");
    String downloadUrl = asset.getString("browser_download_url");
    long size = asset.getLong("size");

    if (name.equals("go_port_wca-aarch64.bin")) {
        url1 = downloadUrl;
        size1 = size;
    } else if (name.equals("whatsapp-wca-aarch64.bin")) {
        url2 = downloadUrl;
        size2 = size;
    } else if (name.equals("ffmpeg-wca-aarch64.bin")) {
        url3 = downloadUrl;
        size3 = size;
    }
}

if (url1 == null || url2 == null || url3 == null) {
    tasker.showToast("Um ou mais arquivos não encontrados no release");
    return "Error: Arquivos não encontrados";
}

long totalBytes = size1 + size2 + size3;

if (totalBytes <= 0) {
    try {
        Request headReq1 = new Request.Builder().url(url1).head().build();
        Response headRes1 = client.newCall(headReq1).execute();
        if (headRes1.isSuccessful()) totalBytes += headRes1.body().contentLength();
        headRes1.close();
    } catch (Exception e) {}

    try {
        Request headReq2 = new Request.Builder().url(url2).head().build();
        Response headRes2 = client.newCall(headReq2).execute();
        if (headRes2.isSuccessful()) totalBytes += headRes2.body().contentLength();
        headRes2.close();
    } catch (Exception e) {}

    try {
        Request headReq3 = new Request.Builder().url(url3).head().build();
        Response headRes3 = client.newCall(headReq3).execute();
        if (headRes3.isSuccessful()) totalBytes += headRes3.body().contentLength();
        headRes3.close();
    } catch (Exception e) {}
}

if (totalBytes <= 0) {
    totalBytes = 100 * 1024 * 1024;
}

boolean downloadFile(String urlStr, String filePathStr, String displayName, long[] downloaded, int[] lastPct, long[] lastTime, long totalBytes, long fileSize) {
    File destFile = new File(filePathStr);
    File parentDir = destFile.getParentFile();
    if (parentDir != null && !parentDir.exists()) parentDir.mkdirs();
    if (destFile.exists()) destFile.delete();

    Request request = new Request.Builder().url(urlStr).build();
    Response response = null;
    InputStream inputStream = null;
    FileOutputStream outputStream = null;

    try {
        response = client.newCall(request).execute();
        if (!response.isSuccessful()) {
            tasker.showToast("HTTP Error " + response.code() + ": " + displayName);
            return false;
        }
        ResponseBody body = response.body();
        if (body == null) {
            tasker.showToast("Response body null: " + displayName);
            return false;
        }
        inputStream = body.byteStream();
        outputStream = new FileOutputStream(destFile);
        byte[] buffer = new byte[65536];
        int bytesRead;
        long fileDownloaded = 0;
        while ((bytesRead = inputStream.read(buffer)) != -1) {
            if (bytesRead == 0) continue;
            outputStream.write(buffer, 0, bytesRead);
            fileDownloaded += bytesRead;
            downloaded[0] += bytesRead;
            long currentTime = System.currentTimeMillis();
            int currentPercent = (int) ((downloaded[0] * 100L) / totalBytes);
            if (currentPercent > 100) currentPercent = 100;
            if (currentPercent < 0) currentPercent = 0;

            boolean percentChanged = currentPercent >= lastPct[0] + 1;
            boolean timeElapsed = (currentTime - lastTime[0] > 1000L) && (currentPercent != lastPct[0]);

            if ((percentChanged || timeElapsed) && currentPercent != lastPct[0] && currentPercent < 100) {
                String percentStr = String.valueOf(currentPercent);
                tasker.setVariable("progress_install", percentStr);
                tasker.setVariable("par1", "installation_upgrade");

                HashMap taskArgs = new HashMap();
                taskArgs.put("progress_install", percentStr);
                taskArgs.put("par1", "installation_upgrade");
                tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgs);

                lastPct[0] = currentPercent;
                lastTime[0] = currentTime;
            }
        }
        outputStream.flush();

        if (fileSize > 0 && fileDownloaded < fileSize) {
            tasker.showToast("Tamanho incorreto: " + displayName);
            return false;
        }

        return true;
    } catch (IOException e) {
        tasker.showToast("Download error: " + e.getMessage() + " - " + displayName);
        if (destFile.exists()) destFile.delete();
        return false;
    } finally {
        try { if (inputStream != null) inputStream.close(); } catch (IOException e) {}
        try { if (outputStream != null) outputStream.close(); } catch (IOException e) {}
        try { if (response != null) response.close(); } catch (IOException e) {}
    }
}

long[] downloadedBytes = new long[]{0};
int[] lastPercent = new int[]{-1};
long[] lastTime = new long[]{System.currentTimeMillis()};

HashMap taskArgsStart = new HashMap();
taskArgsStart.put("progress_install", "0");
taskArgsStart.put("par1", "installation_upgrade");
tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgsStart);

boolean success1 = downloadFile(url1, filePath1, "go_port_wca-aarch64.bin", downloadedBytes, lastPercent, lastTime, totalBytes, size1);
boolean success2 = downloadFile(url2, filePath2, "whatsapp-wca-aarch64.bin", downloadedBytes, lastPercent, lastTime, totalBytes, size2);
boolean success3 = downloadFile(url3, filePath3, "ffmpeg-wca-aarch64.bin", downloadedBytes, lastPercent, lastTime, totalBytes, size3);

if (success1 && success2 && success3) {
    String finalJson = tasker.getVariable("temp_json");
    if (finalJson == null || finalJson.equals("")) {
        finalJson = "";
    }

    HashMap taskArgsFinal = new HashMap();
    taskArgsFinal.put("progress_install", "100");
    taskArgsFinal.put("json", finalJson);
    taskArgsFinal.put("par1", "installation_upgrade");
    tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgsFinal);
    return "Success: All files downloaded";
} else {
    tasker.showToast("Error: One or more downloads failed");
    return "Error: Download failed";
}

document.addEventListener('DOMContentLoaded', () => {

    /* ═══════════════════════════════════════════════
       CONFIGURAÇÕES — edite apenas aqui
    ═══════════════════════════════════════════════ */
    const API_URL                = "http://localhost:3000";
    const AUTH                   = "Basic dXNlcjE6cGFzczE=";
    const USER_NAME              = "%user_name";
    const SHOW_WELCOME_MESSAGE   = %name_exist;
    const OPEN_INSTALL_TAB_FIRST = %open_tab;
    const FIXED_PHONE_NUMBER     = "";
    const VIP_LOG_DATA           = "%mode_system";
    const APP_VERSION            = "v 1.0.0";

    /* ═══════════════════════════════════════════════
       ESTADO INTERNO
    ═══════════════════════════════════════════════ */
    let qrTimers           = {};
    let checkTimers        = {};
    let currentZoomId      = null;
    let currentCodePhone   = null;
    let currentPairDeviceId = null;
    let selectedPlan       = { name: null, price: null };

    /* ═══════════════════════════════════════════════
       REFERÊNCIAS DO DOM
    ═══════════════════════════════════════════════ */
    const dom = {
        licenseLabel:         document.getElementById('licencaLabel'),
        licenseExpiry:        document.getElementById('licencaExp'),
        licenseIcon:          document.getElementById('licencaIcon'),
        licenseIconI:         document.getElementById('licencaIconI'),
        createDeviceBtn:      document.getElementById('createBtn'),
        menuBtn:              document.getElementById('menuBtn'),
        installBtn:           document.getElementById('installBtn'),
        telInput:             document.getElementById('telInput'),
        valMsg:               document.getElementById('valMsg'),
        buyTelInput:          document.getElementById('buyTel'),
        buySendBtn:           document.getElementById('btnSendBuy'),
        buyValMsg:            document.getElementById('buyValMsg'),
        codePhoneInput:       document.getElementById('codePhoneInput'),
        codeSendBtn:          document.getElementById('btnSendCodePhone'),
        codeValMsg:           document.getElementById('codeValMsg'),
        deviceList:           document.getElementById('deviceList'),
        noDeviceMessage:      document.getElementById('noDeviceMessage'),
        welcomeMessage:       document.getElementById('welcomeMessage'),
        helpModal:            document.getElementById('helpModal'),
        suggestionModal:      document.getElementById('sugestaoModal'),
        buyModal:             document.getElementById('buyModal'),
        zoomModal:            document.getElementById('zoomModal'),
        qrLoadingMsg:         document.getElementById('qrLoadingMsg'),
        zoomImg:              document.getElementById('zoomImg'),
        zoomTimerText:        document.getElementById('zoomTimerText'),
        codePhoneModal:       document.getElementById('codePhoneModal'),
        pairCodeModal:        document.getElementById('pairCodeModal'),
        pairLoadingMsg:       document.getElementById('pairLoadingMsg'),
        confirmModal:         document.getElementById('confirmModal'),
        suggestionText:       document.getElementById('sugestaoText'),
        buyNameInput:         document.getElementById('buyName'),
        selectedPlanValue:    document.getElementById('selectedPlanValue'),
        planErrorMsg:         document.getElementById('planErrorMsg'),
        zoomTimer:            document.getElementById('secCount'),
        pairCodeValue:        document.getElementById('pairCodeValue'),
        pairTimerText:        document.getElementById('pairTimerText'),
        pairCodeTimer:        document.getElementById('pairSecCount'),
        confirmDeleteBtn:     document.getElementById('btnConfirmDelete'),
        menuModalVersionBadge: document.getElementById('menuModalVersionBadge'),
        vipButton:            document.getElementById('vip-button'),
        vipCheckModal:        document.getElementById('vipCheckModal'),
    };

    /* ═══════════════════════════════════════════════
       LICENÇA / STATUS
    ═══════════════════════════════════════════════ */
    function processLicense() {
        const isVip     = VIP_LOG_DATA.includes("MODO VIP");
        const isExpired = VIP_LOG_DATA.includes("LICENÇA EXPIRADA");

        dom.licenseLabel.classList.remove('status-vip', 'status-expired', 'status-test');
        dom.licenseIcon.classList.remove('status-vip', 'status-expired', 'status-test');

        if (dom.menuBtn) dom.menuBtn.style.display = "block";

        if (isExpired) {
            dom.createDeviceBtn.disabled = true;
            dom.licenseLabel.textContent = "LICENÇA EXPIRADA";
            dom.licenseLabel.classList.add('status-expired');
            dom.licenseIcon.classList.add('status-expired');
            dom.licenseIconI.className = 'fa-solid fa-circle-xmark';
        } else if (isVip) {
            dom.licenseLabel.textContent = "MODO VIP ATIVO";
            dom.licenseLabel.classList.add('status-vip');
            dom.licenseIcon.classList.add('status-vip');
            dom.licenseIconI.className = 'fa-solid fa-crown';
        } else {
            dom.licenseLabel.textContent = "MODO TESTE ATIVO";
            dom.licenseLabel.classList.add('status-test');
            dom.licenseIcon.classList.add('status-test');
            dom.licenseIconI.className = 'fa-solid fa-flask';
        }

        const parts = VIP_LOG_DATA.split('|');
        if (parts.length >= 3) {
            dom.licenseExpiry.textContent =
                parts[2].trim() + (parts[3] ? ` | ${parts[3].trim()}` : "");
        }

        validatePhoneNumber();
    }

    /* ═══════════════════════════════════════════════
       MODAIS — abrir / fechar
    ═══════════════════════════════════════════════ */
    function openHelp()        { dom.helpModal.style.display = 'flex'; }
    function closeHelp()       { dom.helpModal.style.display = 'none'; }
    function openSuggestion()  { closeHelp(); dom.suggestionModal.style.display = 'flex'; }
    function closeSuggestion() { dom.suggestionModal.style.display = 'none'; }

    function cancelSuggestionAndOpenHelp() {
        closeSuggestion();
        openHelp();
    }

    function openBuyModal() {
        dom.buyModal.style.display = 'flex';
        dom.buyNameInput.value            = '';
        dom.selectedPlanValue.textContent = '';
        dom.planErrorMsg.textContent      = '';
        selectedPlan = { name: null, price: null };
        document.querySelectorAll('.plan-button').forEach(b => b.classList.remove('selected'));
        validateBuyPhoneNumber();
    }
    function closeBuyModal() { dom.buyModal.style.display = 'none'; }

    function openCodePhone(id) {
        currentPairDeviceId = id;
        dom.codePhoneInput.value = "";
        dom.codeSendBtn.disabled = true;
        dom.codePhoneModal.style.display = 'flex';
    }
    function closeCodePhone() { dom.codePhoneModal.style.display = 'none'; }

    function closeZoom() {
        dom.zoomModal.style.display = 'none';
        if (currentZoomId) stopAllTimers(currentZoomId);
        currentZoomId = null;
        dom.qrLoadingMsg.style.display  = 'flex';
        dom.zoomImg.style.display       = 'none';
        dom.zoomTimerText.style.display = 'none';
    }

    function closePairCode() {
        dom.pairCodeModal.style.display     = 'none';
        dom.pairLoadingMsg.style.display    = 'flex';
        dom.pairCodeValue.style.display     = 'none';
        dom.pairTimerText.style.display     = 'none';
        clearInterval(qrTimers["pair"]);
    }

    function askDelete(id) {
        dom.confirmModal.style.display = 'flex';
        dom.confirmDeleteBtn.onclick   = () => doDelete(id);
    }
    function closeConfirm() { dom.confirmModal.style.display = 'none'; }

    /* ═══════════════════════════════════════════════
       SUGESTÃO / FEEDBACK
    ═══════════════════════════════════════════════ */
    function sendSuggestion() {
        const msg     = dom.suggestionText.value;
        const jsonMsg = JSON.stringify({ suggestion: msg }, null, 2);
        tk.setLocal("task", "suggestion-msg");
        tk.setLocal("json", jsonMsg);
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
        closeSuggestion();
    }

    /* ═══════════════════════════════════════════════
       AÇÕES DO MENU
    ═══════════════════════════════════════════════ */
    function openFaq() {
        tk.setLocal("task", "open-faq");
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
    }

    function talkToDeveloper() {
        tk.setLocal("task", "talk-developer");
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
    }

    function quickUpdate() {
        closeHelp();
        tk.setLocal("task", "update-git");
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
    }

    function showAlertTaskerUpdate() {
        tk.setLocal("task", "update-task");
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
    }

    /* ═══════════════════════════════════════════════
       PLANOS DE COMPRA
    ═══════════════════════════════════════════════ */
    function selectPlan(button) {
        dom.planErrorMsg.textContent = '';
        document.querySelectorAll('.plan-button').forEach(b => b.classList.remove('selected'));
        button.classList.add('selected');
        selectedPlan.name  = button.getAttribute('data-plan');
        selectedPlan.price = button.getAttribute('data-price');
        dom.selectedPlanValue.textContent = `Valor: ${selectedPlan.price}`;
    }

    function sendPurchase() {
        if (!selectedPlan.name) {
            dom.planErrorMsg.textContent = "Por favor, selecione um plano.";
            return;
        }
        dom.planErrorMsg.textContent = "";
        tk.setLocal("task", "buy-vip");
        tk.setLocal("json",
            `Desejo contratar o plano apresentado.\n\nNome: ${dom.buyNameInput.value}\nPlano: ${selectedPlan.name}\nTelefone: ${dom.buyTelInput.value}\nValor: ${selectedPlan.price}`
        );
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
        closeBuyModal();
    }

    /* ═══════════════════════════════════════════════
       TABS
    ═══════════════════════════════════════════════ */
    function openTab(evt, tabName) {
        document.querySelectorAll(".tab-content").forEach(c => c.classList.remove("active"));
        document.querySelectorAll(".tab-btn").forEach(b => b.classList.remove("active"));
        document.getElementById(tabName).classList.add("active");

        const targetButton = evt && evt.currentTarget
            ? evt.currentTarget
            : document.querySelector(`.tab-btn[onclick*="'${tabName}'"]`);
        if (targetButton) targetButton.classList.add('active');

        if (tabName === 'connections-tab') {
            checkServerStatus().then(isOnline => { if (isOnline) fetchDevices(); });
        }
    }

    /* ═══════════════════════════════════════════════
       VALIDAÇÕES
    ═══════════════════════════════════════════════ */
    function validatePhoneNumber() {
        const isExpired = VIP_LOG_DATA.includes("LICENÇA EXPIRADA");
        dom.telInput.value = dom.telInput.value.replace(/\D/g, '');
        const val     = dom.telInput.value;
        const isValid = (val.length === 12 || val.length === 13);

        dom.valMsg.classList.remove('success', 'error');

        if (isExpired && val.length > 0) {
            dom.valMsg.textContent = "ACESSO BLOQUEADO (LICENÇA EXPIRADA)";
            dom.valMsg.classList.add('error');
            dom.installBtn.disabled = true;
        } else if (isValid) {
            dom.valMsg.textContent = "✓ Válido";
            dom.valMsg.classList.add('success');
            dom.installBtn.disabled = false;
        } else {
            dom.valMsg.textContent = val.length === 0 ? "" : "✗ Inválido";
            if (val.length > 0) dom.valMsg.classList.add('error');
            dom.installBtn.disabled = true;
        }
    }

    function validateBuyPhoneNumber() {
        dom.buyTelInput.value = dom.buyTelInput.value.replace(/\D/g, '');
        const isValid = (dom.buyTelInput.value.length === 12 || dom.buyTelInput.value.length === 13);
        dom.buyValMsg.classList.remove('success', 'error');
        if (isValid) {
            dom.buyValMsg.textContent = "";
            dom.buySendBtn.disabled = false;
        } else {
            dom.buyValMsg.textContent = dom.buyTelInput.value.length === 0 ? "" : "Número inválido";
            if (dom.buyTelInput.value.length > 0) dom.buyValMsg.classList.add('error');
            dom.buySendBtn.disabled = true;
        }
    }

    function validateCodePhoneNumber() {
        dom.codePhoneInput.value = dom.codePhoneInput.value.replace(/\D/g, '');
        const val = dom.codePhoneInput.value;
        dom.codeValMsg.classList.remove('success', 'error');
        if (val.length === 12 || val.length === 13) {
            dom.codeValMsg.textContent = "✓ Número válido";
            dom.codeValMsg.classList.add('success');
            dom.codeSendBtn.disabled = false;
        } else {
            dom.codeValMsg.textContent = val.length === 0 ? "" : "✗ Número inválido";
            if (val.length > 0) dom.codeValMsg.classList.add('error');
            dom.codeSendBtn.disabled = true;
        }
    }

    /* ═══════════════════════════════════════════════
       INSTALAÇÃO
    ═══════════════════════════════════════════════ */
    function install() {
        const installData = JSON.stringify({
            number: dom.telInput.value,
            reset:  document.querySelector('input[name="resetMode"]:checked').value === "true"
        }, null, 2);
        tk.setLocal("task", "install-project");
        tk.setLocal("json", installData);
        tk.destroyScene('001-CENTRAL_WHATS_CONNECT_API [wca]');
    }

    /* ═══════════════════════════════════════════════
       CÓDIGO DE PAREAMENTO
    ═══════════════════════════════════════════════ */
    async function startCodeGeneration() {
        currentCodePhone = dom.codePhoneInput.value;
        if (currentPairDeviceId) {
            closeCodePhone();
            dom.pairLoadingMsg.style.display = 'flex';
            dom.pairCodeValue.style.display  = 'none';
            dom.pairTimerText.style.display  = 'none';
            dom.pairCodeModal.style.display  = 'flex';
            await fetchPairCode(currentPairDeviceId);
        }
    }

    async function fetchPairCode(id) {
        try {
            const res  = await fetch(`${API_URL}/app/login-with-code?phone=${currentCodePhone}`, {
                headers: { "Authorization": AUTH, "X-Device-Id": id }
            });
            const data = await res.json();
            if (data.results?.pair_code) {
                dom.pairCodeValue.textContent    = data.results.pair_code;
                dom.pairLoadingMsg.style.display = 'none';
                dom.pairCodeValue.style.display  = 'block';
                dom.pairTimerText.style.display  = 'block';
                dom.pairCodeTimer.textContent    = "30";
                startPairTimer(id, 30);
                startStatusCheck(id);
            }
        } catch (e) { console.error("Erro ao buscar código de pareamento:", e); }
    }

    function startPairTimer(id, seconds) {
        clearInterval(qrTimers["pair"]);
        let count = seconds;
        qrTimers["pair"] = setInterval(() => {
            count--;
            dom.pairCodeTimer.textContent = count;
            if (count <= 0) {
                clearInterval(qrTimers["pair"]);
                dom.pairLoadingMsg.style.display = 'flex';
                dom.pairCodeValue.style.display  = 'none';
                dom.pairTimerText.style.display  = 'none';
                fetchPairCode(id);
            }
        }, 1000);
    }

    /* ═══════════════════════════════════════════════
       QR CODE
    ═══════════════════════════════════════════════ */
    async function getQr(id) {
        currentZoomId = id;
        dom.qrLoadingMsg.style.display  = 'flex';
        dom.zoomImg.style.display       = 'none';
        dom.zoomTimerText.style.display = 'none';
        dom.zoomModal.style.display     = 'flex';
        try {
            const res = await fetch(`${API_URL}/app/login`, {
                headers: { "Authorization": AUTH, "X-Device-Id": id }
            });
            const d = await res.json();
            if (d.results?.qr_link) {
                dom.zoomImg.src                 = d.results.qr_link;
                dom.qrLoadingMsg.style.display  = 'none';
                dom.zoomImg.style.display       = 'block';
                dom.zoomTimerText.style.display = 'block';
                dom.zoomTimer.textContent       = d.results.qr_duration;
                startQrTimer(id, d.results.qr_duration);
                startStatusCheck(id);
            }
        } catch (e) { console.error("Erro ao obter QR Code:", e); }
    }

    function startQrTimer(id, seconds) {
        clearInterval(qrTimers[id]);
        let count = seconds;
        qrTimers[id] = setInterval(() => {
            count--;
            if (currentZoomId === id) dom.zoomTimer.textContent = count;
            if (count <= 0) { stopAllTimers(id); getQr(id); }
        }, 1000);
    }

    /* ═══════════════════════════════════════════════
       SERVIDOR & DISPOSITIVOS
    ═══════════════════════════════════════════════ */
    async function checkServerStatus() {
        try {
            const res = await fetch(`${API_URL}/`, { headers: { "Authorization": AUTH } });
            if (res.ok) {
                dom.createDeviceBtn.disabled = false;
                return true;
            }
            handleServerError(`Status: ${res.status}`);
            return false;
        } catch (e) {
            handleServerError(e.message);
            return false;
        }
    }

    function handleServerError(errorDetails) {
        dom.deviceList.innerHTML          = '';
        dom.noDeviceMessage.textContent   = 'Servidor offline.';
        dom.noDeviceMessage.style.display = 'block';
        dom.createDeviceBtn.disabled      = true;
        console.error("Erro de servidor:", errorDetails);
    }

    async function fetchDevices() {
        try {
            const res     = await fetch(`${API_URL}/devices`, { headers: { "Authorization": AUTH } });
            const data    = await res.json();
            const devices = data.results || [];
            dom.deviceList.innerHTML = '';

            dom.noDeviceMessage.style.display = devices.length === 0 ? 'block' : 'none';
            dom.noDeviceMessage.textContent   = 'Nenhum dispositivo cadastrado.';

            devices.sort((a, b) => a.id.localeCompare(b.id)).forEach((dev, index) => {
                const card     = document.createElement('div');
                const isOnline = dev.state === 'logged_in';
                card.className = `device-card${isOnline ? '' : ' offline'}`;
                card.style.animationDelay = `${index * 80}ms`;

                const nameToDisplay = isOnline ? (dev.display_name || 'Conectando...') : 'Dispositivo';
                const idToDisplay   = isOnline ? (dev.jid ? dev.jid.split('@')[0] : dev.id) : dev.id;

                const buttonsHtml = !isOnline ? `
                    <div style="display:flex; gap:8px; margin-top:8px;">
                        <button class="btn-action" style="flex:1; font-size:0.65rem; background:rgba(15,157,203,0.08); color:var(--primary); border:1px solid rgba(15,157,203,0.3);">CÓDIGO</button>
                        <button class="btn-action" style="flex:1; font-size:0.65rem; background:rgba(15,157,203,0.08); color:var(--primary); border:1px solid rgba(15,157,203,0.3);">QR CODE</button>
                    </div>` : '';

                card.innerHTML = `
                    <button class="btn-delete"><i class="fa-solid fa-trash-can"></i></button>
                    <div style="display:flex; gap:8px; align-items:center; padding-right:1.6rem;">
                        <h4 style="font-size:0.88rem; font-weight:700;"></h4>
                        <span class="badge ${isOnline ? 'badge-online' : 'badge-offline'}">${isOnline ? 'ONLINE' : 'OFFLINE'}</span>
                    </div>
                    <p style="font-size:0.72rem; color:var(--text-dim); font-family:'Inter',monospace; margin-top:3px;"></p>
                    ${buttonsHtml}`;

                card.querySelector('h4').textContent = nameToDisplay;
                card.querySelector('p').textContent  = idToDisplay;
                card.querySelector('.btn-delete').onclick = () => askDelete(dev.id);

                if (!isOnline) {
                    card.querySelectorAll('.btn-action')[0].onclick = () => openCodePhone(dev.id);
                    card.querySelectorAll('.btn-action')[1].onclick = () => getQr(dev.id);
                }

                dom.deviceList.appendChild(card);
            });

            return devices.filter(d => d.state === 'logged_in').every(d => d.display_name);
        } catch (e) {
            handleServerError(e);
            return true;
        }
    }

    function startStatusCheck(id) {
        clearInterval(checkTimers[id]);
        checkTimers[id] = setInterval(async () => {
            try {
                const res  = await fetch(`${API_URL}/devices/${id}`, {
                    headers: { "Authorization": AUTH, "X-Device-Id": id }
                });
                const data = await res.json();
                if (data.results?.state === 'logged_in') {
                    stopAllTimers(id);
                    closeZoom();
                    closePairCode();
                    let attempts = 0;
                    const nameFinder = setInterval(async () => {
                        if (await fetchDevices() || attempts++ > 20) clearInterval(nameFinder);
                    }, 1000);
                }
            } catch (e) { /* Ignora erros de checagem */ }
        }, 1500);
    }

    function stopAllTimers(id) {
        if (id) {
            clearInterval(qrTimers[id]);
            clearInterval(checkTimers[id]);
        }
        clearInterval(qrTimers["pair"]);
    }

    async function doDelete(id) {
        stopAllTimers(id);
        await Promise.all([
            fetch(`${API_URL}/app/logout`,    { headers: { "Authorization": AUTH, "X-Device-Id": id } }),
            fetch(`${API_URL}/devices/${id}`, { method: 'DELETE', headers: { "Authorization": AUTH, "X-Device-Id": id } })
        ]);
        closeConfirm();
        fetchDevices();
    }

    async function createDevice() {
        await fetch(`${API_URL}/devices`, {
            method: 'POST',
            headers: { 'Authorization': AUTH, 'Content-Type': 'application/json' },
            body: JSON.stringify({})
        });
        fetchDevices();
    }

    /* ═══════════════════════════════════════════════
       MENSAGEM DE BOAS-VINDAS
    ═══════════════════════════════════════════════ */
    function setWelcomeMessage() {
        if (!dom.welcomeMessage) return;
        dom.welcomeMessage.style.display = SHOW_WELCOME_MESSAGE ? 'inline-block' : 'none';
        if (SHOW_WELCOME_MESSAGE) {
            dom.welcomeMessage.innerHTML = `<span>BEM-VINDO ${USER_NAME.toUpperCase()} AO WCA</span>`;
        }
    }

    /* ═══════════════════════════════════════════════
       LISTENERS GLOBAIS
    ═══════════════════════════════════════════════ */
    function openVipCheck()  { closeHelp(); dom.vipCheckModal.style.display = 'flex'; }
    function closeVipCheck() { dom.vipCheckModal.style.display = 'none'; }

    let vipToastTimer = null;

    function showVipToast() {
        const toast = document.getElementById('vipToast');
        if (!toast) return;
        clearTimeout(vipToastTimer);
        toast.classList.add('show');
        vipToastTimer = setTimeout(() => toast.classList.remove('show'), 5000);
    }

    function confirmVipCheck() {
        closeVipCheck();
        const isVip     = VIP_LOG_DATA.includes("MODO VIP");
        const isExpired = VIP_LOG_DATA.includes("LICENÇA EXPIRADA");
        if (isVip && !isExpired) {
            openHelp();
            showVipToast();
        } else {
            processLicense();
            alert('Status verificado. Nenhum acesso VIP ativo foi encontrado.');
        }
    }

    function setupGlobalListeners() {
        if (dom.vipButton) {
            dom.vipButton.addEventListener('click', openVipCheck);
        }

        dom.helpModal.addEventListener('click', (e) => {
            if (e.target === dom.helpModal) closeHelp();
        });

        dom.vipCheckModal.addEventListener('click', (e) => {
            if (e.target === dom.vipCheckModal) closeVipCheck();
        });
    }

    /* ═══════════════════════════════════════════════
       INICIALIZAÇÃO
    ═══════════════════════════════════════════════ */
    function initialize() {
        processLicense();
        setWelcomeMessage();
        setupGlobalListeners();

        if (dom.menuModalVersionBadge) {
            dom.menuModalVersionBadge.textContent = APP_VERSION;
        }

        const initialTab = OPEN_INSTALL_TAB_FIRST ? 'config-tab' : 'connections-tab';
        const tabButton  = document.querySelector(`.tab-btn[onclick*="'${initialTab}'"]`);
        openTab({ currentTarget: tabButton }, initialTab);

        if (FIXED_PHONE_NUMBER && dom.telInput) {
            dom.telInput.value = FIXED_PHONE_NUMBER;
            validatePhoneNumber();
        }

        checkServerStatus().then(isOnline => {
            if (isOnline) {
                fetchDevices().then(allNamesAreSet => {
                    if (!allNamesAreSet) {
                        let attempts = 0;
                        const initialNamePoller = setInterval(() => {
                            fetchDevices().then(allNamesNowSet => {
                                attempts++;
                                if (allNamesNowSet || attempts >= 20) clearInterval(initialNamePoller);
                            });
                        }, 3000);
                    }
                });
            }
        });

        Object.assign(window, {
            openHelp, closeHelp,
            openSuggestion, closeSuggestion, cancelSuggestionAndOpenHelp, sendSuggestion,
            openFaq, talkToDeveloper, quickUpdate, showAlertTaskerUpdate,
            openBuyModal, closeBuyModal, selectPlan, sendPurchase,
            openTab, validatePhoneNumber, validateBuyPhoneNumber,
            install, openCodePhone, closeCodePhone, validateCodePhoneNumber,
            startCodeGeneration, getQr, askDelete, closeConfirm,
            createDevice, closeZoom, closePairCode,
            openVipCheck, closeVipCheck, confirmVipCheck
        });
    }

    initialize();
});

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

:root {
    --bg-body:   #000;
    --bg-card:   #06222A;
    --primary:   #0F9DCB;
    --accent:    #B5FB2A;
    --border:    #0F507A;
    --text-main: #C6E3DC;
    --text-dim:  #8494A4;
    --color-0:   #ff4d4d;
    --color-10:  #ff794d;
    --color-20:  #ffa64d;
    --color-30:  #ffd24d;
    --color-40:  #ffff4d;
    --color-50:  #d2ff4d;
    --color-60:  #a6ff4d;
    --color-70:  #79ff4d;
    --color-80:  #4dff4d;
    --color-90:  #4dff79;
    --color-100: #4dffa6;
}

*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    font-family: 'Exo 2', sans-serif;
}

html, body {
    height: 100%;
    width: 100%;
    overflow: hidden;
}

body {
    background-color: var(--bg-body);
    color: var(--text-main);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 1rem;
    background-image:
        radial-gradient(ellipse at 20% 20%, rgba(15,157,203,0.06) 0%, transparent 50%),
        radial-gradient(ellipse at 80% 80%, rgba(181,251,42,0.04) 0%, transparent 50%);
}

.main-container {
    width: 100%;
    max-width: 25rem;
    background: var(--bg-card);
    border-radius: 1.25rem;
    border: 0.0625rem solid #0F9DCB55;
    box-shadow: 0 1.5rem 3rem rgba(0,0,0,0.7), 0 0 1.5rem rgba(15,157,203,0.14);
    display: flex;
    flex-direction: column;
    position: relative;
    overflow: hidden;
    margin-bottom: 1.5rem;
}

.main-container::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 0.125rem;
    background: linear-gradient(90deg, transparent, #0F9DCB, transparent);
    z-index: 2;
}

.panel-header {
    padding: 1rem;
    background: rgba(0,0,0,0.3);
    border-bottom: 0.0625rem solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.header-video {
    width: 3.2rem;
    height: 3.2rem;
    border-radius: 50%;
    object-fit: cover;
}

.panel-header h2 {
    font-size: 0.8rem;
    flex: 1;
    text-align: center;
    font-weight: 600;
    letter-spacing: 0.1rem;
    font-family: 'Orbitron', sans-serif;
}

.accent-text { color: var(--accent); }

.content-area {
    padding: 2rem 1rem;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 1.5rem;
}

.progress-container {
    position: relative;
    width: 10rem;
    height: 10rem;
    display: flex;
    justify-content: center;
    align-items: center;
}

.progress-ring {
    width: 100%;
    height: 100%;
    transform: rotate(-90deg);
    filter: drop-shadow(0 0 0.4rem rgba(15,157,203,0.4));
}

.progress-ring__background {
    stroke: rgba(0,0,0,0.3);
    stroke-width: 12;
    fill: transparent;
}

.progress-ring__circle {
    stroke: var(--color-0);
    stroke-width: 12;
    fill: transparent;
    stroke-linecap: round;
    transition: stroke-dashoffset 0.5s ease, stroke 0.5s ease;
}

.progress-text {
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    font-size: 2.2rem;
    font-weight: 900;
    color: var(--text-main);
    font-family: 'Orbitron', sans-serif;
}

.status-info { text-align: center; width: 100%; }

#status-message {
    font-size: 0.75rem;
    color: var(--text-dim);
    margin-bottom: 0.5rem;
    min-height: 1.2em;
    letter-spacing: 0.025rem;
}

.timer {
    font-size: 0.7rem;
    color: var(--primary);
    font-weight: 600;
    font-family: 'Orbitron', sans-serif;
    letter-spacing: 0.05rem;
}

.info-section {
    width: 100%;
    max-width: 25rem;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.info-card {
    width: 100%;
    background: var(--bg-card);
    border: 0.0625rem solid var(--border);
    border-radius: 0.875rem;
    padding: 1rem;
    text-align: center;
    position: relative;
    overflow: hidden;
    opacity: 0;
    transform: translateY(0.75rem);
    transition: opacity 0.5s ease, transform 0.5s ease;
    display: none;
}

.info-card.visible { display: block; }
.info-card.show { opacity: 1; transform: translateY(0); }

.info-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 0.125rem;
    background: linear-gradient(90deg, transparent, var(--card-accent, var(--primary)), transparent);
}

.info-label {
    display: inline-block;
    font-size: 0.55rem;
    font-weight: 800;
    letter-spacing: 0.1rem;
    text-transform: uppercase;
    padding: 0.1rem 0.5rem;
    border-radius: 1rem;
    margin-bottom: 0.5rem;
    background: rgba(255,255,255,0.06);
    color: var(--card-accent, var(--primary));
    border: 0.0625rem solid var(--card-accent, var(--primary));
    font-family: 'Orbitron', sans-serif;
}

.info-card .info-icon {
    display: flex;
    justify-content: center;
    align-items: center;
    margin: 0.2rem auto 0.5rem;
    color: var(--card-accent, var(--primary));
}

.info-card .info-icon svg {
    width: 1.5rem; height: 1.5rem;
    stroke: currentColor; stroke-width: 1.6; fill: none;
}

.info-card .info-text {
    font-size: 0.7rem;
    font-weight: 600;
    letter-spacing: 0.035rem;
    text-transform: uppercase;
    color: var(--card-text, var(--text-main));
    line-height: 1.4;
}

.info-progress-bar {
    margin-top: 0.75rem;
    height: 0.125rem;
    width: 100%;
    background: rgba(255,255,255,0.05);
    border-radius: 0.125rem;
    overflow: hidden;
}

.info-progress-fill {
    height: 100%; width: 0%;
    background: linear-gradient(90deg, var(--card-bar-a, var(--primary)), var(--card-bar-b, var(--accent)));
}

/* =============================================
   TEMAS DOS CARDS
   ============================================= */

.theme-cyan   { --card-accent:#0F9DCB; --card-text:#C6E3DC; --card-bar-a:#0F9DCB; --card-bar-b:#B5FB2A; }
.theme-green  { --card-accent:#4dff79; --card-text:#c6ffda; --card-bar-a:#4dff79; --card-bar-b:#B5FB2A; }
.theme-purple { --card-accent:#b06aff; --card-text:#e8d6ff; --card-bar-a:#b06aff; --card-bar-b:#ff6af5; }
.theme-orange { --card-accent:#ff9f4a; --card-text:#ffe8cc; --card-bar-a:#ff9f4a; --card-bar-b:#ffd24d; }
.theme-pink   { --card-accent:#ff5fa0; --card-text:#ffd6e8; --card-bar-a:#ff5fa0; --card-bar-b:#ff9f4a; }
.theme-teal   { --card-accent:#00e5c8; --card-text:#ccfff8; --card-bar-a:#00e5c8; --card-bar-b:#0F9DCB; }
.theme-red    { --card-accent:#ff4d6a; --card-text:#ffd6dc; --card-bar-a:#ff4d6a; --card-bar-b:#ff9f4a; }
.theme-ice    { --card-accent:#7de8ff; --card-text:#e0f8ff; --card-bar-a:#7de8ff; --card-bar-b:#4dffef; }
.theme-warn   {
    --card-accent:#ffd24d; --card-text:#fff3cc; --card-bar-a:#ffd24d; --card-bar-b:#ff9f4a;
    animation: warnPulse 2s ease-in-out infinite;
}

@keyframes warnPulse {
    0%,100% { box-shadow: 0 0 1rem rgba(255,210,77,0.10); }
    50%     { box-shadow: 0 0 1.75rem rgba(255,210,77,0.25); }
}

.main-footer {
    position: fixed;
    bottom: 0.75rem;
    width: 100%;
    text-align: center;
    font-size: 0.65rem;
    color: var(--text-dim);
}

.dev-name { color: var(--accent); font-weight: 600; }

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "css";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

window.INSTALL_MODE = "%type_project";

window.PROGRESS_CONTROL = {
    percent: 0,
    message: "Baixando Arquivos..."
};

const FILE_CARDS = {
    "project-task": [
        { min: 0, max: 100, label: "PROJETO", theme: "theme-orange", icon: "xml", text: "BAIXANDO WCA API.PRJ.XML" }
    ],
    "project-api": [
        { min: 0,  max: 33,  label: "ARQUIVO 1", theme: "theme-cyan",   icon: "download", text: "BAIXANDO GO PORT WCA" },
        { min: 34, max: 66,  label: "ARQUIVO 2", theme: "theme-purple", icon: "file",     text: "BAIXANDO WHATSAPP WCA" },
        { min: 67, max: 100, label: "ARQUIVO 3", theme: "theme-teal",   icon: "music",    text: "BAIXANDO FFMPEG WCA" }
    ]
};

const APP_STATE = {
    startTime: Date.now(),
    lastPercent: -1,
    lastMessage: "",
    completed: false
};

const ICONS = {
    'download': '<polyline points="8 17 12 21 16 17"/><line x1="12" y1="12" x2="12" y2="21"/><path d="M20.88 18.09A5 5 0 0 0 18 9h-1.26A8 8 0 1 0 3 16.29"/>',
    'file':     '<path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/>',
    'music':    '<path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/>',
    'xml':      '<polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/><line x1="14" y1="4" x2="10" y2="20"/>'
};

document.addEventListener('DOMContentLoaded', () => {
    const progressRing  = document.querySelector('.progress-ring__circle');
    const progressText  = document.getElementById('progress-text');
    const statusMessage = document.getElementById('status-message');
    const timerDisplay  = document.getElementById('timer-display');

    const radius        = 90;
    const circumference = 2 * Math.PI * radius;
    if (progressRing) progressRing.style.strokeDasharray = `${circumference} ${circumference}`;

    const currentCards = FILE_CARDS[window.INSTALL_MODE];

    function getColor(p) {
        if (p < 10)  return 'var(--color-0)';
        if (p < 20)  return 'var(--color-10)';
        if (p < 30)  return 'var(--color-20)';
        if (p < 40)  return 'var(--color-30)';
        if (p < 50)  return 'var(--color-40)';
        if (p < 60)  return 'var(--color-50)';
        if (p < 70)  return 'var(--color-60)';
        if (p < 80)  return 'var(--color-70)';
        if (p < 90)  return 'var(--color-80)';
        if (p < 100) return 'var(--color-90)';
        return 'var(--color-100)';
    }

    function updateUI(percent, message) {
        const p = Math.max(0, Math.min(100, percent));
        const offset = circumference - (p / 100) * circumference;

        if (progressRing) {
            progressRing.style.strokeDashoffset = offset;
            progressRing.style.stroke = getColor(p);
        }
        if (progressText) progressText.textContent = p + '%';
        if (message && statusMessage) statusMessage.textContent = message;

        if (p >= 100 && !APP_STATE.completed) {
            APP_STATE.completed = true;
            setTimeout(() => {
                tk.destroyScene('002-INSTALACAO_PROJETO [wca]');
            }, 1000);
        }
    }

    setInterval(() => {
        const elapsed = Math.floor((Date.now() - APP_STATE.startTime) / 1000);
        const mins = Math.floor(elapsed / 60).toString().padStart(2, '0');
        const secs = (elapsed % 60).toString().padStart(2, '0');
        if (timerDisplay) timerDisplay.textContent = mins + ':' + secs;
    }, 1000);

    function monitor() {
        const p = window.PROGRESS_CONTROL.percent;
        const m = window.PROGRESS_CONTROL.message;
        if (p !== APP_STATE.lastPercent || m !== APP_STATE.lastMessage) {
            APP_STATE.lastPercent = p;
            APP_STATE.lastMessage = m;
            updateUI(p, m);
        }
        requestAnimationFrame(monitor);
    }
    monitor();

    const infoCard    = document.getElementById('info-card');
    const infoLabelEl = document.getElementById('info-label');
    const infoIconEl  = document.getElementById('info-icon');
    const infoTextEl  = document.getElementById('info-text');
    const infoFillEl  = document.getElementById('info-progress-fill');

    let currentCardIndex = -1;

    function getCardIndexForPercent(p) {
        for (let i = 0; i < currentCards.length; i++) {
            if (p >= currentCards[i].min && p <= currentCards[i].max) return i;
        }
        return currentCards.length - 1;
    }

    function getBarPercent(p, card) {
        const range = card.max - card.min;
        const pos   = Math.max(0, Math.min(range, p - card.min));
        return range > 0 ? Math.round((pos / range) * 100) : 100;
    }

    function showCard(index) {
        if (index < 0 || index >= currentCards.length) return;
        const msg  = currentCards[index];
        const barW = getBarPercent(window.PROGRESS_CONTROL.percent, msg) + '%';

        if (index !== currentCardIndex) {
            currentCardIndex = index;
            infoCard.classList.remove('show');

            setTimeout(() => {
                infoLabelEl.textContent = msg.label;
                infoTextEl.textContent  = msg.text;
                infoCard.className = 'info-card visible ' + msg.theme;

                const iconKey = msg.icon || 'file';
                infoIconEl.innerHTML =
                    '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round">' +
                    (ICONS[iconKey] || ICONS['file']) + '</svg>';

                infoFillEl.style.transition = 'none';
                infoFillEl.style.width = barW;
                void infoCard.offsetWidth;
                infoCard.classList.add('show');
            }, 300);
        } else {
            infoFillEl.style.transition = 'width 0.5s ease';
            infoFillEl.style.width = barW;
        }
    }

    function monitorCard() {
        showCard(getCardIndexForPercent(window.PROGRESS_CONTROL.percent));
        requestAnimationFrame(monitorCard);
    }
    monitorCard();
});

