:root {
    --bg-body: #000;
    --bg-card: #06222A;
    --primary: #0F9DCB;
    --accent: #B5FB2A;
    --border: #0F507A;
    --text-main: #C6E3DC;
    --text-dim: #8494A4;
    font-size: 16px;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    font-family: 'Inter', sans-serif;
}

body {
    background-color: var(--bg-body);
    color: var(--text-main);
    width: 100vw;
    height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    overflow: hidden;
}

.content-wrapper {
    width: 92vw;
    max-width: 28rem;
    display: flex;
    flex-direction: column;
}

.main-container {
    width: 100%;
    background: var(--bg-card);
    border-radius: 1.125rem;
    border: 0.0625rem solid var(--border);
    box-shadow: 0 0.75rem 2.1875rem rgba(0,0,0,0.65);
    overflow: hidden;
}

.panel-header {
    padding: 0.875rem 1.25rem;
    background: rgba(0,0,0,0.4);
    border-bottom: 0.0625rem solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.header-video {
    width: 3rem;
    height: 3rem;
    border-radius: 50%;
    object-fit: cover;
}

.panel-header h2 {
    font-size: 1.125rem;
    flex: 1;
    text-align: center;
    font-weight: 600;
    letter-spacing: 0.0375rem;
}

.accent-text { color: var(--accent); }

.info-container {
    padding: 1.25rem 1.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    max-height: 60vh;
    overflow-y: auto;
}

.instrucao {
    font-size: 0.8125rem;
    color: var(--text-dim);
    text-align: center;
    text-transform: uppercase;
    letter-spacing: 0.05rem;
    margin-bottom: 0.25rem;
}

.btn-device {
    width: 100%;
    padding: 1rem;
    background: rgba(15, 157, 203, 0.08);
    color: var(--text-main);
    border: 0.0625rem solid var(--border);
    border-radius: 0.75rem;
    font-size: 0.9375rem;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    align-items: center;
    gap: 0.875rem;
    text-align: left;
}

.btn-device i {
    color: var(--accent);
    font-size: 1.2rem;
}

.btn-device div {
    display: flex;
    flex-direction: column;
}

.btn-device strong {
    color: #fff;
    font-size: 0.9375rem;
}

.btn-device span {
    font-size: 0.8125rem;
    color: var(--text-dim);
}

.btn-device:active {
    transform: scale(0.97);
    background: var(--border);
}

.main-footer {
    padding: 1.25rem 0;
    text-align: center;
    font-size: 0.8125rem;
    color: #aaa;
}

.dev-name {
    color: var(--accent);
    font-weight: 600;
}

.info-container::-webkit-scrollbar { width: 0.25rem; }
.info-container::-webkit-scrollbar-thumb { background: var(--border); border-radius: 0.625rem; }

#statusMsg {
    text-align: center;
    padding: 1.5rem;
    color: var(--primary);
}

.position-center { justify-content: center; min-height: 100vh; }

