import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.io.File;
import java.io.BufferedReader;
import java.io.FileReader;

logPath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/mode-system.log";
logFile = new File(logPath);
modeSystem = "";

if (logFile.exists()) {
    reader = new BufferedReader(new FileReader(logFile));
    line = "";
    while ((line = reader.readLine()) != null) {
        modeSystem = modeSystem + line + "\n";
    }
    reader.close();
}


if (modeSystem.length() > 0) {
    modeSystem = modeSystem.trim();
}

nameExist = false;
userName = "MODO TESTE";

if (modeSystem.length() > 0) {
    regex = Pattern.compile("Usuário:\\s*([^|]+?)\\s*\\|", Pattern.CASE_INSENSITIVE);
    matcher = regex.matcher(modeSystem);

    if (matcher.find()) {
        foundName = matcher.group(1).trim();

        if (!foundName.toLowerCase().equals("teste")) {
            nameExist = true;
            userName = foundName;
        }
    }
}

tasker.setVariable("mode_system", modeSystem);
tasker.setVariable("name_exist", String.valueOf(nameExist));
tasker.setVariable("user_name", userName);

:root {
  --bg-body: #000000;
  --bg-card: #06222A;
  --primary: #0F9DCB;
  --accent: #B5FB2A;
  --border: #0F507A;
  --text-main: #C6E3DC;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
}

body {
  background-color: var(--bg-body);
  color: var(--text-main);
  font-family: system-ui, -apple-system, sans-serif;
  min-height: 100vh;
  margin: 0;
}

.main-wrapper {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  width: 100vw;
  padding: 1rem;
  gap: 1.5rem;
}

.panel-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: rgba(0, 0, 0, 0.4);
  border: 0.0625rem solid var(--border);
  border-radius: 1rem;
  padding: 0.75rem 1rem;
  width: 100%;
  max-width: 40rem;
  box-shadow: 0 0.75rem 2.25rem rgba(0, 0, 0, 0.6);
}

@media (min-width: 30rem) {
  .panel-header {
    padding: 0.75rem 1.5rem;
  }
}

.header-video {
  width: 3rem;
  height: 3rem;
  border-radius: 50vw;
  object-fit: cover;
  background-color: var(--bg-card);
  border: 0.125rem solid var(--border);
  flex-shrink: 0;
}

h2 {
  margin: 0;
  padding: 0 0.5rem;
  display: flex;
  justify-content: center;
  align-items: center;
  flex: 1;
}

.accent-text {
  color: var(--accent);
  font-weight: 800;
  letter-spacing: 0.08em;
  text-shadow: 0 0 0.75rem rgba(181, 251, 42, 0.25);
