        } catch (IOException e) {
        }
    }
}

const lastUpdatedVersion = "%last_update";
const minRequiredMinutes = 5;
let currentUpdateType = "NONE";

function formatHHMM(dateObject) {
  return String(dateObject.getHours()).padStart(2, "0") + ":" + String(dateObject.getMinutes()).padStart(2, "0");
}

function formatDeviceTime(dateObject) {
  return dateObject.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function updateClockDisplay() {
  const clockElement = document.getElementById("clockDisplay");
  if (clockElement) {
    const now = new Date();
    const hours = String(now.getHours()).padStart(2, "0");
    const minutes = String(now.getMinutes()).padStart(2, "0");
    const seconds = String(now.getSeconds()).padStart(2, "0");
    clockElement.textContent = hours + ":" + minutes + ":" + seconds;
  }
}

function fetchChangelogData() {
  const contentElement = document.getElementById("changelogContent");
  if (!contentElement) return;
  fetch("https://raw.githubusercontent.com/multihubandredye-prog/W-C-A_GO/main/wca-resources/updates/changelog.txt")
    .then(function (response) {
      return response.text();
    })
    .then(function (text) {
      contentElement.textContent = text;
    })
    .catch(function () {
      contentElement.textContent = "Não foi possível carregar as novidades.";
    });
}

function isNewVersionAvailable(remoteTag, localTag) {
  const cleanRemote = remoteTag.replace(/^v/i, "").trim();
  const cleanLocal = localTag.replace(/^v/i, "").trim();
  if (!cleanRemote || cleanRemote === cleanLocal) {
    return false;
  }
  const remoteParts = cleanRemote.split(".").map(function (num) {
    return parseInt(num, 10) || 0;
  });
  const localParts = cleanLocal.split(".").map(function (num) {
    return parseInt(num, 10) || 0;
  });
  const maxLen = Math.max(remoteParts.length, localParts.length);
  for (let i = 0; i < maxLen; i++) {
    const r = remoteParts[i] || 0;
    const l = localParts[i] || 0;
    if (r > l) {
      return true;
    }
    if (r < l) {
      return false;
    }
  }
  return false;
}

function checkReleaseUpdate(versionBadge, updateCard, noUpdateCard) {
  fetch("https://api.github.com/repos/multihubandredye-prog/W-C-A_GO/releases/latest")
    .then(function (response) {
      return response.json();
    })
    .then(function (data) {
      const tag = (data && data.tag_name) ? String(data.tag_name).trim() : "";
      const releaseName = (data && data.name) ? String(data.name).trim() : "";
      const upperName = releaseName.toUpperCase();
      const isCoreRelease = upperName.includes("CORE");
      const isUiRelease = upperName.includes("UI");
      const hasNewVersion = isNewVersionAvailable(tag, lastUpdatedVersion);

      if (hasNewVersion && (isCoreRelease || isUiRelease)) {
        currentUpdateType = isCoreRelease ? "CORE" : "UI";
        if (versionBadge) {
          if (isCoreRelease) {
            versionBadge.textContent = "ATUALIZAÇÃO DA API • " + tag;
          } else {
            versionBadge.textContent = "ATUALIZAÇÃO DO TASKER • " + tag;
          }
        }
        fetchChangelogData();
        if (updateCard) {
          updateCard.style.display = "block";
        }
        if (noUpdateCard) {
          noUpdateCard.style.display = "none";
        }
      } else {
        currentUpdateType = "NONE";
        if (updateCard) {
          updateCard.style.display = "none";
        }
        if (noUpdateCard) {
          noUpdateCard.style.display = "block";
        }
      }
    })
    .catch(function () {
      currentUpdateType = "NONE";
      if (updateCard) {
        updateCard.style.display = "none";
      }
      if (noUpdateCard) {
        noUpdateCard.style.display = "block";
      }
    });
}

function initApp() {
  const timeInput = document.getElementById("scheduleTime");
  const confirmScheduleButton = document.getElementById("confirmScheduleButton");
  const updateNowButton = document.getElementById("updateNowButton");
  const quickButtons = document.querySelectorAll(".btn-quick");
  const versionBadge = document.getElementById("versionBadge");
  const updateCard = document.getElementById("updateCard");
  const noUpdateCard = document.getElementById("noUpdateCard");
  const errorMessage = document.getElementById("errorMessage");
  const expandChangelogButton = document.getElementById("expandChangelogButton");
  const changelogContent = document.getElementById("changelogContent");

  updateClockDisplay();
  setInterval(updateClockDisplay, 1000);

  const defaultTime = new Date(Date.now() + minRequiredMinutes * 60000);
  if (timeInput && !timeInput.value) {
    timeInput.value = formatHHMM(defaultTime);
  }

  checkReleaseUpdate(versionBadge, updateCard, noUpdateCard);

  if (confirmScheduleButton) {
    confirmScheduleButton.addEventListener("click", function () {
      if (!timeInput || !timeInput.value) {
        if (errorMessage) {
          errorMessage.textContent = "Por favor, selecione um horário válido.";
          errorMessage.style.display = "block";
        }
        return;
      }

      const timeParts = timeInput.value.split(":");
      const selectedHours = parseInt(timeParts[0], 10);
      const selectedMinutes = parseInt(timeParts[1], 10);
      const currentTime = new Date();
      const scheduledTime = new Date();
      scheduledTime.setHours(selectedHours, selectedMinutes, 0, 0);

      const minAllowedTime = new Date(currentTime.getTime() + minRequiredMinutes * 60000);

      if (scheduledTime.getTime() < minAllowedTime.getTime()) {
        if (errorMessage) {
          errorMessage.textContent = "Mínimo exigido: selecione um horário com pelo menos 5 minutos adiante.";
          errorMessage.style.display = "block";
        }
        return;
      }

      if (errorMessage) {
        errorMessage.style.display = "none";
      }

      alert(JSON.stringify({hora: formatDeviceTime(scheduledTime)},null,2));

      tk.setLocal("task","1");
      tk.setLocal("time_update",JSON.stringify({hora: formatDeviceTime(scheduledTime)},null,2));
      window.open("https://www.wca.com", "_blank");


    });
  }

  quickButtons.forEach(function (buttonElement) {
    buttonElement.addEventListener("click", function () {
      const minutesToAdd = parseInt(buttonElement.getAttribute("data-minutes"), 10);
      const targetTime = new Date(Date.now() + minutesToAdd * 60000);

      if (timeInput) {
        timeInput.value = formatHHMM(targetTime);
      }

      if (errorMessage) {
        errorMessage.style.display = "none";
      }

      ///alert(JSON.stringify({hora: formatDeviceTime(targetTime)},null,2));

      tk.setLocal("task","1");
      tk.setLocal("time_update",JSON.stringify({hora: formatDeviceTime(targetTime)},null,2));
      window.open("https://www.wca.com", "_blank");




    });
  });

  if (updateNowButton) {
    updateNowButton.addEventListener("click", function () {
      if (currentUpdateType === "CORE") {


        ///alert("atualização para core");

        tk.setLocal("task","2");
        window.open("https://www.wca.com", "_blank");



      } else if (currentUpdateType === "UI") {




        ///alert("atualização para ui");

        tk.setLocal("task","3");
        window.open("https://www.wca.com", "_blank");


      }
    });
  }

  if (expandChangelogButton && changelogContent) {
    expandChangelogButton.addEventListener("click", function () {
      if (changelogContent.classList.contains("expanded")) {
        changelogContent.classList.remove("expanded");
        expandChangelogButton.textContent = "Ler mais";
      } else {
        changelogContent.classList.add("expanded");
        expandChangelogButton.textContent = "Ler menos";
      }
    });
  }
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initApp);
} else {
  initApp();
}

