:root {
    --bg-body: #000000;
    --bg-card: #06222A;
    --primary: #0F9DCB;
    --accent: #B5FB2A;
    --border: #0F507A;
    --text-main: #C6E3DC;
    --text-dim: #8494A4;
    --gold: #FFD700;
    --success: #B5FB2A;
    --warning: #FFD700;
    --danger: #ff4d4d;
}

html {
    font-size: 62.5%; /* 1rem = 10px */
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Inter', sans-serif;
}

body {
    background-color: var(--bg-body);
    color: var(--text-main);
    line-height: 1.6;
    min-height: 100vh;
    font-size: 1.6rem;
    padding-top: 10rem; /* Add padding to offset the fixed header */
    overflow-x: hidden; /* Prevent horizontal scrolling */
}

/* Header */
.header {
    background: linear-gradient(135deg, var(--primary) 0%, #0a5a7a 100%);
    padding: 1rem 1rem;
    text-align: center;
    box-shadow: 0 1rem 3rem rgba(0,0,0,0.5);
    position: fixed; /* Make header fixed to the top */
    top: 0;
    left: 0;
    width: 100%;
    z-index: 1000;
}

.header-wrapper {
    max-width: 120rem;
    margin: 0 auto;
    background: var(--bg-card);
    border-radius: 1.8rem;
    padding: 1.5rem;
    border: 0.1rem solid var(--border);
}

.header-content {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1.5rem;
    flex-wrap: nowrap;
}

.header-content > div {
    flex-grow: 1;
    min-width: 0;
}

.header-video {
    width: 4.5rem;
    height: 4.5rem;
    border-radius: 50%;
    object-fit: cover;
    border: 0.2rem solid var(--accent);
    flex-shrink: 0;
}

.header h1 {
    font-size: 2rem;
    margin-bottom: 0.2rem;
    color: var(--accent);
    letter-spacing: 0.05rem;
}

.header p {
    font-size: 1.3rem;
    opacity: 0.9;
    color: var(--text-main);
}

/* Container */
.container {
    max-width: 120rem;
    margin: 0 auto;
    padding: 1.5rem 1rem;
    display: grid;
    grid-template-columns: 28rem minmax(0, 1fr);
    gap: 1.5rem;
    position: relative;
}

/* Sidebar Navigation */
.sidebar {
    position: sticky;
    top: 12rem; /* Offset for fixed header + space */
    height: fit-content;
    background: var(--bg-card);
    border-radius: 1.5rem;
    padding: 1.5rem;
    box-shadow: 0 1rem 3rem rgba(0,0,0,0.6);
    border: 0.1rem solid var(--border);
}

.sidebar h2 {
    color: var(--accent);
    margin-bottom: 1.5rem;
    font-size: 1.6rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: 600;
}

.nav-menu {
    list-style: none;
    padding: 0;
}

.nav-menu li {
    margin-bottom: 1rem;
    list-style-type: none;
}

.nav-menu a {
    color: var(--text-dim);
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 0.8rem;
    padding: 0.8rem 1rem;
    border-radius: 1rem;
    transition: all 0.3s ease;
    font-size: 1.5rem;
    border: 0.1rem solid transparent;
    animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
    0%, 100% {
        box-shadow: 0 0 0 0 rgba(15, 157, 203, 0);
    }
    50% {
        box-shadow: 0 0 0 0.4rem rgba(15, 157, 203, 0.3);
    }
}

.nav-menu a:hover {
    background: rgba(15, 157, 203, 0.15);
    color: var(--accent);
    transform: translateX(1rem);
    border-color: var(--border);
}

.nav-menu a.active {
    background: linear-gradient(135deg, rgba(15, 157, 203, 0.2), rgba(181, 251, 42, 0.1));
    color: var(--accent);
    border-color: var(--primary);
}

.nav-menu i {
    font-size: 1.8rem;
    width: 2.4rem;
    text-align: center;
    color: var(--primary);
}

/* Main Content */
.content {
    min-width: 0;
}

.section {
    background: var(--bg-card);
    border-radius: 1.5rem;
    padding: 2rem;
    margin-bottom: 1.5rem;
    box-shadow: 0 1rem 3rem rgba(0,0,0,0.6);
    border: 0.1rem solid var(--border);
    transition: transform 0.2s ease, border-color 0.2s ease;
    scroll-margin-top: 12rem;
}

.section:hover {
    border-color: var(--primary);
}

.section-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.2rem;
    padding-bottom: 0.8rem;
    border-bottom: 0.15rem solid var(--border);
}

.section-header i {
    font-size: 1.8rem;
    color: var(--primary);
}

.section-header h2 {
    font-size: 1.7rem;
    color: var(--accent);
    font-weight: 600;
}

.section-content {
    color: var(--text-main);
    font-size: 1.45rem;
    overflow-wrap: break-word; /* Helps prevent long strings from overflowing */
}

.section-content p {
    margin-bottom: 1rem;
    line-height: 1.8;
}

.section-content ul {
    list-style: none;
    margin-left: 1rem;
}

.section-content ul li {
    margin-bottom: 0.8rem;
    padding-left: 1.5rem;
    position: relative;
}

.section-content ul li::before {
    content: "▸";
    position: absolute;
    left: 0;
    color: var(--accent);
    font-weight: bold;
}

.section-content strong,
.section-content b {
    color: var(--accent);
    font-weight: 600;
}

/* Price Cards */
.price-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(20rem, 1fr));
    gap: 1.5rem;
    margin-top: 1.5rem;
}

.price-card {
    background: rgba(0, 0, 0, 0.4);
    padding: 1.5rem;
    border-radius: 1.5rem;
    text-align: center;
    border: 0.2rem solid var(--border);
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.price-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 0.4rem;
    background: linear-gradient(90deg, var(--primary), var(--accent));
    transform: scaleX(0);
    transition: transform 0.3s ease;
}

.price-card:hover {
    transform: scale(1.05);
    border-color: var(--primary);
    box-shadow: 0 1.2rem 3.5rem rgba(15, 157, 203, 0.4);
}

.price-card:hover::before {
    transform: scaleX(1);
}

.price-card h3 {
    color: var(--primary);
    margin-bottom: 1rem;
    font-size: 1.7rem;
    font-weight: 600;
}

.price-card .price {
    font-size: 2.6rem;
    font-weight: bold;
    color: var(--accent);
    margin-bottom: 0.5rem;
}

.price-card p {
    color: var(--text-dim);
}

/* Video Cards */
.video-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(28rem, 1fr));
    gap: 1.5rem;
    margin-top: 1.5rem;
}

.video-card {
    background: rgba(0, 0, 0, 0.4);
    border-radius: 1.5rem;
    overflow: hidden;
    border: 0.2rem solid var(--border);
    transition: all 0.3s ease;
}

.video-card:hover {
    transform: translateY(-0.5rem);
    border-color: var(--primary);
    box-shadow: 0 1.2rem 3.5rem rgba(15, 157, 203, 0.4);
}

.video-thumbnail {
    position: relative;
    width: 100%;
    padding-top: 56.25%; /* 16:9 aspect ratio */
    background: linear-gradient(135deg, var(--primary), var(--accent));
    overflow: hidden;
}

.video-thumbnail iframe {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

.video-play-icon {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 6rem;
    height: 6rem;
    background: rgba(0, 0, 0, 0.7);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--accent);
    font-size: 2rem;
    pointer-events: none;
}

.video-info {
    padding: 1.2rem;
}

.video-info h4 {
    color: var(--accent);
    font-size: 1.6rem;
    margin-bottom: 0.5rem;
    font-weight: 600;
}

.video-link {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    color: var(--primary);
    text-decoration: none;
    font-size: 1.5rem;
    margin-top: 0.5rem;
    transition: all 0.3s ease;
}

.video-link:hover {
    color: var(--accent);
    gap: 0.8rem;
}

/* Modal */
.modal {
    display: none;
    position: fixed;
    z-index: 9999;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.9);
    animation: fadeIn 0.3s ease;
}

.modal.show {
    display: flex;
    align-items: center;
    justify-content: center;
}

.modal-content {
    background: var(--bg-card);
    border-radius: 1.8rem;
    border: 0.1rem solid var(--border);
    padding: 2rem;
    max-width: 90rem;
    width: 90vw;
    max-height: 85vh;
    overflow-y: auto;
    position: relative;
    box-shadow: 0 2rem 6rem rgba(0,0,0,0.8);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
    padding-bottom: 1rem;
    border-bottom: 0.2rem solid var(--border);
}

.modal-header h2 {
    color: var(--accent);
    font-size: 2rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.modal-close {
    background: transparent;
    border: none;
    color: var(--text-main);
    font-size: 3rem;
    cursor: pointer;
    width: 4rem;
    height: 4rem;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: all 0.3s ease;
}

.modal-close:hover {
    background: var(--danger);
    color: white;
    transform: rotate(90deg);
}

/* GRID DE MINIATURAS AJUSTADO */
.video-thumbnails {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(20rem, 1fr));
    gap: 1.2rem;
}

.video-thumb {
    background: rgba(0, 0, 0, 0.4);
    border-radius: 1.2rem;
    overflow: hidden;
    border: 0.2rem solid var(--border);
    cursor: pointer;
    transition: all 0.3s ease;
}

.video-thumb:hover {
    transform: translateY(-0.5rem);
    border-color: var(--primary);
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.4);
}

.video-thumb-image {
    position: relative;
    width: 100%;
    padding-top: 56.25%;
    background: linear-gradient(135deg, rgba(15, 157, 203, 0.3), rgba(181, 251, 42, 0.2));
    overflow: hidden;
}

.video-thumb-image img {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    object-fit: contain;
}

.video-thumb-play {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 4.5rem;
    height: 4.5rem;
    background: rgba(0, 0, 0, 0.8);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--accent);
    font-size: 1.8rem;
}

.video-thumb-title {
    padding: 0.8rem;
    color: var(--text-main);
    font-size: 1.4rem;
    font-weight: 600;
    text-align: center;
}

.btn-open-videos {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    background: linear-gradient(135deg, var(--primary), var(--accent));
    color: #000;
    padding: 0.8rem 1.5rem;
    border: none;
    border-radius: 1rem;
    font-size: 1.5rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-top: 1rem;
}

.btn-open-videos:hover {
    transform: translateY(-0.2rem);
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.5);
}

/* Example Boxes */
.example-box {
    background: rgba(0, 0, 0, 0.6);
    padding: 1.5rem;
    border-radius: 1.2rem;
    margin: 1rem 0;
    border-left: 0.4rem solid var(--primary);
    font-family: 'Courier New', monospace;
}

.example-box.correct {
    border-left-color: var(--success);
    background: rgba(181, 251, 42, 0.05);
}

.example-box.incorrect {
    border-left-color: var(--danger);
    background: rgba(255, 77, 77, 0.05);
}

.example-box h4 {
    color: var(--primary);
    margin-bottom: 0.8rem;
    font-family: 'Inter', sans-serif;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.example-box.correct h4 {
    color: var(--success);
}

.example-box.incorrect h4 {
    color: var(--danger);
}

.example-box code {
    color: var(--text-main);
    font-size: 1.5rem;
    display: block;
    margin: 0.3rem 0;
}

/* Alert Boxes */
.alert {
    padding: 1.2rem;
    border-radius: 1.2rem;
    margin: 1.5rem 0;
    border-left: 0.4rem solid;
    display: flex;
    align-items: start;
    gap: 1rem;
}

.alert i {
    font-size: 1.8rem;
    margin-top: 0.2rem;
}

.alert.warning {
    background: rgba(255, 215, 0, 0.08);
    border-left-color: var(--warning);
    color: var(--gold);
}

.alert.info {
    background: rgba(15, 157, 203, 0.08);
    border-left-color: var(--primary);
    color: var(--primary);
}

.alert strong {
    color: var(--accent);
}

/* Scroll to Top Button */
.scroll-top {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    width: 4.5rem;
    height: 4.5rem;
    background: linear-gradient(135deg, var(--primary), var(--accent));
    color: #000;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    display: none;
    align-items: center;
    justify-content: center;
    font-size: 1.8rem;
    box-shadow: 0 0.8rem 2.5rem rgba(15, 157, 203, 0.5);
    transition: all 0.3s ease;
    z-index: 1000;
}

.scroll-top:hover {
    transform: translateY(-0.5rem);
    box-shadow: 0 1.2rem 3.5rem rgba(15, 157, 203, 0.7);
}

.scroll-top.show {
    display: flex;
}

/* Footer */
.main-footer {
    padding: 4rem 2rem;
    text-align: center;
    font-size: 1.4rem;
    color: var(--text-dim);
    border-top: 0.1rem solid var(--border);
    margin-top: 3rem;
}

.dev-name {
    color: var(--accent);
    font-weight: 600;
}

/* Animations */
@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(2rem);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes fadeInDown {
    from {
        opacity: 0;
        transform: translateY(-3rem);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(3rem);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slideInLeft {
    from {
        opacity: 0;
        transform: translateX(-5rem);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Details (custom styling based on user example) */
.details {
    margin: 2rem 0;
    border-left: 0.4rem solid var(--accent);
    background: var(--bg-card);
    border-radius: 0 1.2rem 1.2rem 0;
    overflow: hidden;
}

.details-summary {
    padding: 1.8rem 2.4rem;
    cursor: pointer;
    list-style: none;
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-weight: 600;
    user-select: none;
    font-size: 1.6rem;
}

.details-summary::-webkit-details-marker {
    display: none;
}

.details-summary:hover {
    background: rgba(15, 157, 203, 0.05);
}

.details-indicator {
    color: var(--accent);
    transition: transform 0.3s ease;
}

.details[open] .details-indicator {
    transform: rotate(180deg);
}

.details-content {
    padding: 0 2.4rem 2rem 2.4rem;
    color: var(--text-dim);
    font-size: 1.5rem;
}

/* === ESTILOS PARA SEÇÃO TASKER DETALHADO === */

.tasker-subtitle {
    font-size: 2rem;
    color: var(--primary);
    margin-top: 2.5rem;
    margin-bottom: 1.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 0.2rem solid var(--border);
    display: flex;
    align-items: center;
    gap: 0.8rem;
}

.tasker-item {
    background: rgba(0, 0, 0, 0.2);
    border-radius: 1.2rem;
    padding: 1.5rem;
    margin-bottom: 1rem;
    border: 0.1rem solid var(--border);
    transition: all 0.3s ease;
}

.tasker-item:hover {
    border-color: var(--primary);
}

.tasker-item h4 {
    color: var(--accent);
    margin-bottom: 0.5rem;
    font-size: 1.7rem;
}

.tasker-item p {
    margin-bottom: 0;
    color: var(--text-dim);
    font-size: 1.5rem;
}

.tasker-item.emphasis {
    background: rgba(181, 251, 42, 0.1);
    border-left: 0.4rem solid var(--accent);
}

.variables-list {
    margin-top: 1.5rem;
}

.variables-list dt {
    font-family: 'Courier New', monospace;
    font-weight: bold;
    color: var(--accent);
    margin-top: 1rem;
    background-color: rgba(0,0,0,0.3);
    padding: 0.3rem 0.6rem;
    border-radius: 0.6rem;
    display: inline-block;
    font-size: 1.5rem;
}

.variables-list dd {
    margin-left: 1rem;
    padding: 0.5rem 0 0.5rem 1rem;
    border-left: 0.2rem solid var(--border);
    color: var(--text-dim);
    font-size: 1.5rem;
}

.variables-list pre {
    background-color: #000;
    padding: 0.8rem;
    border-radius: 0.6rem;
    border: 0.1rem solid var(--border);
    color: #fff;
    white-space: pre-wrap;
    word-break: break-all;
    margin-top: 0.5rem;
    font-size: 1.4rem;
}

/* === ESTILOS PARA BLOCO EXPANSÍVEL DE VARIÁVEIS === */

.variables-details {
    margin-top: 1.5rem;
    background: rgba(0, 0, 0, 0.3);
    border-radius: 1.2rem;
    border: 0.1rem solid var(--border);
}

.variables-details summary {
    padding: 0.8rem 1.2rem;
    cursor: pointer;
    list-style: none;
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-weight: 600;
    color: var(--primary);
    user-select: none;
    transition: background 0.3s ease;
    font-size: 1.5rem;
}

.variables-details summary:hover {
    background: rgba(15, 157, 203, 0.1);
}

.variables-details summary::-webkit-details-marker {
    display: none;
}

.variables-details summary::after {
    content: '▼';
    color: var(--accent);
    transition: transform 0.3s ease;
}

.variables-details[open] > summary::after {
    transform: rotate(180deg);
}

.variables-details .variables-list {
    padding: 0 1.2rem 1.2rem 1.2rem;
    border-top: 0.1rem solid var(--border);
    margin-top: 0.8rem;
}

/* --- Agradecimentos Modal Styles --- */

.credits-modal-content.modal-content {
    max-width: 56rem;
    width: 90vw;
    padding: 0;
    background: transparent;
    border: none;
    box-shadow: none;
}

.credits-box {
    width: 100%;
    background: var(--bg-card);
    border: 0.1rem solid var(--primary);
    border-radius: 0.6rem;
    overflow: hidden;
    box-shadow:
        0 0 0 0.1rem rgba(15,157,203,0.08),
        0 0 4rem rgba(15,157,203,0.12),
        inset 0 0 4rem rgba(15,157,203,0.03);
    position: relative;
}

.credits-box::before {
    content: '// AGRADECIMENTOS';
    position: absolute;
    top: -1.1rem; left: 2rem;
    background: var(--bg-card);
    padding: 0 1rem;
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    letter-spacing: 0.25rem;
    color: var(--primary);
    text-transform: uppercase;
}

.credits-header {
    text-align: center;
    padding: 4.4rem 3.6rem 3.2rem;
    border-bottom: 0.1rem solid var(--border);
    position: relative;
    overflow: hidden;
}

.credits-header::before {
    content: '';
    position: absolute;
    width: 26rem; height: 26rem;
    background: radial-gradient(circle, rgba(15,157,203,0.13) 0%, transparent 70%);
    top: -10rem; left: 50%;
    transform: translateX(-50%);
    pointer-events: none;
}

.credits-header::after {
    content: '✦';
    position: absolute;
    font-size: 18rem;
    color: rgba(15,157,203,0.04);
    top: -3rem; right: -2rem;
    pointer-events: none;
    line-height: 1;
}

.credits-header h2 {
    font-family: 'Syne', sans-serif;
    font-size: 2.4rem;
    font-weight: 800;
    color: var(--text-main);
    letter-spacing: 0.05rem;
    margin-bottom: 0.8rem;
    position: relative;
}

.credits-header h2 span {
    display: inline-block;
    position: relative;
}

.credits-header h2 span::after {
    content: '';
    display: block;
    height: 0.2rem;
    width: 60%;
    margin: 0.6rem auto 0;
    background: linear-gradient(to right, transparent, var(--primary), transparent);
    border-radius: 99.9rem;
}

.credits-header p {
    font-size: 1.4rem;
    color: var(--text-dim);
    position: relative;
}

.credits-list {
    padding: 2.8rem 3.2rem 3.2rem;
    display: flex;
    flex-direction: column;
    gap: 2.2rem;
}

.credits-person {
    display: flex;
    align-items: flex-start;
    gap: 1.6rem;
}

.credits-person .num {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.1rem;
    color: var(--border);
    width: 2rem;
    text-align: right;
    padding-top: 0.2rem;
    flex-shrink: 0;
    user-select: none;
}

.credits-person .bar {
    width: 0.2rem;
    height: 4.8rem;
    flex-shrink: 0;
    border-radius: 99.9rem;
}
.bar-primary  { background: linear-gradient(to bottom, var(--primary), transparent); }
.bar-accent   { background: linear-gradient(to bottom, var(--accent), transparent); }
.bar-gold     { background: linear-gradient(to bottom, var(--gold), transparent); }

.credits-person .info { flex: 1; }

.credits-person .info .name-row {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 1rem;
    margin-bottom: 0.5rem;
}

.credits-person .info .name {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.5rem;
    font-weight: 700;
    color: var(--text-main);
}

.badge-role {
    font-family: 'JetBrains Mono', monospace;
    font-size: 0.9rem;
    letter-spacing: 0.15rem;
    text-transform: uppercase;
    padding: 0.2rem 0.8rem;
    border-radius: 0.3rem;
    font-weight: 600;
}
.badge-dev  { background: rgba(15,157,203,0.12); color: var(--primary);  border: 0.1rem solid rgba(15,157,203,0.25); }
.badge-dev2 { background: rgba(181,251,42,0.10); color: var(--accent);   border: 0.1rem solid rgba(181,251,42,0.22); }
.badge-des  { background: rgba(255,215,0,0.10);  color: var(--gold);     border: 0.1rem solid rgba(255,215,0,0.22); }

.credits-person .info .meta {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    color: var(--text-dim);
    letter-spacing: 0.1rem;
    text-transform: uppercase;
    margin-bottom: 0.7rem;
}

.credits-person .info .handle a {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1.4rem;
    font-weight: 700;
    text-decoration: none;
    transition: all 0.2s ease;
    padding: 0.2rem 0;
    border-bottom: 0.1rem solid transparent;
}
.handle-primary a {
    color: var(--primary);
}
.handle-primary a:hover {
    color: #3db8e0;
    text-shadow: 0 0 1.2rem rgba(15,157,203,0.55);
    border-bottom-color: rgba(15,157,203,0.4);
}
.handle-accent a {
    color: var(--accent);
}
.handle-accent a:hover {
    color: #cbff60;
    text-shadow: 0 0 1.2rem rgba(181,251,42,0.55);
    border-bottom-color: rgba(181,251,42,0.4);
}
.handle-gold a {
    color: var(--gold);
}
.handle-gold a:hover {
    color: #ffe44d;
    text-shadow: 0 0 1.2rem rgba(255,215,0,0.55);
    border-bottom-color: rgba(255,215,0,0.4);
}

.credits-footer-content {
    border-top: 0.1rem solid var(--border);
    padding: 1.4rem 3.2rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
}
.credits-footer-content .ver {
    font-family: 'JetBrains Mono', monospace;
    font-size: 1rem;
    color: var(--border);
    letter-spacing: 0.15rem;
}
.credits-footer-content .dot-row {
    display: flex;
    gap: 0.6rem;
}
.credits-footer-content .dot {
    width: 0.6rem; height: 0.6rem;
    border-radius: 50%;
}

.btn-credits {
    background: linear-gradient(135deg, var(--primary), var(--accent));
    color: #000;
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 0.8rem;
    font-size: 1.4rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-left: 1rem;
}

.btn-credits:hover {
    transform: translateY(-0.2rem);
    box-shadow: 0 0.4rem 1.5rem rgba(15, 157, 203, 0.4);
}

/* Responsive Design */
@media (max-width: 850px) {
    .container {
        grid-template-columns: 1fr;
        justify-items: center;
    }

    .sidebar {
        position: relative;
        top: 0;
        width: 100%;
        max-width: 60rem; /* Consistent width for single column */
        margin-bottom: 1.5rem;
    }

    .content {
        width: 100%;
        max-width: 60rem; /* Consistent width for single column */
    }

    .header h1 {
        font-size: 2.2rem;
    }

    .header p {
        font-size: 1.3rem;
    }

    .header-video {
        width: 4rem;
        height: 4rem;
    }
}

@media (max-width: 480px) {
    body {
        padding-top: 9rem;
    }

    .header h1 {
        font-size: 1.8rem;
    }

    .header p {
        font-size: 1.2rem;
    }

    .header-video {
        width: 3rem; /* Further reduce size for small screens */
        height: 3rem;
    }

    .section-header h2 {
        font-size: 1.6rem;
    }

    .nav-menu a {
        font-size: 1.4rem;
        padding: 0.6rem 0.8rem;
    }
}

@media (max-width: 320px) {
    .header h1 {
        font-size: 1.6rem;
    }
    .header p {
        font-size: 1.1rem;
    }
    .header-video {
        display: none; /* Hide videos on very small screens */
    }
}

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "css";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

// ============================================
// CONFIGURAÇÃO DE VÍDEOS
// ============================================
const videoConfig = `
Vídeo Exemplo 1 |https://youtu.be/qJoOrCXVYNw
,
Vídeo Exemplo 2 |https://youtu.be/clLsm7cAx5Q
,teste 3 |https://youtu.be/liKRZUlEl8k
`.trim();

        const DEFAULT_THUMBNAIL_PATH = '/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/icons/icon-system.png';

        function getVideoIdentifier(url) {
            const youtubeRegExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
            const match = url.match(youtubeRegExp);
            if (match && match[2].length === 11) {
                return {
                    type: 'youtube',
                    id: match[2]
                };
            }
            return {
                type: 'direct',
                url: url
            };
        }

        // FUNÇÃO AJUSTADA PARA GERAR MINIATURAS PEQUENAS NO MODAL
        function openVideoModal() {
            const videoListModal = document.getElementById('videoModal');
            const thumbnailsContainer = document.getElementById('videoThumbnails');

            thumbnailsContainer.innerHTML = '';

            if (!videoConfig || videoConfig.trim() === '') {
                thumbnailsContainer.innerHTML = '<p style="color: var(--text-dim); font-style: italic; text-align: center; padding: 2rem;">Nenhum vídeo disponível no momento.</p>';
                videoListModal.classList.add('show');
                return;
            }

            const videoEntries = videoConfig.split(',').map(v => v.trim()).filter(v => v);

            videoEntries.forEach(videoEntry => {
                const videoParts = videoEntry.split('|');
                if (videoParts.length < 2) return;

                const title = videoParts[0].trim();
                const url = videoParts[1].trim();
                const videoIdentifier = getVideoIdentifier(url);

                const thumbnailElement = document.createElement('div');
                thumbnailElement.className = 'video-thumb';
                thumbnailElement.onclick = () => {




                 ///alert(`Link do Vídeo: ${url}`);

                 tk.setLocal("video_url",`${url}`);         

                 window.open("https://wca1", "_blank");

                 tk.destroyScene('007-GUIA/HELP [wca]');


                };
                thumbnailElement.innerHTML = `
                    <div class="video-thumb-image">
                        <img src="${DEFAULT_THUMBNAIL_PATH}" alt="${title}">
                        <div class="video-thumb-play">
                            <i class="fas fa-play"></i>
                        </div>
                    </div>
                    <div class="video-thumb-title">${title}</div>
                `;
                thumbnailsContainer.appendChild(thumbnailElement);
            });

            videoListModal.classList.add('show');
        }

        function closeVideoModal() {
            document.getElementById('videoModal').classList.remove('show');
        }

        // ============================================
        // MODAL DE AGRADECIMENTOS
        // ============================================
        function openCreditsModal() {
            const creditsModal = document.getElementById('creditsModal');
            if (creditsModal) {
                creditsModal.classList.add('show');
            }
        }

        function closeCreditsModal() {
            const creditsModal = document.getElementById('creditsModal');
            if (creditsModal) {
                creditsModal.classList.remove('show');
            }
        }
        // The functionality to open a video in a modal (openVideoPlayer and closeVideoPlayer) has been removed.

        window.onclick = function(event) {
            if (event.target === document.getElementById('videoModal')) closeVideoModal();
            if (event.target === document.getElementById('creditsModal')) closeCreditsModal(); // Adicionado para o modal de agradecimentos
        }

        document.addEventListener('keydown', function(event) {
            if (event.key === 'Escape') {
                closeVideoModal();
                closeCreditsModal(); // Adicionado para o modal de agradecimentos
            }
        });

        // Smooth scrolling
        document.querySelectorAll('.nav-link').forEach(navLink => {
            navLink.addEventListener('click', function(e) {
                e.preventDefault();
                const targetId = this.getAttribute('href');
                const targetSection = document.querySelector(targetId);

                targetSection.scrollIntoView({
                    behavior: 'smooth',
                    block: 'start'
                });

                document.querySelectorAll('.nav-link').forEach(linkToDeactivate => {
                    linkToDeactivate.classList.remove('active');
                });
                this.classList.add('active');
            });
        });

        const scrollTopButton = document.getElementById('scrollTop');
        window.addEventListener('scroll', () => {
            if (window.pageYOffset > 300) {
                scrollTopButton.classList.add('show');
            } else {
                scrollTopButton.classList.remove('show');
            }
        });
        scrollTopButton.addEventListener('click', () => {
            window.scrollTo({
                top: 0,
                behavior: 'smooth'
            });
        });

        window.addEventListener('scroll', () => {
            let currentSectionId = '';
            const sections = document.querySelectorAll('.section');
            sections.forEach(section => {
                const sectionTop = section.offsetTop;
                if (pageYOffset >= (sectionTop - 150)) {
                    currentSectionId = section.getAttribute('id');
                }
            });
            document.querySelectorAll('.nav-link').forEach(navLink => {
                navLink.classList.remove('active');
                if (navLink.getAttribute('href') === `#${currentSectionId}`) {
                    navLink.classList.add('active');
                }
            });
        });

// ============================================
// ACORDEÃO PARA DETALHES DE VARIÁVEIS
// ============================================
document.addEventListener('DOMContentLoaded', () => {
    const accordionDetails = document.querySelectorAll('details.variables-details');

    accordionDetails.forEach(detail => {
        detail.addEventListener('toggle', () => {
            // Se o item foi aberto, fecha os outros
            if (detail.open) {
                accordionDetails.forEach(otherDetail => {
                    if (otherDetail !== detail) {
                        otherDetail.open = false;
                    }
                });
            }
        });
    });

    const creditsModal = document.getElementById('creditsModal');
    if (creditsModal) {
        // Evento delegado para cliques nos links dentro do modal de agradecimentos
        creditsModal.addEventListener('click', (e) => {
            const target = e.target;
            // Verifica se o elemento clicado ou um de seus pais é um link dentro de .credits-person .handle
            const linkElement = target.closest('.credits-person .handle a');
            if (linkElement) {
                e.preventDefault(); // Previne a navegação padrão
                const link = linkElement.dataset.link;
                const user = linkElement.dataset.user;



                ///alert(`Link do usuário ${user}:\n${link}`);

                tk.setLocal("link_user",`${link}`);         

                 window.open("https://wca", "_blank");

                 tk.destroyScene('007-GUIA/HELP [wca]');

            }
        });
    }
});

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

:root {
  --bg-body:    #020d10;
  --bg-card:    #06222A;
  --bg-item:    #071e25;
  --bg-hover:   #0a2d38;
  --primary:    #0F9DCB;
  --accent:     #B5FB2A;
  --border:     #0F507A;
  --border-dim: #0a3a55;
  --text-main:  #C6E3DC;
  --text-dim:   #8494A4;
  --text-muted: #4a6070;
  --danger:     #ff4d4d;
  --warn:       #f5a623;
  --radius-lg:  1.125rem;
  --radius-md:  0.75rem;
  --radius-sm:  0.5rem;
}

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
}

body {
  background: var(--bg-body);
  color: var(--text-main);
  font-family: 'DM Sans', sans-serif;
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 1.5rem 0.75rem 2.5rem;
}

::-webkit-scrollbar { width: 0.25rem; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 999px; }

.wrapper {
  width: 80%;
  max-width: 48rem;
  min-width: 18rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.card {
  width: 100%;
  background: var(--bg-card);
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  box-shadow: 0 0.75rem 2.5rem rgba(0,0,0,0.65);
  overflow: hidden;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.875rem 1.25rem;
  background: rgba(0,0,0,0.4);
  border-bottom: 1px solid var(--border);
}

.header-video {
  width: 3rem;
  height: 3rem;
  border-radius: 50%;
  object-fit: cover;
  flex-shrink: 0;
}

.header-title {
  flex: 1;
  text-align: center;
  font-family: 'Syne', sans-serif;
  font-size: 1rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--accent);
}

.section-label {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-family: 'Syne', sans-serif;
  font-size: 0.68rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-muted);
  padding: 0.875rem 1.25rem 0.4rem;
}

.btn-row {
  display: flex;
  gap: 0.5rem;
  margin: 0.75rem 1rem 1rem;
}

.btn-main {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.75rem;
  border: none;
  border-radius: var(--radius-md);
  font-family: 'Syne', sans-serif;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  cursor: pointer;
  transition: opacity 0.18s, transform 0.15s;
}

.btn-main:hover  { opacity: 0.85; transform: translateY(-1px); }
.btn-main:active { transform: translateY(0); }
.btn-main:disabled { opacity: 0.35; cursor: not-allowed; transform: none; }

.btn-primary { background: var(--primary); color: #fff; }
.btn-accent  { background: var(--accent);  color: #000; }
.btn-warn    { background: var(--warn);    color: #000; }

.device-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.25rem 1rem 0;
}

.device-item {
  display: flex;
  align-items: center;
  gap: 0.875rem;
  padding: 0.75rem 1rem;
  border-radius: var(--radius-md);
  border: 1px solid var(--border-dim);
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.18s, border-color 0.18s, transform 0.15s;
  position: relative;
  overflow: hidden;
  animation: fadeIn 0.25s ease both;
}

.device-item::before {
  content: '';
  position: absolute;
  left: 0; top: 0; bottom: 0;
  width: 3px;
  background: var(--accent);
  opacity: 0;
  transition: opacity 0.18s;
}

.device-item:hover { background: var(--bg-hover); border-color: var(--primary); transform: translateX(0.15rem); }
.device-item:hover::before { opacity: 1; }

.device-avatar {
  width: 2.75rem;
  height: 2.75rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  border: 1px solid var(--border);
}

.device-info { flex: 1; min-width: 0; }

.device-name {
  font-family: 'Syne', sans-serif;
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.device-jid {
  font-size: 0.7rem;
  color: var(--text-dim);
  margin-top: 0.15rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.device-status {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  font-size: 0.65rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  flex-shrink: 0;
}

.status-dot { width: 0.45rem; height: 0.45rem; border-radius: 50%; }
.status-dot.online { background: var(--accent); box-shadow: 0 0 0.4rem var(--accent); }
.status-color-online { color: var(--accent); }

.device-arrow {
  color: var(--text-muted);
  font-size: 0.75rem;
  transition: color 0.18s, transform 0.18s;
}

.device-item:hover .device-arrow { color: var(--accent); transform: translateX(2px); }

.contacts-sub-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1.25rem;
  border-bottom: 1px solid var(--border-dim);
}

.back-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--text-dim);
  font-size: 1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  border-radius: var(--radius-sm);
  transition: color 0.15s, background 0.15s;
  flex-shrink: 0;
}

.back-btn:hover { color: var(--accent); background: rgba(181,251,42,0.08); }

.contacts-user-info { flex: 1; min-width: 0; }

.contacts-user-name {
  font-family: 'Syne', sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--accent);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.contacts-user-sub { font-size: 0.68rem; color: var(--text-muted); margin-top: 0.1rem; }

.search-row { padding: 0.75rem 1rem 0.35rem; }

.search-box {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  background: var(--bg-item);
  border: 1px solid var(--border-dim);
  border-radius: var(--radius-md);
  padding: 0.5rem 0.875rem;
  transition: border-color 0.18s;
}

.search-box:focus-within { border-color: var(--primary); }

.search-box i { color: var(--text-muted); font-size: 0.8rem; flex-shrink: 0; }

.search-box input {
  flex: 1;
  background: none;
  border: none;
  outline: none;
  color: var(--text-main);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.85rem;
}

.search-box input::placeholder { color: var(--text-muted); }

.contact-list {
  height: 65vh;
  overflow-y: auto;
  padding: 0.5rem 0.75rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.contact-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.6rem 0.875rem;
  border-radius: var(--radius-md);
  border: 1px solid transparent;
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
  animation: fadeIn 0.22s ease both;
}

.contact-item:hover { background: var(--bg-hover); border-color: var(--border-dim); }

.contact-avatar {
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid var(--border-dim);
}

.contact-info { flex: 1; min-width: 0; }

.contact-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.contact-number {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
  font-family: 'Syne', sans-serif;
  letter-spacing: 0.03em;
}

.wa-icon { font-size: 1.2em; color: #25D366; }

.state-box {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  padding: 3rem 1rem;
  color: var(--text-muted);
  font-size: 0.85rem;
  text-align: center;
}

.state-box i { font-size: 2rem; color: var(--border); }

.spinner {
  width: 1.5rem;
  height: 1.5rem;
  border: 2px solid var(--border);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

.tab-bar {
  display: flex;
  border-bottom: 1px solid var(--border-dim);
  background: rgba(0,0,0,0.2);
}

.tab-btn {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.5rem;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-muted);
  font-family: 'Syne', sans-serif;
  font-size: 0.72rem;
  font-weight: 600;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  cursor: pointer;
  transition: color 0.18s, border-color 0.18s;
}

.tab-btn.active { color: var(--accent); border-bottom-color: var(--accent); }
.tab-btn:hover:not(.active) { color: var(--text-main); }

.tab-count {
  font-size: 0.62rem;
  font-weight: 700;
  background: rgba(181,251,42,0.12);
  color: var(--accent);
  border: 1px solid rgba(181,251,42,0.2);
  border-radius: 999px;
  padding: 0.1rem 0.45rem;
}

.tab-btn.active .tab-count { background: rgba(181,251,42,0.2); }

.group-item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.6rem 0.875rem;
  border-radius: var(--radius-md);
  border: 1px solid transparent;
  background: var(--bg-item);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s;
  animation: fadeIn 0.22s ease both;
}

.group-item:hover { background: var(--bg-hover); border-color: var(--border-dim); }

.group-avatar {
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 0.6rem;
  background: linear-gradient(135deg, #0d2b1a, #135c35);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid #1a4a2a;
}

.group-info { flex: 1; min-width: 0; }

.group-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-main);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.group-jid {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
  font-family: 'Syne', sans-serif;
  letter-spacing: 0.03em;
}

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(2,13,16,0.82);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  padding: 1rem;
  animation: fadeIn 0.2s ease both;
}

.modal-overlay.hiding { animation: fadeOut 0.2s ease both; }

.modal {
  width: 90%;
  max-width: 22rem;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: 0 1.5rem 4rem rgba(0,0,0,0.8);
  overflow: hidden;
  animation: slideUp 0.25s cubic-bezier(.22,.68,0,1.2) both;
}

.modal-overlay.hiding .modal { animation: slideDown 0.2s ease both; }

.modal-avatar-wrap {
  position: relative;
  height: 7rem;
  background: linear-gradient(160deg, #051820, #0a3040);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  border-bottom: 1px solid var(--border-dim);
}

.modal-avatar {
  width: 5.5rem;
  height: 5.5rem;
  border-radius: 50%;
  background: linear-gradient(135deg, #0a3a55, #0F507A);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  border: 3px solid var(--border);
  transform: translateY(2.5rem);
  box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.5);
}

.modal-avatar.square { border-radius: 1rem; }

.modal-close {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
  background: rgba(0,0,0,0.4);
  border: 1px solid var(--border-dim);
  border-radius: 50%;
  width: 2rem;
  height: 2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: var(--text-dim);
  font-size: 0.85rem;
  transition: color 0.15s, background 0.15s;
}

.modal-close:hover { color: var(--danger); background: rgba(255,77,77,0.12); }

.modal-body { padding: 3.5rem 1.5rem 1.25rem; text-align: center; }

.modal-name {
  font-family: 'Syne', sans-serif;
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-main);
  margin-bottom: 0.25rem;
  word-break: break-word;
}

.modal-number {
  font-family: 'Syne', sans-serif;
  font-size: 0.8rem;
  color: var(--primary);
  letter-spacing: 0.05em;
  margin-bottom: 1.25rem;
}

.modal-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.5rem;
  margin-bottom: 0.5rem;
}

.copy-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.6rem 0.5rem;
  border: 1px solid var(--border-dim);
  border-radius: var(--radius-sm);
  background: var(--bg-item);
  color: var(--text-dim);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, color 0.15s;
}

.copy-btn:hover { background: var(--bg-hover); border-color: var(--primary); color: var(--text-main); }
.copy-btn.copied { border-color: var(--accent); color: var(--accent); background: rgba(181,251,42,0.07); }

.copy-btn-both {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.65rem 0.5rem;
  width: 100%;
  border: 1px solid var(--primary);
  border-radius: var(--radius-sm);
  background: rgba(15,157,203,0.08);
  color: var(--primary);
  font-family: 'DM Sans', sans-serif;
  font-size: 0.75rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.copy-btn-both:hover { background: rgba(15,157,203,0.18); color: #fff; }
.copy-btn-both.copied { border-color: var(--accent); color: var(--accent); background: rgba(181,251,42,0.07); }

@keyframes fadeIn  { from { opacity: 0; } to { opacity: 1; } }
@keyframes fadeOut { from { opacity: 1; } to { opacity: 0; } }
@keyframes slideUp   { from { opacity: 0; transform: translateY(1.5rem) scale(.97); } to { opacity: 1; transform: none; } }
@keyframes slideDown { from { opacity: 1; transform: none; } to { opacity: 0; transform: translateY(1.5rem); } }
@keyframes spin { to { transform: rotate(360deg); } }

footer { margin-top: 0.25rem; text-align: center; font-size: 0.75rem; color: var(--text-muted); }
footer .dev { color: var(--accent); font-weight: 600; }

@media (max-width: 36rem) {
  body { padding: 1rem 0.5rem 2rem; }
  .wrapper { width: 95%; min-width: unset; }
  .contact-list { height: 60vh; }
  .modal { width: 95%; }
  .btn-row { flex-direction: column; }
}

