const API_HOST = 'http://127.0.0.1:3000';
const API_AUTH = 'dXNlcjE6cGFzczE=';

const INVALID_JID_PREFIXES = ['0@', 'status@'];
function isValidContact(jid) {
  if (!jid) return false;
  if (!jid.endsWith('@s.whatsapp.net') && !jid.endsWith('@c.us')) return false;
  for (const p of INVALID_JID_PREFIXES) { if (jid.startsWith(p)) return false; }
  if (!/^\d{8,}$/.test(jid.split('@')[0])) return false;
  return true;
}

let allContacts   = [];
let allGroups     = [];
let currentDevice = null;
let activeTab     = 'contacts';

const $ = id => document.getElementById(id);
const WA_ICON = '<i class="fa-brands fa-whatsapp wa-icon"></i>';

function buildHeaders(deviceId) {
  return {
    'Accept'       : 'application/json',
    'Authorization': 'Basic ' + API_AUTH,
    'X-Device-Id'  : deviceId || ''
  };
}

function escHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function fmtJid(jid) { return jid.replace(/@s\.whatsapp\.net|@c\.us/g, ''); }

function stagger(el, i) { el.style.animationDelay = (i * 18) + 'ms'; }

// normalização para busca com fontes unicode
function normalizeSearch(str) {
  if (!str) return '';
  let result = '';
  for (const ch of str) { result += FONT_MAP[ch] || ch; }
  return result.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\w\s\d]/g,' ').replace(/\s+/g,' ').trim().toLowerCase();
}

const FONT_MAP = (() => {
  const map = {};
  const mathRanges = [
    [0x1D400,0x1D41A],[0x1D434,0x1D44E],[0x1D468,0x1D482],
    [0x1D49C,0x1D4B6],[0x1D504,0x1D51E],[0x1D538,0x1D552],
    [0x1D5A0,0x1D5BA],[0x1D5D4,0x1D5EE],[0x1D608,0x1D622],
    [0x1D63C,0x1D656],[0x1D670,0x1D68A],
  ];
  mathRanges.forEach(([bu,bl]) => {
    for (let i=0;i<26;i++) {
      try{map[String.fromCodePoint(bu+i)]=String.fromCharCode(97+i);}catch(_){}
      try{map[String.fromCodePoint(bl+i)]=String.fromCharCode(97+i);}catch(_){}
    }
  });
  [0x1D7CE,0x1D7D8,0x1D7E2,0x1D7EC,0x1D7F6].forEach(base=>{
    for(let i=0;i<10;i++) try{map[String.fromCodePoint(base+i)]=String(i);}catch(_){}
  });
  for(let i=0;i<26;i++){
    map[String.fromCodePoint(0x24B6+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x24D0+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x249C+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0xFF21+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0xFF41+i)]=String.fromCharCode(97+i);
    map[String.fromCodePoint(0x1F1E6+i)]=String.fromCharCode(97+i);
  }
  for(let i=0;i<10;i++) map[String.fromCodePoint(0xFF10+i)]=String(i);
  return map;
})();

async function fetchDevices() {
  const btn = $('btn-load-devices');
  btn.disabled = true;
  btn.innerHTML = '<span class="spinner" style="width:.9rem;height:.9rem;border-width:2px"></span> Carregando…';
  $('device-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Conectando à API…</span></div>`;

  try {
    const res = await fetch(`${API_HOST}/devices`, {
      headers: buildHeaders('00000000-0000-0000-0000-000000000000')
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data    = await res.json();
    const devices = (data.results || []).filter(d => d.state === 'logged_in');
    renderDevices(devices);
  } catch(e) {
    $('device-list').innerHTML = `
      <div class="state-box">
        <i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i>
        <span>Falha na conexão:<br>${escHtml(e.message)}</span>
      </div>`;
  }

  btn.disabled = false;
  btn.innerHTML = '<i class="fa-solid fa-rotate-right"></i> Atualizar Dispositivos';
}

function renderDevices(devices) {
  const list = $('device-list');
  if (!devices.length) {
    list.innerHTML = `<div class="state-box"><i class="fa-solid fa-plug-circle-xmark"></i><span>Nenhum dispositivo online</span></div>`;
    return;
  }
  list.innerHTML = '';
  devices.forEach((d, i) => {
    const label = d.display_name || 'Dispositivo';
    const sub   = d.jid ? fmtJid(d.jid) : d.id.slice(0,8) + '…';

    const el = document.createElement('div');
    el.className = 'device-item';
    el.innerHTML = `
      <div class="device-avatar">${WA_ICON}</div>
      <div class="device-info">
        <div class="device-name">${escHtml(label)}</div>
        <div class="device-jid">${escHtml(sub)}</div>
      </div>
      <div class="device-status">
        <span class="status-dot online"></span>
        <span class="status-color-online">Online</span>
      </div>
      <i class="fa-solid fa-chevron-right device-arrow"></i>
    `;
    stagger(el, i);
    el.addEventListener('click', () => openContacts(d));
    list.appendChild(el);
  });
}

async function openContacts(device) {
  currentDevice = device;
  allContacts   = [];

  $('contacts-user-name').textContent = device.display_name || 'Dispositivo';
  $('contacts-user-sub').textContent  = 'Carregando…';
  $('tab-count-contacts').textContent = '—';
  $('tab-count-groups').textContent   = '—';
  $('search-input').value             = '';
  $('search-groups-input').value      = '';
  $('contact-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Carregando contatos…</span></div>`;

  $('devices-panel').style.display  = 'none';
  $('contacts-panel').style.display = 'block';

  await loadContactsFromAPI(device);
  await loadGroupsFromAPI(device);
}

async function loadContactsFromAPI(device) {
  try {
    const res = await fetch(
      `${API_HOST}/user/my/contacts?filter=chatted`,
      { headers: buildHeaders(device.id) }
    );
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    allContacts = (data?.results?.data || [])
      .filter(c => isValidContact(c.jid))
      .sort((a, b) => normalizeSearch(a.name||fmtJid(a.jid)).localeCompare(normalizeSearch(b.name||fmtJid(b.jid)), 'pt-BR'))
      .map(c => ({ jid: c.jid, name: c.name || '' }));

    $('tab-count-contacts').textContent = allContacts.length;
    $('contacts-user-sub').textContent  = `${allContacts.length} contatos`;
    renderContacts(allContacts);
  } catch(e) {
    $('contact-list').innerHTML = `
      <div class="state-box">
        <i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i>
        <span>Erro: ${escHtml(e.message)}</span>
      </div>`;
  }
}

function renderContacts(list) {
  const el = $('contact-list');
  if (!list.length) {
    el.innerHTML = `<div class="state-box"><i class="fa-solid fa-user-slash"></i><span>Nenhum contato encontrado</span></div>`;
    return;
  }
  el.innerHTML = '';
  list.forEach((c, i) => {
    const name   = c.name || fmtJid(c.jid);
    const number = fmtJid(c.jid);

    const item = document.createElement('div');
    item.className = 'contact-item';
    item.innerHTML = `
      <div class="contact-avatar">${WA_ICON}</div>
      <div class="contact-info">
        <div class="contact-name">${escHtml(name)}</div>
        <div class="contact-number">${escHtml(number)}</div>
      </div>
    `;
    stagger(item, i);
    item.addEventListener('click', () => openContactModal(c));
    el.appendChild(item);
  });
}

function openContactModal(contact) {
  const name   = contact.name || fmtJid(contact.jid);
  const number = fmtJid(contact.jid);

  $('modal-name').textContent   = name;
  $('modal-number').textContent = number;

  ['copy-name-btn','copy-number-btn','copy-both-btn'].forEach(id => $(id).classList.remove('copied'));
  $('copy-name-btn').innerHTML   = '<i class="fa-solid fa-user"></i> Copiar nome';
  $('copy-number-btn').innerHTML = '<i class="fa-solid fa-hashtag"></i> Copiar número';
  $('copy-both-btn').innerHTML   = '<i class="fa-solid fa-copy"></i> Copiar nome + número';

  $('copy-name-btn').onclick   = () => copyText(name,                 'copy-name-btn',   '<i class="fa-solid fa-user"></i> Copiar nome');
  $('copy-number-btn').onclick = () => copyText(number,               'copy-number-btn', '<i class="fa-solid fa-hashtag"></i> Copiar número');
  $('copy-both-btn').onclick   = () => copyText(`${name}\n${number}`, 'copy-both-btn',   '<i class="fa-solid fa-copy"></i> Copiar nome + número');

  const overlay = $('contact-modal');
  overlay.classList.remove('hiding');
  overlay.style.display = 'flex';
}

function closeModal() {
  const overlay = $('contact-modal');
  overlay.classList.add('hiding');
  setTimeout(() => { overlay.style.display = 'none'; overlay.classList.remove('hiding'); }, 200);
}

function copyText(text, btnId, resetHtml) {
  const apply = () => {
    const btn = $(btnId);
    btn.classList.add('copied');
    btn.innerHTML = '<i class="fa-solid fa-check"></i> Copiado!';
    setTimeout(() => { btn.classList.remove('copied'); btn.innerHTML = resetHtml; }, 2000);
  };
  navigator.clipboard.writeText(text).then(apply).catch(() => {
    const ta = document.createElement('textarea');
    ta.value = text; ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0;';
    document.body.appendChild(ta); ta.focus(); ta.select();
    try { document.execCommand('copy'); } catch(_) {}
    document.body.removeChild(ta);
    apply();
  });
}

function switchTab(tab) {
  activeTab = tab;
  $('tab-contacts').classList.toggle('active', tab === 'contacts');
  $('tab-groups').classList.toggle('active',   tab === 'groups');
  $('pane-contacts').style.display = tab === 'contacts' ? '' : 'none';
  $('pane-groups').style.display   = tab === 'groups'   ? '' : 'none';
}

async function loadGroupsFromAPI(device) {
  $('group-list').innerHTML = `<div class="state-box"><div class="spinner"></div><span>Carregando grupos…</span></div>`;
  try {
    const res = await fetch(`${API_HOST}/user/my/groups`, { headers: buildHeaders(device.id) });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    allGroups = (data?.results?.data || [])
      .filter(g => g.JID && g.JID.endsWith('@g.us'))
      .sort((a, b) => normalizeSearch(a.Name||'').localeCompare(normalizeSearch(b.Name||''), 'pt-BR'))
      .map(g => ({ jid: g.JID, name: g.Name || '' }));

    $('tab-count-groups').textContent = allGroups.length;
    renderGroups(allGroups);
  } catch(e) {
    $('group-list').innerHTML = `<div class="state-box"><i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i><span>Erro: ${escHtml(e.message)}</span></div>`;
  }
}

function renderGroups(list) {
  const el = $('group-list');
  if (!list.length) {
    el.innerHTML = `<div class="state-box"><i class="fa-solid fa-people-roof"></i><span>Nenhum grupo encontrado</span></div>`;
    return;
  }
  el.innerHTML = '';
  list.forEach((g, i) => {
    const name   = g.name || g.jid;
    const jidFmt = g.jid.replace('@g.us', '');

    const item = document.createElement('div');
    item.className = 'group-item';
    item.innerHTML = `
      <div class="group-avatar">${WA_ICON}</div>
      <div class="group-info">
        <div class="group-name">${escHtml(name)}</div>
        <div class="group-jid">${escHtml(jidFmt)}</div>
      </div>
    `;
    stagger(item, i);
    item.addEventListener('click', () => openGroupModal(g));
    el.appendChild(item);
  });
}

function openGroupModal(group) {
  const name   = group.name || group.jid;
  const jidFmt = group.jid.replace('@g.us', '');

  $('group-modal-name').textContent = name;
  $('group-modal-jid').textContent  = jidFmt;

  ['gcopy-name-btn','gcopy-jid-btn','gcopy-both-btn'].forEach(id => $(id).classList.remove('copied'));
  $('gcopy-name-btn').innerHTML  = '<i class="fa-solid fa-people-roof"></i> Copiar nome';
  $('gcopy-jid-btn').innerHTML   = '<i class="fa-solid fa-hashtag"></i> Copiar JID';
  $('gcopy-both-btn').innerHTML  = '<i class="fa-solid fa-copy"></i> Copiar nome + JID';

  $('gcopy-name-btn').onclick  = () => copyText(name,                 'gcopy-name-btn',  '<i class="fa-solid fa-people-roof"></i> Copiar nome');
  $('gcopy-jid-btn').onclick   = () => copyText(jidFmt,               'gcopy-jid-btn',   '<i class="fa-solid fa-hashtag"></i> Copiar JID');
  $('gcopy-both-btn').onclick  = () => copyText(`${name}\n${jidFmt}`, 'gcopy-both-btn',  '<i class="fa-solid fa-copy"></i> Copiar nome + JID');

  const overlay = $('group-modal');
  overlay.classList.remove('hiding');
  overlay.style.display = 'flex';
}

function closeGroupModal() {
  const overlay = $('group-modal');
  overlay.classList.add('hiding');
  setTimeout(() => { overlay.style.display = 'none'; overlay.classList.remove('hiding'); }, 200);
}

// eventos
$('modal-close-btn').addEventListener('click', closeModal);
$('contact-modal').addEventListener('click', e => { if (e.target === $('contact-modal')) closeModal(); });
$('group-modal-close-btn').addEventListener('click', closeGroupModal);
$('group-modal').addEventListener('click', e => { if (e.target === $('group-modal')) closeGroupModal(); });

$('search-input').addEventListener('input', e => {
  const q = normalizeSearch(e.target.value);
  if (!q) { renderContacts(allContacts); $('tab-count-contacts').textContent = allContacts.length; return; }
  const filtered = allContacts.filter(c => normalizeSearch(c.name||'').includes(q) || fmtJid(c.jid).includes(q));
  renderContacts(filtered);
  $('tab-count-contacts').textContent = filtered.length;
});

$('search-groups-input').addEventListener('input', e => {
  const q = normalizeSearch(e.target.value);
  if (!q) { renderGroups(allGroups); $('tab-count-groups').textContent = allGroups.length; return; }
  const filtered = allGroups.filter(g => normalizeSearch(g.name||'').includes(q) || g.jid.includes(q));
  renderGroups(filtered);
  $('tab-count-groups').textContent = filtered.length;
});

$('btn-back').addEventListener('click', () => {
  $('contacts-panel').style.display = 'none';
  $('devices-panel').style.display  = 'block';
  allContacts = []; allGroups = []; currentDevice = null;
  switchTab('contacts');
});

// init
$('btn-load-devices').addEventListener('click', fetchDevices);
fetchDevices();

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "js";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import android.os.Environment;

// 1. Definimos a pasta base
File taskerDir = new File(Environment.getExternalStorageDirectory(), "Tasker/projects_task/projects/whats-connect-api/system/broadcast-master");

// 2. Lista de arquivos que precisam ser verificados/criados
String[] filesToCreate = {
    "cash.json",
    "json-images.json",
    "json-messages.json",
    "json-polls.json",
    "json-status.json"
};

// 3. Garantimos que o diretório pai exista antes de iterar
if (!taskerDir.exists()) {
    if (taskerDir.mkdirs()) {
        tasker.log("Diretórios criados: " + taskerDir.getAbsolutePath());
    }
}

// 4. Iteramos sobre a lista de arquivos
for (String fileName : filesToCreate) {
    File targetFile = new File(taskerDir, fileName);

    if (!targetFile.exists()) {
        FileWriter writer = null;
        try {
            writer = new FileWriter(targetFile);
            writer.write("[]");
            tasker.log("Arquivo criado e inicializado: " + fileName);
        } catch (IOException e) {
            tasker.log("Erro ao criar " + fileName + ": " + e.getMessage());
        } finally {
            if (writer != null) {
                try {
                    writer.close();
                } catch (IOException e) {
                    // Silencioso no fechamento
                }
            }
        }
    } else {
        tasker.log("O arquivo já existe: " + fileName);
    }
}

:root {
            --bg-body: #000;
            --bg-card: #06222A;
            --bg-card-2: #041A21;
            --bg-input: #021216;
            --primary: #0F9DCB;
            --primary-dark: #085E7A;
            --accent: #B5FB2A;
            --accent-dark: #8CC11F;
            --border: #0F507A;
            --border-light: #1a6b9e;
            --text-main: #C6E3DC;
            --text-dim: #8494A4;
            --gold: #FFD700;
            --btn-no: #ff4d4d;
            --success: #22c55e;
            --online: #22c55e;
            --offline: #ef4444;
            --tab-active-bg: #0F9DCB;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Inter', sans-serif;
            -webkit-tap-highlight-color: transparent;
            user-select: none;
        }

        html { font-size: 3.5vw; scroll-behavior: smooth; }

        body {
            background-color: var(--bg-body);
            color: var(--text-main);
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 1.5vh 0;
        }

        .content-wrapper {
            width: 100%;
            max-width: 40rem;
            padding: 0 3.5vw;
            display: flex;
            flex-direction: column;
            gap: 1.2vh;
        }

        .devices-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
        }

        .devices-header {
            padding: 0.625rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 0.75rem;
        }

        .devices-title {
            display: flex;
            align-items: center;
            gap: 0.375rem;
            color: var(--accent);
            font-weight: 700;
            font-size: 0.9375rem;
        }

        .devices-title svg { width: 1.125rem; height: 1.125rem; fill: var(--accent); }

        .btn-refresh {
            background: var(--primary);
            color: #fff;
            border: none;
            padding: 0.375rem 0.75rem;
            border-radius: 0.5rem;
            font-weight: 600;
            font-size: 0.75rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 0.25rem;
            transition: all 0.2s;
        }

        .btn-refresh:hover { background: var(--primary-dark); }

        .devices-list {
            padding: 0.75rem;
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
            max-height: 11rem;
            overflow-y: auto;
        }

        .device-item {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            padding: 0.5rem 0.75rem;
            display: flex;
            align-items: center;
            gap: 0.625rem;
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            animation: fadeInLeft 0.4s ease-out;
        }

        .device-item:hover { 
            border-color: var(--border-light);
            transform: translateX(0.25rem);
            box-shadow: 0 0.25rem 0.5rem rgba(0,0,0,0.2);
        }

        .device-item.display-only {
            cursor: default !important;
        }
        .device-item.display-only:hover {
            border-color: var(--border) !important;
            box-shadow: none !important;
            transform: none !important;
        }
        .device-item.selected {
            border-color: var(--accent);
            background: linear-gradient(135deg, rgba(181,251,42,0.08), rgba(6,34,42,0.9));
        }

        .device-avatar {
            width: 2rem;
            height: 2rem;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--accent), var(--primary));
            display: flex;
            align-items: center;
            justify-content: center;
            color: #000;
            font-weight: 700;
            font-size: 0.875rem;
            flex-shrink: 0;
        }

        .device-info {
            flex: 1;
            min-width: 0;
            display: flex;
            flex-direction: column;
            gap: 0.0625rem;
        }

        .device-name-row { display: flex; align-items: center; gap: 0.375rem; }

        .status-dot {
            width: 0.5rem;
            height: 0.5rem;
            border-radius: 50%;
            flex-shrink: 0;
        }

        .status-dot.online { background: var(--online); box-shadow: 0 0 0.25rem var(--online); }
        .status-dot.offline { background: var(--offline); }

        .device-name {
            font-weight: 600;
            font-size: 0.8125rem;
            color: var(--text-main);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-id {
            font-size: 0.6875rem;
            color: var(--text-dim);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-check {
            width: 1.25rem;
            height: 1.25rem;
            border: 0.125rem solid var(--border);
            border-radius: 0.3125rem;
            background: var(--bg-input);
            display: flex;
            align-items: center;
            justify-content: center;
            flex-shrink: 0;
        }

        .device-item.selected .device-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .device-check svg { width: 0.875rem; height: 0.875rem; fill: #000; opacity: 0; }
        .device-item.selected .device-check svg { opacity: 1; }

        .tabs-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
        }

        .tabs-grid {
            display: grid;
            grid-template-columns: repeat(5, 1fr);
        }

        .tab-btn {
            padding: 0.75rem 0.25rem;
            background: transparent;
            border: none;
            border-right: 0.0625rem solid var(--border);
            color: var(--text-dim);
            cursor: pointer;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.25rem;
            font-size: 0.6875rem;
            font-weight: 600;
            transition: all 0.2s;
        }

        .tab-btn:last-child { border-right: none; }
        .tab-btn svg { width: 1rem; height: 1rem; fill: currentColor; }
        .tab-btn:hover { color: var(--text-main); background: rgba(15,157,203,0.05); }
        .tab-btn.active { background: var(--tab-active-bg); color: #fff; }

        .main-container {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
            min-height: 18rem;
        }

        .tab-content { display: none; padding: 0.875rem; }
        .tab-content.active { display: block; animation: fadeIn 0.25s; }
        @keyframes fadeIn { from {opacity:0; transform:translateY(0.25rem);} to {opacity:1; transform:translateY(0);} }

        .section-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 0.75rem;
            padding: 0 0.25rem 0.875rem;
            border-bottom: 0.0625rem solid var(--border);
            margin-bottom: 0.875rem;
        }

        .section-header h2 {
            color: var(--accent);
            font-size: 1.25rem;
            font-weight: 800;
            letter-spacing: 0.125rem;
            flex: 1;
            text-align: center;
        }

        .header-video {
            width: 3.5rem;
            height: 3.5rem;
            border-radius: 50%;
            object-fit: cover;
            border: 0.125rem solid var(--accent);
            flex-shrink: 0;
            animation: pulse-glow 2s ease-in-out infinite;
        }

        @keyframes pulse-glow {
            0%, 100% { box-shadow: 0 0 0.5rem rgba(15,157,203,0.5); }
            50% { box-shadow: 0 0 1.5rem rgba(15,157,203,0.8); }
        }

        .section-actions {
            display: flex;
            gap: 0.375rem;
        }

        .icon-action-btn {
            width: 2rem;
            height: 2rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            color: var(--text-dim);
            transition: all 0.2s;
        }

        .icon-action-btn:hover { color: var(--accent); border-color: var(--accent); }
        .icon-action-btn svg { width: 1rem; height: 1rem; fill: currentColor; }

        .upload-grid {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 0.5rem;
            margin-bottom: 0.875rem;
        }

        .upload-btn {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            padding: 0.625rem 0.375rem;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.25rem;
            color: var(--text-main);
            cursor: pointer;
            font-weight: 600;
            font-size: 0.6875rem;
        }

        .upload-btn:hover { border-color: var(--accent); background: rgba(181,251,42,0.05); }
        .upload-btn svg { width: 1.375rem; height: 1.375rem; fill: var(--accent); }

        .filter-chips {
            display: flex;
            flex-wrap: wrap;
            gap: 0.375rem;
            margin-bottom: 0.875rem;
            justify-content: center;
        }

        .chip {
            padding: 0.375rem 0.875rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 2rem;
            color: var(--text-main);
            font-size: 0.75rem;
            font-weight: 600;
            cursor: pointer;
        }

        .chip:hover { border-color: var(--accent); }
        .chip.active { background: var(--accent); color: #000; border-color: var(--accent); }

        .items-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(6rem, 1fr));
            gap: 0.625rem;
            max-height: 22rem;
            overflow-y: auto;
            padding: 0.25rem;
            margin-bottom: 0.875rem;
        }

        .item-card {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.625rem;
            overflow: hidden;
            position: relative;
            cursor: pointer;
            display: flex;
            flex-direction: column;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            animation: fadeInUp 0.4s ease-out;
        }

        .item-card:hover { 
            border-color: var(--border-light);
            transform: translateY(-2px);
            box-shadow: 0 0.5rem 1rem rgba(0,0,0,0.3);
        }

        .item-card.selected {
            border-color: var(--accent);
            box-shadow: 0 0 0 0.125rem var(--accent);
        }

        .item-card .preview {
            aspect-ratio: 1/1;
            background: var(--bg-input);
            display: flex;
            align-items: center;
            justify-content: center;
            color: var(--text-dim);
            font-size: 0.625rem;
            padding: 0;
            text-align: center;
            word-break: break-word;
            position: relative;
            overflow: hidden;
        }

        .item-card .preview img,
        .item-card .preview video { 
            width: 100%; 
            height: 100%; 
            object-fit: cover; 
            display: block;
        }

        .modal-preview-container {
            width: 100%;
            background: #000;
            border-radius: 0.5rem;
            overflow: hidden;
            display: flex;
            align-items: center;
            justify-content: center;
            margin-bottom: 0.75rem;
            border: 0.0625rem solid var(--border);
        }

        .modal-preview-container img,
        .modal-preview-container video {
            max-width: 100%;
            max-height: 15rem;
            object-fit: contain;
            display: block;
        }

        .item-card .meta {
            background: linear-gradient(180deg, transparent, rgba(0,0,0,0.85));
            padding: 0.25rem 0.375rem;
            font-size: 0.5625rem;
            font-weight: 600;
            color: var(--accent);
        }

        .item-card .meta-row {
            display: flex;
            align-items: center;
            gap: 0.1875rem;
            color: var(--gold);
            font-size: 0.5rem;
        }

        .item-card .item-check {
            position: absolute;
            top: 0.25rem;
            right: 0.25rem;
            width: 1.125rem;
            height: 1.125rem;
            border-radius: 50%;
            background: rgba(0,0,0,0.6);
            border: 0.125rem solid var(--border-light);
            display: none;
            align-items: center;
            justify-content: center;
            z-index: 3;
        }

        .multiselect-mode .item-card .item-check { display: flex; }

        .item-card.selected .item-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .item-card .item-check svg {
            width: 0.75rem;
            height: 0.75rem;
            fill: #000;
            opacity: 0;
        }

        .item-card.selected .item-check svg { opacity: 1; }

        .item-card-actions {
            display: flex;
            justify-content: center;
            gap: 0.5rem;
            padding: 0.375rem;
            background: rgba(0,0,0,0.4);
            border-top: 0.0625rem solid var(--border);
        }

        .action-btn {
            width: 1.75rem;
            height: 1.75rem;
            border-radius: 0.375rem;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
            color: var(--text-dim);
        }

        .action-btn:hover {
            background: var(--accent);
            color: #000;
            border-color: var(--accent);
            transform: scale(1.1);
        }

        .action-btn svg {
            width: 1rem;
            height: 1rem;
            fill: currentColor;
        }

        .action-btn.schedule-btn {
            color: var(--primary);
        }

        .action-btn.schedule-btn:hover {
            background: var(--primary);
            color: #fff;
        }

        .schedule-info {
            padding: 0.25rem 0.375rem;
            font-size: 0.625rem;
            color: var(--primary);
            text-align: center;
            background: rgba(15,157,203,0.1);
            border-top: 0.0625rem solid rgba(15,157,203,0.3);
        }

        .list-container {
            max-height: 20rem;
            overflow-y: auto;
            margin-bottom: 0.875rem;
        }

        .list-item {
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            padding: 0.625rem;
            margin-bottom: 0.5rem;
            position: relative;
            cursor: pointer;
            transition: all 0.2s;
        }

        .list-item:hover { border-color: var(--border-light); }

        .list-item.selected {
            border-color: var(--accent);
            background: rgba(181,251,42,0.08);
        }

        .list-item.has-schedule {
            border-left: 0.25rem solid var(--primary);
        }

        .list-item.in-multiselect { cursor: crosshair; }

        .list-item .list-header {
            display: flex;
            align-items: flex-start;
            justify-content: space-between;
            gap: 0.375rem;
            margin-bottom: 0.25rem;
        }

        .list-item .list-type {
            color: var(--accent);
            font-size: 0.625rem;
            font-weight: 700;
            letter-spacing: 0.0625rem;
        }

        .list-item .list-title {
            font-weight: 600;
            font-size: 0.8125rem;
            color: var(--text-main);
            word-break: break-word;
            margin-bottom: 0.1875rem;
        }

        .list-item .list-meta {
            font-size: 0.6875rem;
            color: var(--text-dim);
        }

        .list-item .list-check {
            position: absolute;
            top: 0.5rem;
            right: 0.5rem;
            width: 1.125rem;
            height: 1.125rem;
            border-radius: 50%;
            background: rgba(0,0,0,0.6);
            border: 0.125rem solid var(--border-light);
            display: none;
            align-items: center;
            justify-content: center;
            z-index: 3;
        }

        .multiselect-mode .list-item .list-check { display: flex; }

        .list-item.selected .list-check {
            background: var(--accent);
            border-color: var(--accent);
        }

        .list-item .list-check svg {
            width: 0.75rem;
            height: 0.75rem;
            fill: #000;
            opacity: 0;
        }

        .list-item.selected .list-check svg { opacity: 1; }

        .tab-multiselect-controls {
            display: none;
            gap: 0.5rem;
            margin-bottom: 1rem;
            animation: fadeIn 0.3s ease;
        }

        .tab-multiselect-controls.show {
            display: flex;
        }

        .ms-btn {
            flex: 1;
            background: var(--bg-card-2);
            border: 0.0625rem solid var(--border);
            border-radius: 0.375rem;
            color: var(--text-dim);
            font-size: 0.625rem;
            font-weight: 600;
            padding: 0.5rem 0.25rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.25rem;
            transition: all 0.2s;
            text-transform: uppercase;
            letter-spacing: 0.02rem;
            white-space: nowrap;
        }

        .ms-btn:hover {
            background: var(--primary-dark);
            color: #fff;
            border-color: var(--primary);
        }

        .ms-btn.danger {
            color: #ff4d4d;
            border-color: rgba(255, 77, 77, 0.3);
        }

        .ms-btn.danger:hover {
            background: #ff4d4d;
            color: #fff;
            border-color: #ff4d4d;
        }

        .submit-btn {
            width: 100%;
            padding: 0.75rem;
            background: var(--accent);
            color: #000;
            border: none;
            border-radius: 0.625rem;
            font-weight: 800;
            font-size: 0.875rem;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 0.375rem;
            transition: all 0.3s ease;
        }

        .submit-btn:hover { 
            background: var(--accent-dark);
            transform: translateY(-2px);
            box-shadow: 0 0.25rem 0.75rem rgba(181,251,42,0.3);
        }
        .submit-btn:active { transform: translateY(0) scale(0.98); }
        .submit-btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }
        .submit-btn svg { width: 1rem; height: 1rem; fill: #000; }
        .submit-btn.hidden { display: none !important; }

        .terminal-panel {
            width: 100%;
            background: var(--bg-card);
            border-radius: 0.875rem;
            border: 0.0625rem solid var(--border);
            box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.65);
            overflow: hidden;
            margin-top: 0.375rem;
            transition: all 0.3s ease;
        }

        .terminal-panel.minimized .terminal-body {
            display: none;
        }

        .terminal-window-controls {
            display: flex;
            gap: 0.375rem;
            align-items: center;
            margin-left: auto;
        }

        .window-btn {
            width: 1.75rem;
            height: 1.75rem;
            border: none;
            border-radius: 0.25rem;
            background: transparent;
            color: var(--text-dim);
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
            padding: 0;
        }

        .window-btn:hover {
            background: rgba(255,255,255,0.1);
            color: var(--text-main);
        }

        .window-btn.minimize:hover {
            background: rgba(181,251,42,0.15);
            color: var(--accent);
        }

        .window-btn svg {
            width: 1rem; height: 1rem;
            fill: currentColor;
        }

        .window-btn.minimize svg {
            transform: translateY(0.25rem);
        }

        .terminal-header {
            user-select: none;
            padding: 0.5rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }

        .terminal-header h3 {
            color: var(--accent);
            font-size: 0.8125rem;
            font-weight: 700;
            margin: 0;
            display: flex;
            align-items: center;
            gap: 0.375rem;
            flex-shrink: 0;
        }

        .terminal-header h3::before {
            content: '●';
            color: var(--success);
            animation: blink 1.5s infinite;
        }

        @keyframes blink { 50% { opacity: 0.3; } }

        .btn-clear {
            background: transparent;
            border: 0.0625rem solid var(--border);
            color: var(--text-dim);
            padding: 0.1875rem 0.625rem;
            border-radius: 0.375rem;
            font-size: 0.6875rem;
            cursor: pointer;
        }

        .terminal-body {
            padding: 0.5rem 1rem;
            max-height: 10rem;
            overflow-y: auto;
            font-family: 'Courier New', monospace;
            font-size: 0.6875rem;
            line-height: 1.5;
        }

        .log-entry {
            padding: 0.1875rem 0;
            border-bottom: 0.0625rem solid rgba(15,80,122,0.3);
            word-break: break-all;
        }

        .log-entry:last-child { border-bottom: none; }
        .log-time { color: var(--text-dim); }
        .log-info { color: var(--primary); }
        .log-success { color: var(--accent); }
        .log-error { color: var(--btn-no); }
        .log-warn { color: var(--gold); }

        .form-group { margin-bottom: 0.75rem; }
        .form-group label { display: block; font-size: 0.75rem; font-weight: 600; margin-bottom: 0.25rem; }

        .form-group input[type="text"],
        .form-group input[type="number"],
        .form-group textarea,
        .form-group select {
            width: 100%;
            padding: 0.5rem 0.75rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-main);
            font-size: 0.8125rem;
            font-family: inherit;
        }

        .form-group input:focus, .form-group textarea:focus, .form-group select:focus {
            outline: none;
            border-color: var(--accent);
        }

        .form-group textarea { resize: vertical; min-height: 3rem; }

        .auto-expand {
            overflow: hidden;
            min-height: 2.5rem;
            max-height: 13rem;
            line-height: 1.5;
            resize: none;
            box-sizing: border-box;
            transition: none;
        }

        .auto-expand:focus {
            overflow-y: auto;
        }

        .toggle-row {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0.375rem 0;
            font-size: 0.8125rem;
        }

        .toggle-switch {
            position: relative;
            width: 2.25rem;
            height: 1.25rem;
            background: var(--bg-input);
            border-radius: 1rem;
            border: 0.0625rem solid var(--border);
            cursor: pointer;
        }

        .toggle-switch.on { background: var(--accent); border-color: var(--accent); }

        .toggle-switch::after {
            content: '';
            position: absolute;
            top: 0.125rem; left: 0.125rem;
            width: 0.875rem; height: 0.875rem;
            background: #fff;
            border-radius: 50%;
            transition: left 0.2s;
        }

        .toggle-switch.on::after { left: 1.125rem; }

        .modal-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0,0,0,0.85);
            display: none;
            align-items: center;
            justify-content: center;
            padding: 3vw;
            z-index: 200;
        }

        .modal-overlay.show { 
            display: flex;
            animation: fadeIn 0.2s ease-out;
        }

        .modal {
            animation: slideUp 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            background: var(--bg-card);
            border: 0.0625rem solid var(--border);
            border-radius: 0.875rem;
            max-width: 28rem;
            width: 100%;
            max-height: 90vh;
            overflow-y: auto;
            box-shadow: 0 1.5rem 3rem rgba(0,0,0,0.7);
        }

        @keyframes slideUp {
            from { opacity: 0; transform: translateY(2rem); }
            to { opacity: 1; transform: translateY(0); }
        }

        .modal-header {
            padding: 0.75rem 1rem;
            background: rgba(0,0,0,0.4);
            border-bottom: 0.0625rem solid var(--border);
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .modal-header h3 { color: var(--accent); font-size: 0.9375rem; font-weight: 700; }

        .modal-close {
            background: transparent;
            border: none;
            color: var(--text-dim);
            font-size: 1.25rem;
            cursor: pointer;
            line-height: 1;
        }

        .modal-body { padding: 1rem; }

        .modal-footer {
            padding: 0.75rem 1rem;
            border-top: 0.0625rem solid var(--border);
            display: flex;
            gap: 0.5rem;
        }

        .btn-action {
            flex: 1;
            padding: 0.5rem 0.75rem;
            border: none;
            border-radius: 0.5rem;
            font-size: 0.8125rem;
            font-weight: 600;
            cursor: pointer;
        }

        .btn-no { background: var(--btn-no); color: white; }
        .btn-yes { background: var(--accent); color: #000; }
        .btn-primary { background: var(--primary); color: white; }
        .btn-action:hover { opacity: 0.9; }

        .picker-search {
            width: 100%;
            padding: 0.5rem 0.75rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-main);
            font-size: 0.8125rem;
            margin-bottom: 0.5rem;
        }

        .suffix-picker {
            display: flex;
            gap: 0.375rem;
            flex-wrap: wrap;
            margin-bottom: 0.5rem;
        }

        .suffix-chip {
            padding: 0.5rem 0.875rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.75rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            gap: 0.375rem;
        }

        .suffix-chip:hover { border-color: var(--accent); color: var(--text-main); }
        .suffix-chip.active {
            background: var(--accent);
            color: #000;
            border-color: var(--accent);
        }

        .device-picker {
            display: flex;
            flex-direction: column;
            gap: 0.375rem;
            margin-top: 0.375rem;
            max-height: 14rem;
            overflow-y: auto;
            padding-right: 0.25rem;
        }

        .device-picker::-webkit-scrollbar { width: 0.375rem; }
        .device-picker::-webkit-scrollbar-track { background: var(--bg-input); border-radius: 0.25rem; }
        .device-picker::-webkit-scrollbar-thumb { background: var(--border); border-radius: 0.25rem; }

        .device-chip {
            padding: 0.5rem 0.625rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
            color: var(--text-dim);
            font-size: 0.6875rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            gap: 0.5rem;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .device-chip:hover { border-color: var(--primary); color: var(--text-main); }
        .device-chip.active { background: var(--primary); color: #fff; border-color: var(--primary); }

        .device-chip .device-avatar {
            width: 1.25rem; height: 1.25rem;
            border-radius: 50%;
            background: var(--bg-card-2);
            flex-shrink: 0;
            display: flex; align-items: center; justify-content: center;
            overflow: hidden;
        }

        .device-chip .device-avatar img { width: 100%; height: 100%; object-fit: cover; }

        .device-chip .device-status {
            width: 0.375rem; height: 0.375rem;
            border-radius: 50%;
            flex-shrink: 0;
            margin-left: auto;
        }

        .device-chip .device-status.online { background: #4ade80; }
        .device-chip .device-status.offline { background: #f87171; }

        .duration-picker {
            display: flex;
            flex-wrap: wrap;
            gap: 0.375rem;
            margin-top: 0.375rem;
        }

        .duration-chip {
            flex: 1;
            min-width: calc(50% - 0.1875rem);
            padding: 0.5rem 0.625rem;
            background: var(--bg-input);
            border: 0.0625rem solid var(--border);
            border-radius: 0.5rem;
