import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import com.joaomgcd.taskerm.action.java.JavaCodeException;


type = "css";

project_path = tasker.getVariable("project_path");

if (project_path == null || project_path == void) {
    throw new JavaCodeException("A variável do Tasker 'project_path' não está definida.");
}

folderName = "";
extension = "";
contentVarName = "";

if (type.equals("css")) {
    folderName = "css";
    extension = "css";
    contentVarName = "css";
} else if (type.equals("js")) {
    folderName = "js";
    extension = "js";
    contentVarName = "jsc";
} else {
    throw new JavaCodeException("Tipo não suportado: " + type);
}

file_content = tasker.getVariable(contentVarName);

if (file_content == null || file_content == void) {
    throw new JavaCodeException("A variável do Tasker '" + contentVarName + "' não está definida ou está vazia.");
}

dirPath = project_path + File.separator + folderName;
dir = new File(dirPath);

if (!dir.exists()) {
    if (!dir.mkdirs()) {
        throw new JavaCodeException("Falha ao criar o diretório: " + dirPath);
    }
}

filePath = dirPath + File.separator + "index." + extension;
file = new File(filePath);

writer = null;
try {
    writer = new FileWriter(file);
    writer.write(file_content);
} catch (IOException e) {
    throw new JavaCodeException("Falha ao escrever o arquivo " + extension + ": " + e.getMessage());
} finally {
    if (writer != null) {
        try {
            writer.close();
        } catch (IOException e) {
        }
    }
}

