/* =========================================================
   FILE I/O
   ========================================================= */
function isTasker() { return typeof tk !== 'undefined' && tk && typeof tk.readFile === 'function'; }

function readFileSafe(path) {
    try {
        if (isTasker()) {
            const c = tk.readFile(path);
            if (c && c.trim()) return JSON.parse(c);
        } else {
            const raw = localStorage.getItem('wc_' + path);
            if (raw) return JSON.parse(raw);
        }
    } catch (e) {}
    return null;
}

function writeFileSafe(path, data) {
    try {
        const str = JSON.stringify(data, null, 2);
        if (isTasker()) tk.writeFile(path, str, false);
        else localStorage.setItem('wc_' + path, str);
    } catch (e) { log('error', 'Erro escrita: ' + path); }
}

/* Detecta MIME type baseado na extensão do arquivo */
function getMimeType(path) {
    const ext = path.split('.').pop().toLowerCase();
    const mimeTypes = {
        'jpg': 'image/jpeg',
        'jpeg': 'image/jpeg',
        'png': 'image/png',
        'gif': 'image/gif',
        'webp': 'image/webp',
        'bmp': 'image/bmp',
        'mp4': 'video/mp4',
        '3gp': 'video/3gpp',
        'avi': 'video/avi',
        'mov': 'video/quicktime',
        'wmv': 'video/x-ms-wmv',
        'pdf': 'application/pdf',
        'doc': 'application/msword',
        'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'xls': 'application/vnd.ms-excel',
        'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'ppt': 'application/vnd.ms-powerpoint',
        'pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'txt': 'text/plain',
        'csv': 'text/csv',
        'json': 'application/json',
        'xml': 'application/xml',
        'zip': 'application/zip',
        'rar': 'application/x-rar-compressed',
        '7z': 'application/x-7z-compressed',
        'mp3': 'audio/mpeg',
        'wav': 'audio/wav',
        'ogg': 'audio/ogg',
        'flac': 'audio/flac'
    };
    return mimeTypes[ext] || 'application/octet-stream';
}

/* Lê arquivo local como Blob preservando bytes binários
   IMPORTANTE: tk.readFile() retorna string, o que corrompe arquivos binários.
   Por isso usamos fetch/XHR para ler o Blob diretamente. */
async function pathToBlob(path) {
    try {
        log('info', `Lendo arquivo: ${path}`);
        const mimeType = getMimeType(path);
        log('info', `Tipo MIME: ${mimeType}`);

        let fullPath = path;
        if (!fullPath.startsWith('file://') && !fullPath.startsWith('http')) {
            fullPath = 'file://' + fullPath;
        }

        // Tentativa 1: fetch (preserva bytes binários)
        try {
            const res = await fetch(fullPath);
            if (res.ok) {
                const blob = await res.blob();
                if (blob.size > 0) {
                    log('success', `✓ Arquivo lido via fetch (${blob.size} bytes, tipo: ${blob.type || mimeType})`);
                    // Retorna blob com MIME type correto se necessário
                    if (blob.type !== mimeType && mimeType !== 'application/octet-stream') {
                        return new Blob([blob], { type: mimeType });
                    }
                    return blob;
                }
            }
        } catch (e) {
            log('warn', `fetch falhou: ${e.message}`);
        }

        // Tentativa 2: XMLHttpRequest com responseType blob
        try {
            const blob = await new Promise((resolve, reject) => {
                const xhr = new XMLHttpRequest();
                xhr.open('GET', fullPath, true);
                xhr.responseType = 'blob';
                xhr.onload = function() {
                    if (xhr.status === 200 || xhr.status === 0) {
                        resolve(xhr.response);
                    } else {
                        reject(new Error('XHR status: ' + xhr.status));
                    }
                };
                xhr.onerror = function() { reject(new Error('XHR error')); };
                xhr.send();
            });
            if (blob && blob.size > 0) {
                log('success', `✓ Arquivo lido via XHR (${blob.size} bytes, tipo: ${mimeType})`);
                if (mimeType !== 'application/octet-stream') {
                    return new Blob([blob], { type: mimeType });
                }
                return blob;
            }
        } catch (e) {
            log('warn', `XHR falhou: ${e.message}`);
        }

        // Tentativa 3: tk.readFile como base64 (.b64)
        if (isTasker()) {
            try {
                const b64Path = path + '.b64';
                log('info', `Tentando tk.readFile base64: ${b64Path}`);
                const b64 = tk.readFile(b64Path);
                if (b64 && b64.trim()) {
                    const byteChars = atob(b64.trim());
                    const byteNumbers = new Array(byteChars.length);
                    for (let i = 0; i < byteChars.length; i++) {
                        byteNumbers[i] = byteChars.charCodeAt(i);
                    }
                    const byteArray = new Uint8Array(byteNumbers);
                    const blob = new Blob([byteArray], { type: mimeType });
                    log('success', `✓ Arquivo lido via tk.readFile base64 (${blob.size} bytes)`);
                    return blob;
                }
            } catch (e) {
                log('warn', `tk.readFile base64 falhou: ${e.message}`);
            }
        }

        log('error', `❌ Não foi possível ler: ${path}`);
        return null;
    } catch (e) {
        log('error', `Erro ao ler arquivo: ${e.message}`);
        return null;
    }
}

/* Lê arquivo local como base64 puro */
async function pathToBase64(path) {
    const blob = await pathToBlob(path);
    if (!blob) return null;
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            const b64 = reader.result.split(',')[1];
            resolve(b64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
}

/* =========================================================
   LOGS
   ========================================================= */
function log(type, message) {
    const body = document.getElementById('terminalBody');
    const time = new Date().toLocaleTimeString('pt-BR');
    const entry = document.createElement('div');
    entry.className = 'log-entry';
    entry.innerHTML = `<span class="log-time">[${time}]</span> <span class="log-${type}">${escapeHtml(message)}</span>`;
    body.appendChild(entry);
    body.scrollTop = body.scrollHeight;
}

function clearTerminal() { document.getElementById('terminalBody').innerHTML = ''; log('info', 'Terminal limpo.'); }

function copyTerminal() {
    const body = document.getElementById('terminalBody');
    const text = Array.from(body.querySelectorAll('.log-entry'))
        .map(entry => entry.textContent)
        .join('\n');

    if (!text) { log('warn', 'Terminal vazio.'); return; }

    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(() => {
            log('success', '✓ Terminal copiado!');
        }).catch(err => {
            fallbackCopyText(text);
        });
    } else {
        fallbackCopyText(text);
    }
}

function toggleTerminalMinimize() {
    const panel = document.querySelector('.terminal-panel');
    if (panel) {
        panel.classList.toggle('minimized');
    }
}

// Terminal inicia minimizado
if (document.readyState === 'complete' || document.readyState === 'interactive') {
    // Já carregado
} else {
    document.addEventListener('DOMContentLoaded', () => {
        // Terminal já inicia com classe 'minimized' no HTML
    });
}

function fallbackCopyText(text) {
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.style.position = 'fixed';
    textarea.style.left = '-9999px';
    document.body.appendChild(textarea);
    textarea.select();
    try {
        document.execCommand('copy');
        log('success', '✓ Terminal copiado!');
    } catch (err) {
        log('error', 'Falha ao copiar. Selecione manualmente.');
    }
    document.body.removeChild(textarea);
}

function escapeHtml(str) {
    if (typeof str !== 'string') return String(str);
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/* =========================================================
   API
   ========================================================= */
/* Requisição JSON normal (mensagens, enquetes, status texto, devices, contatos) */
async function apiRequest(endpoint, method, body, deviceId) {
    const headers = {
        'Authorization': AUTH,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
    };
    if (deviceId) headers['X-Device-Id'] = deviceId;

    const opts = { method, headers };
    if (body !== undefined) opts.body = JSON.stringify(body);

    try {
        const res = await fetch(API_BASE + endpoint, opts);
        const text = await res.text();
        let json = null;
        try { json = JSON.parse(text); } catch(e){}
        return { ok: res.ok, status: res.status, data: json || text };
    } catch (e) {
        return { ok: false, status: 0, data: e.message };
    }
}

/* Requisição multipart/form-data (apenas imagens e arquivos) */
async function apiMultipart(endpoint, formData, deviceId) {
    const headers = {
        'Authorization': AUTH,
        'Accept': 'application/json'
    };
    if (deviceId) headers['X-Device-Id'] = deviceId;
    // NÃO define Content-Type - o browser adiciona com o boundary correto

    try {
        console.log('API multipart:', endpoint);
        const res = await fetch(API_BASE + endpoint, { method: 'POST', headers, body: formData });
        const text = await res.text();
        let json = null;
        try { json = JSON.parse(text); } catch(e){}
        return { ok: res.ok, status: res.status, data: json || text };
    } catch (e) {
        return { ok: false, status: 0, data: e.message };
    }
}

/* =========================================================
   DEVICES
   ========================================================= */
async function loadDevices() {
    log('info', 'Carregando dispositivos...');
    const res = await apiRequest('/devices', 'GET');
    let devicesRaw = null;
    if (res && res.ok) {
        if (res.data && Array.isArray(res.data.results)) devicesRaw = res.data.results;
        else if (Array.isArray(res.data)) devicesRaw = res.data;
    }
    if (!devicesRaw) {
        log('warn', 'API indisponível. Tentando novamente em 10s...');
        setTimeout(() => { if (STATE.devices.length === 0) loadDevices(); }, 10000);
        return;
    }
    STATE.devices = devicesRaw.map(d => ({
        id: d.id,
        name: d.display_name || d.name || '',
        phone: d.jid || d.phone || '',
        online: d.state === 'logged_in' || d.state === 'online' || d.state === 'connected',
        rawState: d.state
    })).sort((a, b) => {
        // Prioridade: com nome primeiro, depois online
        const aHasName = a.name ? 0 : 1;
        const bHasName = b.name ? 0 : 1;
        if (aHasName !== bHasName) return aHasName - bHasName;
        const aOnline = a.online ? 0 : 1;
        const bOnline = b.online ? 0 : 1;
        if (aOnline !== bOnline) return aOnline - bOnline;
        return (a.name || a.id).localeCompare(b.name || b.id);
    });
    STATE.selectedDeviceIds.clear();
    const onlineDevices = STATE.devices.filter(d => d.online);
    if (onlineDevices.length > 0) onlineDevices.forEach(d => STATE.selectedDeviceIds.add(d.id));
    else if (STATE.devices.length > 0) STATE.selectedDeviceIds.add(STATE.devices[0].id);
    renderDevices();
    log('success', `Dispositivos: ${STATE.devices.length} (${onlineDevices.length} online)`);
    loadDeviceAvatars();
}

/* Cores vibrantes para avatares */
const CAL_ICON = '<svg style="width:0.875rem;height:0.875rem;fill:var(--primary);vertical-align:middle;" viewBox="0 0 24 24"><path d="M19 3h-1V1h-2v2H8V1H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V8h14v11zM9 10H7v2h2v-2zm4 0h-2v2h2v-2zm4 0h-2v2h2v-2z"/></svg>';

const SCHEDULE_BTN_ICON = '<svg viewBox="0 0 24 24"><path d="M19 3h-1V1h-2v2H8V1H6v2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H5V8h14v11zM9 10H7v2h2v-2zm4 0h-2v2h2v-2zm4 0h-2v2h2v-2z"/></svg>';

const ADD_BTN = '<span>Agendar</span>';

const DAY_LABELS = { 'Seg': 'SEG', 'Ter': 'TER', 'Qua': 'QUA', 'Qui': 'QUI', 'Sex': 'SEX', 'Sáb': 'SÁB', 'Dom': 'DOM' };

function formatScheduleText(schedule) {
    const times = schedule?.times || [];
    const days = schedule?.days || [];
    if (times.length === 0 && days.length === 0) return 'Nenhum agendamento';
    return CAL_ICON + ' ' + (days.join(', ') || 'Todos') + (times.length > 0 ? ' • ' + times.join(', ') : '');
}

function renderSchedulePreview(schedule) {
    const times = schedule?.times || [];
    const days = schedule?.days || [];
    const hasSchedule = times.length > 0 || days.length > 0;

    const badgeHtml = ['Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb', 'Dom'].map(d => {
        const active = days.includes(d);
        return '<span class="day-badge' + (active ? ' active' : '') + '">' + DAY_LABELS[d] + '</span>';
    }).join('');

    const timesHtml = times.length > 0 ? ('<div class="times-preview">🕐 ' + times.join(' • ') + '</div>') : '';
    const innerHtml = hasSchedule ? ('<div class="days-badges">' + badgeHtml + '</div>' + timesHtml) : 'Nenhum agendamento definido';

    return '<div class="schedule-preview"><div class="schedule-preview-text' + (hasSchedule ? ' has-schedule' : '') + '" style="flex:1;">' + innerHtml + '</div></div>';
}

const AVATAR_COLORS = [
    'linear-gradient(135deg, #B5FB2A, #0F9DCB)',
    'linear-gradient(135deg, #FFD700, #FF6B6B)',
    'linear-gradient(135deg, #0F9DCB, #8B5CF6)',
    'linear-gradient(135deg, #22c55e, #0F9DCB)',
    'linear-gradient(135deg, #ec4899, #F59E0B)',
    'linear-gradient(135deg, #8B5CF6, #ec4899)'
];

function getAvatarColor(name) {
    if (!name) return AVATAR_COLORS[0];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
        hash = ((hash << 5) - hash) + name.charCodeAt(i);
        hash = hash & hash;
    }
    return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

function getInitials(name) {
    if (!name) return '?';
    const clean = name.replace(/@s\.whatsapp\.net|@g\.us/g, '').trim();
    const parts = clean.split(' ').filter(Boolean);
    if (parts.length >= 2) {
        return (parts[0].charAt(0) + parts[1].charAt(0)).toUpperCase();
    }
    return clean.charAt(0).toUpperCase() || '?';
}

function renderDevices() {
    const container = document.getElementById('devicesList');
    if (STATE.devices.length === 0) { container.innerHTML = '<div class="empty-state">Nenhum dispositivo.</div>'; return; }
    container.innerHTML = STATE.devices.map(d => {
        const initials = getInitials(d.name);
        const color = getAvatarColor(d.name);
        const avatarHtml = d.avatar 
            ? `<img src="${d.avatar}" style="width:100%;height:100%;border-radius:50%;object-fit:cover;" onerror="this.style.display='none'; this.nextSibling.style.display='flex'"><span style="display:none;width:100%;height:100%;align-items:center;justify-content:center;color:#000;font-weight:700;font-size:0.875rem;">${initials}</span>`
            : initials;
        return `
            <div class="device-item display-only">
                <div class="device-avatar" style="background:${color};">${avatarHtml}</div>
                <div class="device-info">
                    <div class="device-name-row">
                        <span class="status-dot ${d.online ? 'online' : 'offline'}"></span>
                        <span class="device-name">${escapeHtml(d.name)}</span>
                    </div>
                    <div class="device-id">${escapeHtml(d.phone || d.id)}</div>
                </div>
            </div>
        `;
    }).join('');
}

/* Tenta buscar avatar dos dispositivos */
async function loadDeviceAvatars() {
    const devices = getSelectedDevices();
    if (devices.length === 0) return;
    const deviceId = devices[0].id;

    for (const device of STATE.devices) {
        if (!device.phone) continue;
        try {
            log('info', `Carregando avatar de ${device.name}...`);
            const res = await apiRequest(
                `/user/avatar?phone=${encodeURIComponent(device.phone)}&is_preview=false&is_community=false`,
                'GET',
                undefined,
                deviceId
            );
            if (res && res.ok && res.data) {
                const url = res.data.results?.url;
                if (url) {
                    device.avatar = url;
                    log('success', `✓ Avatar carregado para ${device.name}`);
                } else {
                    log('warn', `Avatar não disponível para ${device.name}`);
                }
            } else {
                log('warn', `Falha avatar ${device.name}: ${JSON.stringify(res?.data || res)}`);
            }
        } catch (e) {
            log('warn', `Erro avatar ${device.name}: ${e.message}`);
        }
    }
    renderDevices();
}

function toggleDevice(id) {
    const device = STATE.devices.find(d => d.id === id);
    if (!device) return;
    if (STATE.selectedDeviceIds.has(id)) {
        const onlineSel = Array.from(STATE.selectedDeviceIds).filter(did => {
            const dev = STATE.devices.find(x => x.id === did); return dev && dev.online;
        });
        if (device.online && onlineSel.length > 1) STATE.selectedDeviceIds.delete(id);
        else if (!device.online) STATE.selectedDeviceIds.delete(id);
        else { log('warn', 'Mantenha ao menos um dispositivo online.'); return; }
    } else {
        const hasOnline = Array.from(STATE.selectedDeviceIds).some(did => {
            const dev = STATE.devices.find(x => x.id === did); return dev && dev.online;
        });
        if (!device.online && hasOnline) { log('warn', 'Não pode selecionar offline.'); return; }
        STATE.selectedDeviceIds.add(id);
    }
    renderDevices();
}

function getSelectedDevices() { return STATE.devices.filter(d => STATE.selectedDeviceIds.has(d.id)); }

/* =========================================================
   TABS
   ========================================================= */
function switchTab(tab) {
    // Limpa todas as seleções ao mudar de aba
    STATE.statusItems.forEach(i => i.selected = false);
    STATE.imageItems.forEach(i => i.selected = false);
    STATE.messageItems.forEach(i => i.selected = false);
    STATE.pollItems.forEach(i => i.selected = false);
    STATE.fileItems.forEach(i => i.selected = false);

    exitMultiselect();

    document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    document.querySelectorAll(`.tab-btn[data-tab="${tab}"]`).forEach(b => b.classList.add('active'));
    document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
    const el = document.getElementById('tab-' + tab);
    if (el) el.classList.add('active');
    if (tab === 'status') {
        renderStatus();
        updateSendButtonsVisibility('status');
        updateSendTypesVisibility();
    } else if (tab === 'images') {
        renderImages();
        updateSendButtonsVisibility('images');
    } else if (tab === 'messages') {
        renderMessages();
        updateSendButtonsVisibility('messages');
    } else if (tab === 'polls') {
        renderPolls();
        updateSendButtonsVisibility('polls');
    } else if (tab === 'files') {
        renderFiles();
        updateSendButtonsVisibility('files');
    }
}

