function openAddStatus(type) {
    STATE._pendingStatusType = type;
    STATE._pendingStatusSchedule = { times: [], days: [] };
    document.getElementById('addStatusTitle').textContent = 'Adicionar Status: ' + type.toUpperCase();
    document.getElementById('statusPreview').style.display = 'none';
    document.getElementById('statusTextGroup').style.display = type === 'text' ? 'block' : 'none';
    document.getElementById('statusCaptionGroup').style.display = type !== 'text' ? 'block' : 'none';
    document.getElementById('statusFileInput').style.display = type !== 'text' ? 'block' : 'none';
    document.getElementById('statusMessage').value = '';
    document.getElementById('statusCaption').value = '';
    handleAutoExpand(document.getElementById('statusCaption'));
    updateAddSchedulePreview('addStatusSchedulePreview', '_pendingStatusSchedule');
    if (type !== 'text') setTimeout(() => document.getElementById('statusFileInput').click(), 50);
    openModal('addStatusModal');
}

function openScheduleModalForAdd(type, containerPreviewId, stateKey) {
    scheduleItemType = type;
    scheduleItemIndex = -1;
    clearScheduleAlert();

    const schedule = STATE[stateKey] || { times: [], days: [] };
    const selectedDays = schedule.days || [];
    document.querySelectorAll('#scheduleDaysGrid .day-chip').forEach(chip => {
        chip.classList.toggle('active', selectedDays.includes(chip.dataset.day));
    });

    const timesList = document.getElementById('scheduleTimesList');
    timesList.innerHTML = '';
    (schedule.times || []).forEach(time => addScheduleTime(time));

    openModal('scheduleModal');
}

function updateAddSchedulePreview(containerPreviewId, stateKey) {
    const schedule = STATE[stateKey] || { times: [], days: [] };
    const previewEl = document.getElementById(containerPreviewId);
    if (previewEl) previewEl.innerHTML = renderSchedulePreview(schedule);
}

