   ========================================================= */
function openAddPoll() {
    document.getElementById('pollQuestion').value = '';
    document.getElementById('pollMaxAnswer').value = '1';
    document.getElementById('pollOptions').innerHTML = '';
    STATE._pendingPollSchedule = { times: [], days: [] };
    populateRecipientsContainer('pollRecipients', []);
    addPollOption(); addPollOption();
    updateAddSchedulePreview('addPollSchedulePreview', '_pendingPollSchedule');
    hideRecipientsAlert('pollRecipientsAlert');
    populateDevicePicker('poll', []);
    openModal('addPollModal');
}

function addPollOption() {
    const c = document.getElementById('pollOptions');
    const opts = c.querySelectorAll('.poll-option');
    if (opts.length >= 12) { log('warn', 'Máx. 12 opções.'); return; }
    const div = document.createElement('div');
    div.className = 'poll-option';
    div.innerHTML = `<input type="text" placeholder="Opção ${opts.length + 1}"><button onclick="this.parentElement.remove()" type="button">×</button>`;
    c.appendChild(div);
}

async function confirmAddPoll() {
    const question = document.getElementById('pollQuestion').value.trim();
    if (!question) { log('error', 'Digite a pergunta.'); return; }
    const options = Array.from(document.querySelectorAll('#pollOptions input')).map(i => i.value.trim()).filter(Boolean);
    if (options.length < 2) { log('error', 'Mín. 2 opções.'); return; }
    const recipients = collectRecipientsFromContainer('pollRecipients');
    if (recipients.length === 0) {
        showRecipientsAlert('pollRecipientsAlert');
        log('error', 'Adicione pelo menos um destinatário.');
        return;
    }
    hideRecipientsAlert('pollRecipientsAlert');
    const deviceIds = getSelectedDeviceIds('poll');
    if (deviceIds.length === 0) {
        showDevicePickerAlert('poll');
        log('error', 'Selecione pelo menos um dispositivo de envio.');
        return;
    }
    const max_answer = Math.max(1, Math.min(options.length, parseInt(document.getElementById('pollMaxAnswer').value) || 1));
    const schedule = STATE._pendingPollSchedule || { times: [], days: [] };
    STATE.pollItems.push({ recipients, question, options, max_answer, type: 'poll', schedule, device_ids: deviceIds });
    savePollsFile();
    log('success', `Enquete adicionada para ${deviceIds.length} dispositivo(s) e ${recipients.length} destinatário(s).`);
    closeModal('addPollModal');
    renderPolls();
}

