/* =========================================================
   CLICK / LONG PRESS / MULTISELECT
   ========================================================= */
let pressTimer = null;
let pressStart = 0;

let pressStartPos = { x: 0, y: 0 };
let currentMoveHandler = null;
let currentRemoveMoveListeners = null;

function handlePressStart(e, section, idx) {
    pressStart = Date.now();
    // Captura posição inicial do toque/mouse
    const touch = e.touches ? e.touches[0] : e;
    pressStartPos.x = touch.clientX;
    pressStartPos.y = touch.clientY;

    // Adiciona listener para detectar movimento
    currentMoveHandler = (moveEvent) => {
        const moveTouch = moveEvent.touches ? moveEvent.touches[0] : moveEvent;
        const deltaX = Math.abs(moveTouch.clientX - pressStartPos.x);
        const deltaY = Math.abs(moveTouch.clientY - pressStartPos.y);

        // Se moveu mais de 10px, cancela (é scroll/arraste)
        if (deltaX > 10 || deltaY > 10) {
            handlePressEnd();
            removeMoveListeners();
        }
    };

    currentRemoveMoveListeners = () => {
        if (currentMoveHandler) {
            document.removeEventListener('touchmove', currentMoveHandler);
            document.removeEventListener('mousemove', currentMoveHandler);
            currentMoveHandler = null;
            currentRemoveMoveListeners = null;
        }
    };

    document.addEventListener('touchmove', currentMoveHandler, { passive: true });
    document.addEventListener('mousemove', currentMoveHandler, { passive: true });

    pressTimer = setTimeout(() => {
        removeMoveListeners();
        // Long press → entrar em multiselect
        if (!STATE.multiselect.active) {
            STATE.multiselect.active = true;
            STATE.multiselect.section = section;
        }
        toggleSelect(section, idx, e.target);
    }, 500);
}

function handlePressEnd() {
    if (pressTimer) { clearTimeout(pressTimer); pressTimer = null; }
    removeMoveListeners();
}

function removeMoveListeners() {
    if (currentRemoveMoveListeners) {
        currentRemoveMoveListeners();
    }
}

function handleItemClick(section, idx, e) {
    const duration = Date.now() - pressStart;

    // Remove listeners de movimento
    removeMoveListeners();

    if (STATE.multiselect.active && STATE.multiselect.section === section) {
        // Em multiselect, clique normal também seleciona
        toggleSelect(section, idx, e ? e.target : null);
    } else if (duration < 400) {
        // Clique normal (não foi long press) → abrir editor
        openEditor(section, idx);
    }
    // Se foi long press mas o timer disparou, não faz nada adicional
}

function toggleSelect(section, idx, el) {
    let arr;
    if (section === 'status') arr = STATE.statusItems;
    else if (section === 'images') arr = STATE.imageItems;
    else if (section === 'messages') arr = STATE.messageItems;
    else if (section === 'polls') arr = STATE.pollItems;
    else if (section === 'files') arr = STATE.fileItems;

    if (!arr || !arr[idx]) return;

    arr[idx].selected = !arr[idx].selected;
    const isSelected = arr[idx].selected;

    let targetEl = null;
    if (el && typeof el.closest === 'function') {
        targetEl = el.closest('[data-idx]');
    }

    if (!targetEl) {
        const container = getItemsContainer(section);
        if (container) {
            targetEl = container.querySelector(`[data-idx="${idx}"]`);
        }
    }

    if (targetEl) {
        targetEl.classList.toggle('selected', isSelected);
    }

    updateMultiselectBar();
}

function updateMultiselectBar() {
    const section = STATE.multiselect.section || document.querySelector('.tab-btn.active')?.dataset.tab;
    if (!section) return;

    let arr;
    if (section === 'status') arr = STATE.statusItems;
    else if (section === 'images') arr = STATE.imageItems;
    else if (section === 'messages') arr = STATE.messageItems;
    else if (section === 'polls') arr = STATE.pollItems;
    else if (section === 'files') arr = STATE.fileItems;

    if (!arr) return;

    const count = arr.filter(i => i.selected).length;

    const tabId = 'tab-' + section;
    const tab = document.getElementById(tabId);
    if (tab) {
        const controls = tab.querySelector('.tab-multiselect-controls');
        if (controls) {
            controls.classList.toggle('show', count > 0);
        }
    }

    if (count === 0 && STATE.multiselect.active) {
        exitMultiselect();
    } else {
        updateSendButtonsVisibility(section);
    }
}

function selectAllCurrent() {
    const section = document.querySelector('.tab-btn.active')?.dataset.tab;
    if (!section) return;

    if (!STATE.multiselect.active) {
        STATE.multiselect.active = true;
        STATE.multiselect.section = section;
    }

    let arr;
    if (section === 'status') arr = STATE.statusItems;
    else if (section === 'images') arr = STATE.imageItems;
    else if (section === 'messages') arr = STATE.messageItems;
    else if (section === 'polls') arr = STATE.pollItems;
    else if (section === 'files') arr = STATE.fileItems;

    if (!arr) return;

    arr.forEach(i => i.selected = true);

    const container = getItemsContainer(section);
    if (container) {
        container.querySelectorAll('[data-idx]').forEach(el => {
            el.classList.add('selected');
        });
    }

    updateMultiselectBar();
}

function deselectAllCurrent() {
    const section = STATE.multiselect.section || document.querySelector('.tab-btn.active')?.dataset.tab;
    if (!section) return;

    let arr;
    if (section === 'status') arr = STATE.statusItems;
    else if (section === 'images') arr = STATE.imageItems;
    else if (section === 'messages') arr = STATE.messageItems;
    else if (section === 'polls') arr = STATE.pollItems;
    else if (section === 'files') arr = STATE.fileItems;

    if (!arr) return;

    arr.forEach(i => i.selected = false);
    exitMultiselect();
}

async function deleteSelectedCurrent() {
    const section = STATE.multiselect.section || document.querySelector('.tab-btn.active')?.dataset.tab;
    if (!section) return;

    let arr;
    if (section === 'status') arr = STATE.statusItems;
    else if (section === 'images') arr = STATE.imageItems;
    else if (section === 'messages') arr = STATE.messageItems;
    else if (section === 'polls') arr = STATE.pollItems;
    else if (section === 'files') arr = STATE.fileItems;

    if (!arr) return;

    const count = arr.filter(i => i.selected).length;
    if (count === 0) { log('warn', 'Nenhum selecionado.'); return; }
    const ok = await askConfirm(`Eliminar ${count} item(ns)?`);
    if (!ok) return;
    for (let i = arr.length - 1; i >= 0; i--) {
        if (arr[i].selected) arr.splice(i, 1);
    }
    const savers = { status: saveStatusFile, images: saveImagesFile, messages: saveMessagesFile, polls: savePollsFile, files: saveFilesFile };
    if (savers[section]) savers[section]();

    // Esconde os controles antes de renderizar
    const tab = document.getElementById('tab-' + section);
    if (tab) {
        const controls = tab.querySelector('.tab-multiselect-controls');
        if (controls) controls.classList.remove('show');
    }

    exitMultiselect();
    if (section === 'status') renderStatus();
    else if (section === 'images') renderImages();
    else if (section === 'messages') renderMessages();
    else if (section === 'polls') renderPolls();
    else if (section === 'files') renderFiles();
}

function getItemsContainer(section) {
    if (section === 'status') return document.getElementById('statusGrid');
    else if (section === 'images') return document.getElementById('imagesGrid');
    else if (section === 'messages') return document.getElementById('messagesList');
    else if (section === 'polls') return document.getElementById('pollsList');
    else if (section === 'files') return document.getElementById('filesList');
    return null;
}

function exitMultiselect() {
    // Esconde controles de todas as abas
    document.querySelectorAll('.tab-multiselect-controls').forEach(c => c.classList.remove('show'));

    STATE.multiselect.active = false;
    STATE.multiselect.section = null;

    // Re-render para remover modo multiselect visual
    const activeTab = document.querySelector('.tab-btn.active')?.dataset.tab;
    if (activeTab === 'status') renderStatus();
    else if (activeTab === 'images') renderImages();
    else if (activeTab === 'messages') renderMessages();
    else if (activeTab === 'polls') renderPolls();
    else if (activeTab === 'files') renderFiles();
}

/* =========================================================
   EDITORS
   ========================================================= */
function openEditor(section, idx) {
    console.log('openEditor:', section, idx);
    STATE.editingIndex = idx;
    try {
        if (section === 'images') openEditImage(idx);
        else if (section === 'messages') openEditMessage(idx);
        else if (section === 'polls') openEditPoll(idx);
        else if (section === 'files') openEditFile(idx);
        else if (section === 'status') openEditStatus(idx);
    } catch (e) {
        console.error('Erro ao abrir editor:', e);
        log('error', 'Erro ao abrir editor: ' + e.message);
    }
}

function openEditStatus(idx) {
    const item = STATE.statusItems[idx];
    if (!item) return;
    document.getElementById('editStatusTitle').textContent = `Editar Status: ${item.type.toUpperCase()}`;

    const preview = document.getElementById('editStatusPreview');
    if ((item.type === 'image' || item.type === 'video') && item.path) {
        preview.innerHTML = `<div class="modal-preview-container">
            ${item.type === 'video' 
                ? `<video id="editStatusVidPreview" src="${item.path}" controls></video>`
                : `<img id="editStatusImgPreview" src="${item.path}">`
            }
        </div>`;
    } else {
        preview.innerHTML = '';
    }

    document.getElementById('editStatusTextGroup').style.display = item.type === 'text' ? 'block' : 'none';
    document.getElementById('editStatusCaptionGroup').style.display = item.type !== 'text' ? 'block' : 'none';

    if (item.type === 'text') {
        document.getElementById('editStatusMessage').value = item.message || '';
    } else {
        const capEl = document.getElementById('editStatusCaption');
        capEl.value = item.caption || '';
        handleAutoExpand(capEl);
    }

    const scheduleText = formatScheduleText(item.schedule);
    const displayEl = document.getElementById('editStatusScheduleDisplay');
    if (displayEl) displayEl.innerHTML = scheduleText;

    populateDevicePicker('editStatus', item.device_ids || []);

    openModal('editStatusModal');
}
async function saveEditStatus() {
    const idx = STATE.editingIndex;
    const item = STATE.statusItems[idx];
    if (!item) return;

    const deviceIds = getSelectedDeviceIds('editStatus');
    if (deviceIds.length === 0) {
        showDevicePickerAlert('editStatus');
        log('error', 'Selecione pelo menos um dispositivo de envio.');
        return;
    }
    item.device_ids = deviceIds;

    if (item.type === 'text') {
        item.message = document.getElementById('editStatusMessage').value.trim();
    } else {
        item.caption = document.getElementById('editStatusCaption').value.trim();
    }

    saveStatusFile();
    log('success', 'Status editado.');
    closeModal('editStatusModal');
    renderStatus();
}

function openEditImage(idx) {
    const item = STATE.imageItems[idx];
    if (!item) return;

    const preview = document.getElementById('editImagePreview');
    const path = item.base64 || item.path || '';
    if (path) {
        preview.innerHTML = `<div class="modal-preview-container"><img id="editImageImgPreview" src="${path}"></div>`;
    } else {
        preview.innerHTML = '';
    }

    const capEl = document.getElementById('editImageCaption');
    capEl.value = item.caption || '';
    handleAutoExpand(capEl);
    document.getElementById('editImageViewOnce').classList.toggle('on', !!item.view_once);
    document.getElementById('editImageForwarded').classList.toggle('on', !!item.is_forwarded);
    const editImageDurationValue = String(item.duration || 0);
    selectDuration('editImageDuration', editImageDurationValue, document.querySelector(`#editImageDurationPicker .duration-chip[data-value="${editImageDurationValue}"]`));
    const times = item.schedule?.times || [];
    const days = item.schedule?.days || [];
    const scheduleText = times.length > 0 || days.length > 0 
        ? CAL_ICON + ' ' + (days.join(', ') || 'Todos') + (times.length > 0 ? ' • ' + times.join(', ') : '')
        : 'Nenhum agendamento';
    const displayEl = document.getElementById('editImageScheduleDisplay');
    if (displayEl) displayEl.innerHTML = scheduleText;
    populateRecipientsContainer('editImageRecipients', item.recipients || []);
    populateDevicePicker('editImage', item.device_ids || []);
    openModal('editImageModal');
}

