        <div class="selected-chips">${recs.map(r => `<span class="selected-chip">${escapeHtml(r.phone + r.suffix)}</span>`).join('')}</div>`;
}

function openContactPickerForEdit(mode) {
    STATE.currentPickerRecipients = [...(STATE._editRecipients || [])];
    document.getElementById('contactPickerTitle').textContent = 'Editar Contatos';
    document.getElementById('contactSearch').value = '';
    renderSelectedChips();
    switchPickerTab('contacts', document.querySelector('#contactPickerModal .picker-tab[data-ptab="contacts"]'));
    loadContactsForPicker();
    // Callback especial: ao confirmar, atualiza STATE._editRecipients
    STATE._editPickerCallback = (recs) => {
        STATE._editRecipients = recs;
        renderEditRecipients(mode);
    };
    openModal('contactPickerModal');
}

/* =========================================================
   CONTACT PICKER
   ========================================================= */
function openContactPicker(mode) {
    console.log('openContactPicker chamado com mode:', mode);
    log('info', 'Abrindo seletor de contatos...');
    STATE.currentPickerMode = mode;
    STATE.currentPickerRecipients = [];
    STATE._editPickerCallback = null;

    const titleEl = document.getElementById('contactPickerTitle');
    const searchEl = document.getElementById('contactSearch');
    const modalEl = document.getElementById('contactPickerModal');

    console.log('Elementos:', { title: !!titleEl, search: !!searchEl, modal: !!modalEl });

    if (titleEl) titleEl.textContent = 'Selecionar Contatos';
    if (searchEl) searchEl.value = '';

    renderSelectedChips();

    const tabEl = document.querySelector('#contactPickerModal .picker-tab[data-ptab="contacts"]');
    console.log('Tab encontrado:', !!tabEl);
    switchPickerTab('contacts', tabEl);

    // Abre o modal PRIMEIRO (antes de carregar contatos)
    openModal('contactPickerModal');

    // Depois carrega contatos em background
    loadContactsForPicker();
}

async function loadContactsForPicker() {
    const devices = getSelectedDevices();
    STATE.contacts = { contacts: [], groups: [], recent: [] };
    if (devices.length === 0) {
        log('warn', 'Selecione um dispositivo para carregar contatos.');
    } else {
        const deviceId = devices[0].id;
        log('info', 'Carregando contatos...');

        // Carregar contatos
        try {
            const res = await apiRequest('/user/my/contacts?filter=all', 'GET', undefined, deviceId);
            if (res && res.ok && res.data) {
                // Estrutura: { code, message, results: { data: [{jid, name}, ...] } }
                let raw = [];
                if (res.data.results && Array.isArray(res.data.results.data)) {
                    raw = res.data.results.data;
                } else if (Array.isArray(res.data)) {
                    raw = res.data;
                }
                STATE.contacts.contacts = raw.map(c => ({
                    phone: (c.jid || c.id || '').replace(/@s\.whatsapp\.net$/, '') + '@s.whatsapp.net',
                    name: c.name || c.pushName || c.notify || c.id || c.jid || 'Contato'
                })).sort((a, b) => (a.name || '').localeCompare(b.name || '', 'pt-BR', { sensitivity: 'base' }));
                log('success', `${STATE.contacts.contacts.length} contatos carregados.`);
            } else {
                log('warn', `Falha contatos: ${JSON.stringify(res?.data || res)}`);
            }
        } catch(e) {
            log('error', 'Erro contatos: ' + e.message);
        }

        // Carregar grupos (endpoint separado)
        try {
            const gres = await apiRequest('/user/my/groups', 'GET', undefined, deviceId);
            if (gres && gres.ok && gres.data) {
                let raw = [];
                if (gres.data.results && Array.isArray(gres.data.results.data)) {
                    raw = gres.data.results.data;
                } else if (Array.isArray(gres.data)) {
                    raw = gres.data;
                }
                STATE.contacts.groups = raw.map(g => ({
                    phone: g.JID || g.jid || g.id || '',
                    name: g.Name || g.name || g.subject || g.JID || 'Grupo',
                    isGroup: true
                })).sort((a, b) => (a.name || '').localeCompare(b.name || '', 'pt-BR', { sensitivity: 'base' }));
                log('success', `${STATE.contacts.groups.length} grupos carregados.`);
            } else {
                log('warn', `Falha grupos: ${JSON.stringify(gres?.data || gres)}`);
            }
        } catch(e) {
            log('error', 'Erro grupos: ' + e.message);
        }
    }
    // Recentes do histórico
        const histData = readFileSafe(FILE_PATHS.history);
    if (histData && Array.isArray(histData)) {
        const recent = new Map();
        histData.slice().reverse().forEach(h => {
            if (h.target && !recent.has(h.target) && h.target !== 'status@broadcast') {
                recent.set(h.target, { phone: h.target, name: h.target.split('@')[0], isRecent: true });
            }
        });
        STATE.contacts.recent = Array.from(recent.values()).sort((a, b) => (a.name || '').localeCompare(b.name || '', 'pt-BR', { sensitivity: 'base' })).slice(0, 100);
    }
    renderContactList('contacts');
}

function switchPickerTab(tab, el) {
    document.querySelectorAll('#contactPickerModal .picker-tab').forEach(t => t.classList.remove('active'));
    if (el) el.classList.add('active');
    if (tab === 'manual') {
        document.getElementById('contactList').style.display = 'none';
        document.getElementById('manualInputContainer').style.display = 'block';
    } else {
        document.getElementById('contactList').style.display = 'block';
        document.getElementById('manualInputContainer').style.display = 'none';
        renderContactList(tab);
    }
}

function filterContacts() {
    const active = document.querySelector('#contactPickerModal .picker-tab.active')?.dataset.ptab || 'contacts';
    renderContactList(active);
}

function renderContactList(filter) {
    const q = (document.getElementById('contactSearch').value || '').toLowerCase();
    let list = [];
    if (filter === 'groups') list = STATE.contacts.groups || [];
    else if (filter === 'recent') list = STATE.contacts.recent || [];
    else list = STATE.contacts.contacts || [];
    if (q) list = list.filter(c => (c.name||'').toLowerCase().includes(q) || (c.phone||'').toLowerCase().includes(q));
    const container = document.getElementById('contactList');
    if (list.length === 0) { container.innerHTML = '<div class="empty-state">Nenhum contato.</div>'; return; }
    container.innerHTML = list.map(c => {
        const phone = c.phone || '';
        const isSelected = STATE.currentPickerRecipients.some(r => r.phone === phone);
        const initial = (c.name || 'C').charAt(0).toUpperCase();

        // Determina o tipo baseado no sufixo
        const suffix = phone.includes('@') ? phone.split('@')[1] : '';
        const typeLabel = suffix === 'g.us' ? ' • Grupo' : suffix === 'lid' ? ' • LID' : suffix === 's.whatsapp.net' ? ' • Usuário' : '';
        const cleanPhone = phone.replace(/@.*$/, '');

        return `
            <div class="contact-item ${isSelected ? 'selected' : ''}" onclick="toggleContact('${escapeHtml(phone)}', '${escapeHtml(c.name || '')}')">
                <div class="contact-avatar">${initial}</div>
                <div class="contact-info">
                    <div class="contact-name">${escapeHtml(c.name || cleanPhone)}</div>
                    <div class="contact-phone">${escapeHtml(cleanPhone)}${typeLabel}</div>
                </div>
            </div>
        `;
    }).join('');
}

function setSuffix(suffix, el) {
    STATE.currentSuffix = suffix;
    document.querySelectorAll('.suffix-chip').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
}

function toggleContact(phone, name) {
    // Remove qualquer sufixo existente antes de adicionar o novo
    let cleanPhone = phone.replace(/@s\.whatsapp\.net|@g\.us|@lid/g, '');
    const fullPhone = cleanPhone + STATE.currentSuffix;

    const idx = STATE.currentPickerRecipients.findIndex(r => r.phone === fullPhone);
    if (idx >= 0) STATE.currentPickerRecipients.splice(idx, 1);
    else STATE.currentPickerRecipients.push({ phone: fullPhone, name });
    renderSelectedChips();
    const active = document.querySelector('#contactPickerModal .picker-tab.active')?.dataset.ptab || 'contacts';
    renderContactList(active);
}

/* ====== RECIPIENTES INLINE ====== */
let recipientBoxCounter = 0;

function addRecipientBox(containerId, phone = '', suffix = '@s.whatsapp.net', name = '') {
    const container = document.getElementById(containerId);
    if (!container) return;

    const boxId = 'rb_' + (++recipientBoxCounter);
    const cleanPhone = phone.replace(/@s\.whatsapp\.net|@g\.us|@lid/g, '');

    const box = document.createElement('div');
    box.className = 'recipient-box';
    box.id = boxId;
    box.innerHTML = `
        <input type="text" class="recipient-phone" placeholder="ex: 5581..." value="${escapeHtml(cleanPhone)}">
        <div class="suffix-selector">
            <button class="suffix-selector-btn" onclick="toggleSuffixDropdown('${boxId}')">${getSuffixLabel(suffix)}</button>
            <div class="suffix-dropdown" id="dropdown_${boxId}">
                <div class="suffix-option ${suffix === '@s.whatsapp.net' ? 'active' : ''}" onclick="selectSuffixForBox('${boxId}', '@s.whatsapp.net')">
                    <span>👤 Usuário</span>
                    <div class="suffix-radio"></div>
                </div>
                <div class="suffix-option ${suffix === '@g.us' ? 'active' : ''}" onclick="selectSuffixForBox('${boxId}', '@g.us')">
                    <span>👥 Grupo</span>
                    <div class="suffix-radio"></div>
                </div>
                <div class="suffix-option ${suffix === '@lid' ? 'active' : ''}" onclick="selectSuffixForBox('${boxId}', '@lid')">
                    <span>🆔 LID</span>
                    <div class="suffix-radio"></div>
                </div>
            </div>
        </div>
        <button class="recipient-search-btn" onclick="openQuickSearch('${boxId}')" title="Buscar">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0016 9.5 6.5 6.5 0 109.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/></svg>
        </button>
        <button class="recipient-remove-btn" onclick="removeRecipientBox('${boxId}')">×</button>
    `;

    container.appendChild(box);
}

function removeRecipientBox(boxId) {
    const box = document.getElementById(boxId);
    if (box) box.remove();
}

function toggleSuffixDropdown(boxId) {
    const dropdown = document.getElementById('dropdown_' + boxId);
    if (!dropdown) return;

    // Fecha todos os outros dropdowns
    document.querySelectorAll('.suffix-dropdown').forEach(d => {
        if (d.id !== 'dropdown_' + boxId) d.classList.remove('show');
    });

    if (!dropdown.classList.contains('show')) {
        const box = document.getElementById(boxId);
        const btn = box ? box.querySelector('.suffix-selector-btn') : null;
        if (btn) {
            const rect = btn.getBoundingClientRect();
            dropdown.style.top = (rect.bottom + 4) + "px";
            dropdown.style.left = rect.left + "px";
        }
        dropdown.classList.add('show');
    } else {
        dropdown.classList.remove('show');
    }
}

function selectSuffixForBox(boxId, suffix) {
    const box = document.getElementById(boxId);
    if (!box) return;

    const btn = box.querySelector('.suffix-selector-btn');
    if (btn) btn.textContent = getSuffixLabel(suffix);

    const dropdown = document.getElementById('dropdown_' + boxId);
    if (dropdown) {
        dropdown.querySelectorAll('.suffix-option').forEach(opt => {
            opt.classList.remove('active');
        });
        const selected = Array.from(dropdown.querySelectorAll('.suffix-option')).find(opt => 
            opt.textContent.includes(suffix === '@s.whatsapp.net' ? 'Usuário' : suffix === '@g.us' ? 'Grupo' : 'LID')
        );
        if (selected) selected.classList.add('active');
        dropdown.classList.remove('show');
    }
}

function getSuffixLabel(suffix) {
    const labels = {
        '@s.whatsapp.net': '👤 Usuário',
        '@g.us': '👥 Grupo',
        '@lid': '🆔 LID'
    };
    return labels[suffix] || suffix;
}

function getSuffixFromBox(boxId) {
    const box = document.getElementById(boxId);
    if (!box) return '@s.whatsapp.net';

    const btn = box.querySelector('.suffix-selector-btn');
    const text = btn ? btn.textContent : '';

    if (text.includes('Grupo')) return '@g.us';
    if (text.includes('LID')) return '@lid';
    return '@s.whatsapp.net';
}

function collectRecipientsFromContainer(containerId) {
    const container = document.getElementById(containerId);
    if (!container) return [];

    const recipients = [];
    container.querySelectorAll('.recipient-box').forEach(box => {
        const phoneInput = box.querySelector('.recipient-phone');
        const phone = phoneInput ? phoneInput.value.trim() : '';
        if (phone) {
            const cleanPhone = phone.replace(/@s\.whatsapp\.net|@g\.us|@lid/g, '');
            const suffix = getSuffixFromBox(box.id);
            recipients.push({ phone: cleanPhone, suffix });
        }
    });

    return recipients;
}

function populateRecipientsContainer(containerId, recipients) {
    const container = document.getElementById(containerId);
    if (!container) return;

    container.innerHTML = '';

    if (recipients && recipients.length > 0) {
        recipients.forEach(r => {
            addRecipientBox(containerId, r.phone + r.suffix, r.suffix, r.name || '');
        });
    } else {
        addRecipientBox(containerId, '', '@s.whatsapp.net');
    }
}

/* ====== BUSCA RÁPIDA ====== */
let quickSearchTargetBoxId = null;
let quickSearchSuffix = '@s.whatsapp.net';

function openQuickSearch(boxId) {
    quickSearchTargetBoxId = boxId;
    quickSearchSuffix = getSuffixFromBox(boxId);

    // Atualiza chips de sufixo
    document.querySelectorAll('#quickSearchSuffixPicker .suffix-chip').forEach(chip => {
        chip.classList.toggle('active', chip.dataset.suffix === quickSearchSuffix);
    });

    document.getElementById('quickSearchInput').value = '';

    openModal('quickSearchModal');

    // Foca no input
    setTimeout(() => document.getElementById('quickSearchInput').focus(), 100);

    // Já carrega os contatos ao abrir
    loadQuickSearchContacts();
}

function setQuickSearchSuffix(suffix, el) {
    quickSearchSuffix = suffix;
    document.querySelectorAll('#quickSearchSuffixPicker .suffix-chip').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
    runQuickSearch(); // Re-executa a busca com o novo sufixo
}

async function loadRecentContacts() {
    const resultsDiv = document.getElementById('quickSearchResults');
    resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem;">Carregando...</div>';

    // Carrega do arquivo de histórico
    const histData = readFileSafe(FILE_PATHS.history);
    const recent = new Map();

    if (histData && Array.isArray(histData)) {
        histData.slice().reverse().forEach(h => {
            if (h.target && !recent.has(h.target) && h.target !== 'status@broadcast') {
                recent.set(h.target, { 
                    phone: h.target, 
                    name: h.target.split('@')[0],
                    isRecent: true 
                });
            }
        });
    }

    const recentList = Array.from(recent.values());
    STATE.contacts.recent = recentList;

    if (recentList.length === 0) {
        resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem; color:var(--text-dim);">Nenhum contato recente</div>';
        return;
    }

    displayQuickSearchResults(recentList);
}

async function loadQuickSearchContacts() {
    const resultsDiv = document.getElementById('quickSearchResults');

    if (quickSearchSuffix === 'recent') {
        await loadRecentContacts();
        return;
    }

    resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem;">Carregando...</div>';

    if (quickSearchSuffix === '@g.us') {
        // Carrega apenas grupos
        const groupsList = STATE.contacts.groups || [];
        if (groupsList.length === 0) {
            await loadContactsForPicker();
            const groups = STATE.contacts.groups || [];
            if (groups.length === 0) {
                resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem; color:var(--text-dim);">Nenhum grupo encontrado</div>';
                return;
            }
            displayQuickSearchResults(groups);
            return;
        }
        displayQuickSearchResults(groupsList);
        return;
    }

    // Para @s.whatsapp.net e @lid, carrega usuários
    const usersList = STATE.contacts.contacts || [];
    if (usersList.length === 0) {
        await loadContactsForPicker();
        const users = STATE.contacts.contacts || [];
        if (users.length === 0) {
            resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem; color:var(--text-dim);">Nenhum contato encontrado</div>';
            return;
        }
        displayQuickSearchResults(users);
        return;
    }

    displayQuickSearchResults(usersList);
}

async function runQuickSearch() {
    const query = document.getElementById('quickSearchInput').value.trim().toLowerCase();
    const resultsDiv = document.getElementById('quickSearchResults');

    if (quickSearchSuffix === 'recent') {
        const recentList = STATE.contacts.recent || [];
        const filtered = recentList.filter(c => {
            const name = (c.name || '').toLowerCase();
            const phone = (c.phone || '').toLowerCase();
            return name.includes(query) || phone.includes(query);
        });
        displayQuickSearchResults(filtered.length > 0 ? filtered : recentList);
        return;
    }

    if (quickSearchSuffix === '@g.us') {
        // Mostra apenas grupos
        const groupsList = STATE.contacts.groups || [];
        const filtered = groupsList.filter(c => {
            const name = (c.name || '').toLowerCase();
            const phone = (c.phone || '').toLowerCase();
            return name.includes(query) || phone.includes(query);
        });
        displayQuickSearchResults(filtered.length > 0 ? filtered : groupsList);
        return;
    }

    // Para @s.whatsapp.net e @lid, mostra apenas usuários
    const usersList = STATE.contacts.contacts || [];
    const filtered = usersList.filter(c => {
        const name = (c.name || '').toLowerCase();
        const phone = (c.phone || '').toLowerCase();
        return name.includes(query) || phone.includes(query);
    });

    displayQuickSearchResults(filtered.length > 0 ? filtered : usersList);
}

function displayQuickSearchResults(contacts) {
    const resultsDiv = document.getElementById('quickSearchResults');

    if (contacts.length === 0) {
        resultsDiv.innerHTML = '<div style="text-align:center; padding:1rem; color:var(--text-dim);">Nenhum contato encontrado</div>';
        return;
    }

    resultsDiv.innerHTML = contacts.map(c => {
        const cleanPhone = (c.phone || '').replace(/@s\.whatsapp\.net|@g\.us|@lid/g, '');
        const name = c.name || cleanPhone;
        const originalPhone = c.phone || '';
        const suffix = originalPhone.includes('@') ? originalPhone.split('@')[1] : '';
        const typeLabel = suffix === 'g.us' ? ' • Grupo' : suffix === 'lid' ? ' • LID' : suffix === 's.whatsapp.net' ? ' • Usuário' : '';
        return `
            <div class="search-result-item" onclick="selectQuickSearchResult('${escapeHtml(cleanPhone)}', '${escapeHtml(name)}', '${escapeHtml(originalPhone)}')">
                <div class="search-result-name">${escapeHtml(name)}</div>
                <div class="search-result-phone">${escapeHtml(cleanPhone)}${typeLabel}</div>
            </div>
        `;
    }).join('');
}

function selectQuickSearchResult(phone, name, originalPhone = '') {
    if (!quickSearchTargetBoxId) return;

    const box = document.getElementById(quickSearchTargetBoxId);
    if (!box) return;

    const phoneInput = box.querySelector('.recipient-phone');
    if (phoneInput) phoneInput.value = phone;

    // Se o sufixo é "recent", detecta o tipo baseado no originalPhone
    let newSuffix = quickSearchSuffix;
    if (quickSearchSuffix === 'recent' && originalPhone) {
        if (originalPhone.includes('@g.us')) {
            newSuffix = '@g.us';
        } else if (originalPhone.includes('@lid')) {
            newSuffix = '@lid';
        } else {
            newSuffix = '@s.whatsapp.net';
        }
    }

    selectSuffixForBox(quickSearchTargetBoxId, newSuffix);

    closeModal('quickSearchModal');
}

/* ====== MODAL DE AGENDAMENTO ====== */
let scheduleItemIndex = -1;
let scheduleItemType = '';

function openScheduleModal(section, idx) {
    scheduleItemIndex = idx;
    scheduleItemType = section;

    clearScheduleAlert();

    let item;
    if (section === 'status') item = STATE.statusItems[idx];
    else if (section === 'images') item = STATE.imageItems[idx];
    else if (section === 'messages') item = STATE.messageItems[idx];
    else if (section === 'polls') item = STATE.pollItems[idx];
    else if (section === 'files') item = STATE.fileItems[idx];

    if (!item) return;

    // Carrega dias selecionados
    const selectedDays = item.schedule?.days || [];
    document.querySelectorAll('#scheduleDaysGrid .day-chip').forEach(chip => {
        if (selectedDays.includes(chip.dataset.day)) {
            chip.classList.add('active');
        } else {
            chip.classList.remove('active');
        }
    });

    // Carrega horários
    const timesList = document.getElementById('scheduleTimesList');
    timesList.innerHTML = '';
    const times = item.schedule?.times || [];
    times.forEach(time => addScheduleTime(time));

    openModal('scheduleModal');
}

function toggleDayChip(el) {
    el.classList.toggle('active');
    clearScheduleAlert();
}

function addScheduleTime(defaultTime = '') {
    const timesList = document.getElementById('scheduleTimesList');
    const div = document.createElement('div');
    div.className = 'time-item';
    div.innerHTML = `
        <input type="time" value="${defaultTime}" style="flex:1;" onchange="clearScheduleAlert()">
        <button class="time-remove" onclick="this.parentElement.remove(); clearScheduleAlert();">×</button>
    `;
    timesList.appendChild(div);
    clearScheduleAlert();
}

function onScheduleDayClick(chip) {
    chip.classList.toggle('active');
    clearScheduleAlert();
}

function showScheduleAlert(message, type = 'error') {
    const alert = document.getElementById('scheduleAlert');
    const alertText = document.getElementById('scheduleAlertText');
    if (!alert || !alertText) return;
    alertText.textContent = message;
    alert.className = 'schedule-alert' + (type === 'success' ? ' success' : '');
    alert.style.display = 'flex';
}

function clearScheduleAlert() {
    const alert = document.getElementById('scheduleAlert');
    if (alert) alert.style.display = 'none';
}

function saveSchedule() {
    const days = Array.from(document.querySelectorAll('#scheduleDaysGrid .day-chip.active'))
        .map(chip => chip.dataset.day);

    const times = Array.from(document.querySelectorAll('#scheduleTimesList input[type="time"]'))
        .map(input => input.value)
        .filter(v => v);

    if (days.length > 0 && times.length === 0) {
        const msg = '⚠️ Selecione pelo menos um horário quando marcar dias!';
        showScheduleAlert(msg, 'error');
        log('error', msg);
        return;
    }

    // Mapeamento de stateKey para cada tipo
    const stateMap = {
        status: '_pendingStatusSchedule',
        messages: '_pendingMessageSchedule',
        polls: '_pendingPollSchedule',
        images: '_pendingImageSchedule',
        files: '_pendingFileSchedule'
    };

    const previewMap = {
        status: 'addStatusSchedulePreview',
        messages: 'addMsgSchedulePreview',
        polls: 'addPollSchedulePreview',
        images: 'addImageSchedulePreview',
        files: 'addFileSchedulePreview'
    };

    if (scheduleItemIndex === -1 && stateMap[scheduleItemType]) {
        STATE[stateMap[scheduleItemType]] = { days, times };
        if (previewMap[scheduleItemType]) {
            updateAddSchedulePreview(previewMap[scheduleItemType], stateMap[scheduleItemType]);
        }
        showScheduleAlert('✓ Agendamento salvo com sucesso!', 'success');
        setTimeout(() => closeModal('scheduleModal'), 900);
        return;
    }

    let item;
    if (scheduleItemType === 'status') item = STATE.statusItems[scheduleItemIndex];
    else if (scheduleItemType === 'images') item = STATE.imageItems[scheduleItemIndex];
    else if (scheduleItemType === 'messages') item = STATE.messageItems[scheduleItemIndex];
    else if (scheduleItemType === 'polls') item = STATE.pollItems[scheduleItemIndex];
    else if (scheduleItemType === 'files') item = STATE.fileItems[scheduleItemIndex];

    if (!item) return;

    item.schedule = { days, times };

    const savers = {
        status: saveStatusFile,
        images: saveImagesFile,
        messages: saveMessagesFile,
        polls: savePollsFile,
        files: saveFilesFile
    };
    if (savers[scheduleItemType]) savers[scheduleItemType]();

    log('success', `Agendamento salvo para item ${scheduleItemIndex}`);
    updateScheduleDisplayInEditor();

    showScheduleAlert('✓ Agendamento salvo com sucesso!', 'success');
    setTimeout(() => closeModal('scheduleModal'), 900);

    if (scheduleItemType === 'status') renderStatus();
    else if (scheduleItemType === 'images') renderImages();
    else if (scheduleItemType === 'messages') renderMessages();
    else if (scheduleItemType === 'polls') renderPolls();
    else if (scheduleItemType === 'files') renderFiles();
}

function updateScheduleDisplayInEditor() {
    let item;
    if (scheduleItemType === 'status') item = STATE.statusItems[scheduleItemIndex];
    else if (scheduleItemType === 'images') item = STATE.imageItems[scheduleItemIndex];
    else if (scheduleItemType === 'messages') item = STATE.messageItems[scheduleItemIndex];
    else if (scheduleItemType === 'polls') item = STATE.pollItems[scheduleItemIndex];
    else if (scheduleItemType === 'files') item = STATE.fileItems[scheduleItemIndex];

    if (!item) return;

    const scheduleText = formatScheduleText(item.schedule);

    const displayMap = {
        images: 'editImageScheduleDisplay',
        messages: 'editMsgScheduleDisplay',
        polls: 'editPollScheduleDisplay',
        files: 'editFileScheduleDisplay',
        status: 'editStatusScheduleDisplay'
    };

    const displayId = displayMap[scheduleItemType];
    const displayEl = document.getElementById(displayId);
    if (displayEl) displayEl.innerHTML = scheduleText;
}

function openScheduleModalFromEditor(section, idx) {
    openScheduleModal(section, idx);
}

function renderSelectedChips() {
    document.getElementById('selectedChips').innerHTML = STATE.currentPickerRecipients.map(r =>
        `<span class="selected-chip">${escapeHtml(r.name || r.phone)} <span class="remove" onclick="toggleContact('${r.phone}', '${escapeHtml(r.name || '')}')">×</span></span>`
    ).join('');
}

function addManualContact() {
    const phone = document.getElementById('manualPhone').value.trim();
    if (!phone) return;
    const normalized = phone.includes('@') ? phone : phone + STATE.currentSuffix;
    toggleContact(normalized, phone);
    document.getElementById('manualPhone').value = '';
}

function confirmContactPicker() {
    if (STATE._editPickerCallback) {
        STATE._editPickerCallback([...STATE.currentPickerRecipients]);
    } else {
        renderRecipientsInForm(STATE.currentPickerMode, STATE.currentPickerRecipients);
    }
    closeModal('contactPickerModal');
}

function renderRecipientsInForm(mode, recipients) {
    const map = { image:'imageSelectedRecipients', message:'msgSelectedRecipients', poll:'pollSelectedRecipients', file:'fileSelectedRecipients' };
    const c = document.getElementById(map[mode]);
    if (!c) return;
    c.innerHTML = `<div style="font-size:0.6875rem; color:var(--text-dim); margin-top:0.375rem;">${recipients.length} destinatário(s)</div>
        <div class="selected-chips">${recipients.map(r => `<span class="selected-chip">${escapeHtml(r.name || r.phone)}</span>`).join('')}</div>`;
}

/* =========================================================
   HISTORY (por seção)
   ========================================================= */
async function addToHistory(entry) {
    const hist = readFileSafe(FILE_PATHS.history) || [];
    entry.id = 'hist-' + Date.now() + Math.floor(Math.random() * 1000);
    entry.timestamp = new Date().toISOString();
    hist.unshift(entry);
    writeFileSafe(FILE_PATHS.history, hist.slice(0, 500));
    STATE.history = hist.slice(0, 500);
}

function openHistory(section) {
    STATE.historySection = section;
    STATE.historyFilter = 'all';
    const titles = { status:'Status', images:'Imagens', messages:'Mensagens', polls:'Enquetes', files:'Arquivos' };
    document.getElementById('historyTitle').textContent = 'Histórico: ' + (titles[section] || section);
    document.querySelectorAll('#historyModal .chip').forEach(c => c.classList.remove('active'));
    document.querySelector('#historyModal .chip[data-hf="all"]').classList.add('active');
    renderHistory();
    openModal('historyModal');
}

function filterHistory(filter, el) {
    STATE.historyFilter = filter;
    document.querySelectorAll('#historyModal .chip').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
    renderHistory();
}

function renderHistory() {
    const list = STATE.history.filter(h => h.section === STATE.historySection);
    const filtered = STATE.historyFilter === 'all' ? list : list.filter(h => h.status === STATE.historyFilter);
    const container = document.getElementById('historyList');
    if (filtered.length === 0) { container.innerHTML = '<div class="empty-state">Sem histórico.</div>'; return; }
    container.innerHTML = filtered.map(h => {
        const time = h.timestamp ? new Date(h.timestamp).toLocaleString('pt-BR') : '';
        return `
            <div class="history-item ${h.status || 'error'}">
                <div><span class="h-time">${time}</span><span class="h-status">${(h.status||'').toUpperCase()}</span></div>
                <div class="h-target">${escapeHtml(h.target || (h.targets||[]).join(', ') || '')}</div>
                <div class="h-detail">${escapeHtml(h.detail || h.question || '')}</div>
            </div>
        `;
    }).join('');
}

async function clearHistoryCurrentSection() {
    const ok = await askConfirm(`Limpar todo o histórico de ${STATE.historySection}?`);
    if (!ok) return;
    STATE.history = STATE.history.filter(h => h.section !== STATE.historySection);
    writeFileSafe(FILE_PATHS.history, STATE.history);
    renderHistory();
    log('success', `Histórico de ${STATE.historySection} limpo.`);
}

async function clearHistoryErrors() {
    const ok = await askConfirm('Limpar apenas os erros?');
    if (!ok) return;
    STATE.history = STATE.history.filter(h => !(h.section === STATE.historySection && h.status === 'error'));
    writeFileSafe(FILE_PATHS.history, STATE.history);
    renderHistory();
    log('success', 'Erros limpos.');
}

/* =========================================================
   SAVE FILES
   ========================================================= */
function saveStatusFile() {
    const items = STATE.statusItems.map(i => {
        const out = {
            type: i.type, schedule: i.schedule,
            device_ids: normalizeDeviceIds(i.device_ids || [])
        };
        if (i.caption) out.caption = i.caption;
        if (i.message !== undefined) out.message = i.message;
        if (i.path) out.path = i.path;
        return out;
    });
    writeFileSafe(FILE_PATHS.status, {
        devices: getSelectedDevices().map(d => ({ device_id: d.id, device_phone: d.phone.replace(/@s\.whatsapp\.net$/, '') })),
        items
    });
}

function saveImagesFile() {
    const items = STATE.imageItems.map(i => {
        const out = {
            recipients: i.recipients, type: i.type, caption: i.caption||'', is_forwarded: i.is_forwarded,
            view_once: i.view_once, duration: i.duration, schedule: i.schedule,
            device_ids: normalizeDeviceIds(i.device_ids || [])
        };
        if (i.path) out.path = i.path;
        return out;
    });
    writeFileSafe(FILE_PATHS.images, {
        devices: getSelectedDevices().map(d => ({ device_id: d.id, device_phone: d.phone.replace(/@s\.whatsapp\.net$/, '') })),
        items
    });
}

function saveMessagesFile() {
    writeFileSafe(FILE_PATHS.messages, {
        devices: getSelectedDevices().map(d => ({ device_id: d.id, device_phone: d.phone.replace(/@s\.whatsapp\.net$/, '') })),
        items: STATE.messageItems.map(i => ({
            recipients: i.recipients, message: i.message, is_forwarded: i.is_forwarded,
            duration: i.duration, type: i.type, schedule: i.schedule,
            device_ids: normalizeDeviceIds(i.device_ids || [])
        }))
    });
}

function savePollsFile() {
    writeFileSafe(FILE_PATHS.polls, {
        devices: getSelectedDevices().map(d => ({ device_id: d.id, device_phone: d.phone.replace(/@s\.whatsapp\.net$/, '') })),
        items: STATE.pollItems.map(i => ({
            recipients: i.recipients, question: i.question, options: i.options,
            max_answer: i.max_answer, type: i.type, schedule: i.schedule,
            device_ids: normalizeDeviceIds(i.device_ids || [])
        }))
    });
}

function saveFilesFile() {
    writeFileSafe(FILE_PATHS.files, {
        devices: getSelectedDevices().map(d => ({ device_id: d.id, device_phone: d.phone.replace(/@s\.whatsapp\.net$/, '') })),
        items: STATE.fileItems.map(i => ({
            recipients: i.recipients, path: i.path, caption: i.caption||'',
            is_forwarded: i.is_forwarded, type: i.type, schedule: i.schedule,
            device_ids: normalizeDeviceIds(i.device_ids || [])
        }))
    });
}

/* =========================================================
   HELPERS & MODALS
   ========================================================= */
function toggleSwitch(el) { el.classList.toggle('on'); }

function formatDuration(s) {
    if (!s || s === 0) return 'Permanente';
    if (s === 86400) return '24 horas';
    if (s === 604800) return '7 dias';
    if (s === 7776000) return '90 dias';
    return Math.round(s/3600) + 'h';
}

function escapeForJson(str) {
    return String(str).replace(/\\/g,'\\\\').replace(/"/g,'\\"').replace(/\n/g,'\\n').replace(/\r/g,'\\r').replace(/\t/g,'\\t');
}

let modalZIndex = 200;

function openModal(id) {
    modalZIndex += 10;
    const el = document.getElementById(id);
    if (!el) { console.error('Modal não encontrado:', id); return; }
    el.style.zIndex = modalZIndex;
    el.classList.add('show');
    console.log('Modal aberto:', id, 'z-index:', modalZIndex);
}

function closeModal(id) {
    const el = document.getElementById(id);
    if (!el) return;
    el.classList.remove('show');
    modalZIndex = Math.max(200, modalZIndex - 10);

    // Para todos os vídeos e áudios dentro do modal ao fechar
    const mediaElements = el.querySelectorAll('video, audio');
    mediaElements.forEach(media => {
        media.pause();
        media.currentTime = 0;
    });

    // Fecha todos os dropdowns de sufixo ao fechar o modal
    document.querySelectorAll('.suffix-dropdown.show').forEach(d => d.classList.remove('show'));
}

function askConfirm(message) {
    return new Promise(resolve => {
        document.getElementById('confirmMessage').textContent = message;
        window.confirmCallback = resolve;
        openModal('confirmModal');
    });
}

document.querySelectorAll('.modal-overlay').forEach(ov => {
    ov.addEventListener('click', e => { if (e.target === ov) closeModal(ov.id); });
});

/* =========================================================
   INIT
   ========================================================= */
/* Lê arquivo JSON do Tasker (formato: { devices, items }) e retorna apenas o array de items */
function loadItemsFromFile(filePath) {
    try {
        const data = readFileSafe(filePath);
        if (data && typeof data === 'object' && Array.isArray(data.items)) {
            // Normaliza device_ids de todos os itens
            return data.items.map(item => ({
                ...item,
                device_ids: normalizeDeviceIds(item.device_ids || [])
            }));
        }
        // Suporte ao formato antigo (array direto)
        if (Array.isArray(data)) {
            return data.map(item => ({
                ...item,
                device_ids: normalizeDeviceIds(item.device_ids || [])
            }));
        }
    } catch (e) {
        log('error', 'Erro ao ler arquivo: ' + filePath + ' - ' + e.message);
    }
    return [];
}

async function init() {
    await loadDevices();

    // Carregar itens DOS ARQUIVOS (não das variáveis fixas)
    const statusItemsRaw = loadItemsFromFile(FILE_PATHS.status);
    STATE.statusItems = statusItemsRaw.map((it, i) => ({
        ...it,
        id: 'st-' + i,
        selected: false,
        base64: null
    }));

    const imageItemsRaw = loadItemsFromFile(FILE_PATHS.images);
    STATE.imageItems = imageItemsRaw.map((it, i) => ({
        ...it,
        id: 'img-' + i,
        selected: false,
        base64: null
    }));

    const messageItemsRaw = loadItemsFromFile(FILE_PATHS.messages);
    STATE.messageItems = messageItemsRaw.map((it, i) => ({
        ...it,
        id: 'msg-' + i,
        selected: false
    }));

    const pollItemsRaw = loadItemsFromFile(FILE_PATHS.polls);
    STATE.pollItems = pollItemsRaw.map((it, i) => ({
        ...it,
        id: 'poll-' + i,
        selected: false
    }));

    const fileItemsRaw = loadItemsFromFile(FILE_PATHS.files);
    STATE.fileItems = fileItemsRaw.map((it, i) => ({
        ...it,
        id: 'file-' + i,
        selected: false
    }));

    // Histórico: lido do arquivo
    STATE.history = readFileSafe(FILE_PATHS.history) || [];

    renderStatus();
    renderImages();
    renderMessages();
    renderPolls();
    renderFiles();

    updateSendButtonsVisibility('status');
    updateSendButtonsVisibility('images');
    updateSendButtonsVisibility('messages');
    updateSendButtonsVisibility('polls');
    updateSendButtonsVisibility('files');
    updateSendTypesVisibility();

    log('success', `Sistema inicializado: ${STATE.statusItems.length} status, ${STATE.imageItems.length} imagens, ${STATE.messageItems.length} mensagens, ${STATE.pollItems.length} enquetes, ${STATE.fileItems.length} arquivos.`);
}

/* =========================================================
   AUTO-EXPAND TEXTAREAS
   ========================================================= */
function handleAutoExpand(el) {
    if (!el.classList.contains('auto-expand')) return;

    // Reseta altura para calcular o scrollHeight real
    el.style.height = 'auto';

    // Limite de 10 linhas: line-height (1.5) * font-size (14px) * 10
    const maxHeight = 1.5 * 14 * 10; 
    const currentScrollHeight = el.scrollHeight;

    if (currentScrollHeight > maxHeight) {
        el.style.height = maxHeight + 'px';
        el.style.overflowY = 'auto';
    } else {
        el.style.height = currentScrollHeight + 'px';
        el.style.overflowY = 'hidden';
    }
}

document.addEventListener('input', function (event) {
    if (event.target.tagName.toLowerCase() !== 'textarea') return;
    handleAutoExpand(event.target);
});

// Inicializa no foco também para garantir o tamanho correto ao abrir modal
document.addEventListener('focusin', function (event) {
    if (event.target.tagName.toLowerCase() !== 'textarea') return;
    handleAutoExpand(event.target);
});

