String readFileContent(String filePath) throws JavaCodeException {
    File file = new File(filePath);
    if (!file.exists()) {
        throw new JavaCodeException("File not found: " + filePath);
    }
    if (!file.canRead()) {
        throw new JavaCodeException("Cannot read file: " + filePath);
    }

    StringBuilder sb = new StringBuilder();
    BufferedReader br = null;
    try {
        br = new BufferedReader(new FileReader(file));
        String line;
        while ((line = br.readLine()) != null) {
            sb.append(line).append("\n");
        }
    } catch (Exception e) {
        throw new JavaCodeException("Error reading file " + filePath + ": " + e.getMessage());
    } finally {
        if (br != null) {
            try {
                br.close();
            } catch (Exception e) {
                System.err.println("Error closing reader for " + filePath + ": " + e.getMessage());
            }
        }
    }

    String content = sb.toString();
    while (content.endsWith("\n")) {
        content = content.substring(0, content.length() - 1);
    }
    return content;
}

void writeFileContent(String filePath, String content) throws JavaCodeException {
    FileWriter writer = null;
    try {
        writer = new FileWriter(filePath);
        writer.write(content);
    } catch (Exception e) {
        throw new JavaCodeException("Error writing file " + filePath + ": " + e.getMessage());
    } finally {
        if (writer != null) {
            try {
                writer.close();
            } catch (Exception e) {
                System.err.println("Error closing writer for " + filePath + ": " + e.getMessage());
            }
        }
    }
}

String getCurrentDayOfWeek() {
    Calendar calendar = Calendar.getInstance();
    int dayOfWeek = calendar.get(Calendar.DAY_OF_WEEK);
    String[] days = new String[]{"Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sab"};
    return days[dayOfWeek - 1];
}

boolean isTimeDue(String scheduledTimeStr, String currentTimeStr) {
    try {
        SimpleDateFormat sdf = new SimpleDateFormat("HH:mm");
        java.util.Date scheduledTime = sdf.parse(scheduledTimeStr);
        java.util.Date currentTime = sdf.parse(currentTimeStr);
        return currentTime.compareTo(scheduledTime) >= 0;
    } catch (java.text.ParseException e) {
        return false;
    }
}

boolean shouldSendItem(JSONObject schedule, String currentDay, String currentTime) {
    try {
        if (schedule == null) return false;

        if (!schedule.has("times") || !schedule.has("days")) return false;

        JSONArray times = schedule.getJSONArray("times");
        JSONArray days = schedule.getJSONArray("days");

        if (times.length() == 0 || days.length() == 0) return false;

        boolean dayMatch = false;
        for (int j = 0; j < days.length(); j++) {
            String day = days.getString(j);
            if (currentDay.equals(day)) {
                dayMatch = true;
                break;
            }
        }

        if (!dayMatch) return false;

        for (int j = 0; j < times.length(); j++) {
            String scheduledTime = times.getString(j);
            if (isTimeDue(scheduledTime, currentTime)) {
                return true;
            }
        }

        return false;

    } catch (org.json.JSONException e) {
        return false;
    }
}

String fileToBase64(String filePath) {
    File file = new File(filePath);
    if (!file.exists() || !file.canRead()) {
        return null;
    }

    FileInputStream fis = null;
    ByteArrayOutputStream bos = null;
    try {
        fis = new FileInputStream(file);
        bos = new ByteArrayOutputStream();
        byte[] buffer = new byte[8192];
        int bytesRead;
        while ((bytesRead = fis.read(buffer)) != -1) {
            bos.write(buffer, 0, bytesRead);
        }
        byte[] bytes = bos.toByteArray();
        return Base64.encodeToString(bytes, Base64.NO_WRAP);
    } catch (IOException e) {
        return null;
    } finally {
        try {
            if (fis != null) fis.close();
            if (bos != null) bos.close();
        } catch (IOException e) {}
    }
}

String sendHttpRequest(String url, String jsonBody, String deviceId) {
    OkHttpClient client = new OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build();

    MediaType JSON = MediaType.parse("application/json; charset=utf-8");
    RequestBody body = RequestBody.create(JSON, jsonBody);

    Request request = new Request.Builder()
        .url(url)
        .post(body)
        .addHeader("Accept", "application/json, text/plain, */*")
        .addHeader("Authorization", "Basic dXNlcjE6cGFzczE=")
        .addHeader("X-Device-Id", deviceId)
        .addHeader("Content-Type", "application/json")
        .build();

    Response response = null;
    try {
        response = client.newCall(request).execute();
        String responseBody = response.body().string();

        if (response.isSuccessful()) {
            return "SUCCESS";
        } else {
            return "ERROR: HTTP " + response.code();
        }
    } catch (IOException e) {
        return "ERROR: " + e.getMessage();
    } finally {
        if (response != null) {
            response.close();
        }
    }
}

String extractFileName(String path) {
    if (path == null) return "arquivo_desconhecido";
    int lastSeparator = path.lastIndexOf('/');
    if (lastSeparator >= 0 && lastSeparator < path.length() - 1) {
        return path.substring(lastSeparator + 1);
    }
    return "arquivo_" + path.hashCode();
}

String extractPhoneNumber(JSONObject item) {
    try {
        if (item.has("phone")) {
            String phone = item.getString("phone");
            if (phone != null && phone.trim().length() > 0) {
                return phone.trim();
            }
        }
    } catch (Exception e) {}
    return "sem_telefone";
}

String extractImagePath(JSONObject item) {
    try {
        if (item.has("path")) {
            return item.getString("path");
        }
    } catch (Exception e) {}
    return null;
}

String extractMessageText(JSONObject item) {
    try {
        if (item.has("message")) {
            String msg = item.getString("message");
            if (msg != null && msg.length() > 0) {
                return msg;
            }
        }
    } catch (Exception e) {}
    return "sem_mensagem";
}

String extractQuestionText(JSONObject item) {
    try {
        if (item.has("question")) {
            String q = item.getString("question");
            if (q != null && q.length() > 0) {
                return q;
            }
        }
    } catch (Exception e) {}
    return "sem_pergunta";
}

String extractType(JSONObject item) {
    try {
        if (item.has("type")) {
            return item.getString("type");
        }
    } catch (Exception e) {}

    if (item.has("question") && item.has("options")) {
        return "poll";
    }
    if (item.has("path")) {
        if (item.has("phone")) {
            return "image_message";
        }
        return "status_image";
    }
    if (item.has("message") && item.has("phone")) {
        return "message";
    }
    if (item.has("message")) {
        return "text";
    }

    return "desconhecido";
}

String generateItemKey(JSONObject item, String scheduledTime, String deviceId) {
    try {
        String type = extractType(item);
        StringBuilder key = new StringBuilder();

        if ("text".equals(type)) {
            String message = extractMessageText(item);
            key.append("text_").append(message.hashCode());

        } else if ("status_image".equals(type) || "image".equals(type)) {
            String path = item.getString("path");
            String fileName = extractFileName(path);
            key.append("status_img_").append(fileName.hashCode());

        } else if ("status_video".equals(type) || "video".equals(type)) {
            String path = item.getString("path");
            String fileName = extractFileName(path);
            key.append("status_vid_").append(fileName.hashCode());

        } else if ("message".equals(type)) {
            String phone = extractPhoneNumber(item);
            String message = extractMessageText(item);
            key.append("msg_").append(phone).append("_").append(message.hashCode());

        } else if ("image_message".equals(type) || "image".equals(type)) {
            String phone = extractPhoneNumber(item);
            String path = item.getString("path");
            String fileName = extractFileName(path);
            key.append("img_").append(phone).append("_").append(fileName.hashCode());

        } else if ("poll".equals(type)) {
            String phone = extractPhoneNumber(item);
            String question = extractQuestionText(item);
            key.append("poll_").append(phone).append("_").append(question.hashCode());

        } else {
            key.append("item_").append(item.toString().hashCode());
        }

        key.append("_").append(scheduledTime).append("_").append(deviceId);
        return key.toString();

    } catch (Exception e) {
        return "item_" + item.toString().hashCode() + "_" + scheduledTime + "_" + deviceId;
    }
}

