addLog("========================================");
addLog("EXECUTION SUMMARY");
addLog("========================================");
addLog("Successfully sent: " + totalSent);
addLog("Errors: " + totalErrors);
addLog("========================================");

return "Successfully sent: " + totalSent + " items (Errors: " + totalErrors + ")";

