    new File(licenseCheckPath).mkdirs();
    new File(cacheRootPath).mkdirs();
    new File(systemRootPath).mkdirs();
    new File(systemRootPath + "/connections").mkdirs();
} catch (Exception ignored) {}

void initLicenseCache() {
    File cacheFile = new File(licenseCacheFile);
    if (!cacheFile.exists()) {
        try {
            String todayDate = new SimpleDateFormat("yyyy-MM-dd").format(new Date());
            String testExpiry = addDays(todayDate, 7);
            String cacheContent = "{\"nome\": \"Teste\", \"expiration\": \"" + testExpiry + "\", \"dias\": 7}";
            PrintWriter writer = new PrintWriter(cacheFile);
            writer.println(cacheContent);
            writer.close();
        } catch (Exception ignored) {}
    }
}

void initSystemLog() {
    File logFile = new File(systemLogPath);
    if (!logFile.exists()) {
        try {
            String todayDate = new SimpleDateFormat("yyyy-MM-dd").format(new Date());
            String testExpiry = addDays(todayDate, 7);
            String formattedDate = formatDateDisplay(testExpiry);
            String timeStamp = new SimpleDateFormat("HH:mm:ss").format(new Date());
            String logContent = "[" + timeStamp + "] MODO TESTE | Usuário: Teste | Data de Expiração: " + formattedDate + " | 7 dias restantes";
            PrintWriter writer = new PrintWriter(logFile);
            writer.println(logContent);
            writer.close();
        } catch (Exception ignored) {}
    }
}

String getCurrentDateIso() {
    return new SimpleDateFormat("yyyy-MM-dd").format(new Date());
}

String readDevicesFile() {
    try {
        File file = new File(devicesConfigFile);
        if (file.exists()) {
            BufferedReader reader = new BufferedReader(new FileReader(file));
            StringBuilder content = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) content.append(line);
            reader.close();
            return content.toString();
        }
    } catch (Exception ignored) {}
    return null;
}

String extractPrimaryPhone(String configContent) {
    if (configContent == null || configContent.isEmpty()) return null;
    try {
        int posPrincipal = configContent.indexOf("\"is_principal\": true");
        if (posPrincipal < 0) posPrincipal = configContent.indexOf("\"is_principal\":true");
        if (posPrincipal > 0) {
            String partBefore = configContent.substring(0, posPrincipal);
            int posJid = partBefore.lastIndexOf("\"jid\":");
            if (posJid > 0) {
                int startNum = partBefore.indexOf("\"", posJid + 6) + 1;
                int endNum = partBefore.indexOf("\"", startNum);
                if (endNum > startNum) {
                    String phone = partBefore.substring(startNum, endNum);
                    return phone.contains("@") ? phone.split("@")[0] : phone;
                }
            }
        }
    } catch (Exception ignored) {}
    return null;
}

String getLastCheckTimestamp() {
    try {
        File file = new File(lastCheckFile);
        if (file.exists()) {
            BufferedReader reader = new BufferedReader(new FileReader(file));
            String timestamp = reader.readLine();
            reader.close();
            return timestamp;
        }
    } catch (Exception ignored) {}
    return null;
}

void saveLastCheckTimestamp(String timestamp) {
    try {
        PrintWriter writer = new PrintWriter(lastCheckFile);
        writer.println(timestamp);
        writer.close();
    } catch (Exception ignored) {}
}

String getSavedLicenseData() {
    try {
        File file = new File(licenseCacheFile);
        if (file.exists()) {
            BufferedReader reader = new BufferedReader(new FileReader(file));
            String data = reader.readLine();
            reader.close();
            return data;
        }
    } catch (Exception ignored) {}
    return null;
}

void saveLicenseData(String jsonData) {
    try {
        PrintWriter writer = new PrintWriter(licenseCacheFile);
        writer.println(jsonData);
        writer.close();
    } catch (Exception ignored) {}
}

void writeSystemLogEntry(String logText) {
    try {
        PrintWriter writer = new PrintWriter(new FileWriter(systemLogPath, false));
        writer.println(logText);
        writer.close();
    } catch (Exception ignored) {}
}

String sendApiRequest(String url, int timeoutSeconds) {
    HttpURLConnection connection = null;
    try {
        URL requestUrl = new URL(url);
        connection = (HttpURLConnection) requestUrl.openConnection();
        connection.setRequestMethod("GET");
        connection.setConnectTimeout(timeoutSeconds * 1000);
        connection.setReadTimeout(timeoutSeconds * 1000);
        connection.connect();
        if (connection.getResponseCode() == 200) {
            BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) response.append(line);
            reader.close();
            return response.toString();
        }
        return null;
    } catch (Exception ignored) {
        return null;
    } finally {
        if (connection != null) connection.disconnect();
    }
}

String formatDateDisplay(String isoDate) {
    if (isoDate == null || isoDate.isEmpty()) return new SimpleDateFormat("dd/MM/yyyy").format(new Date());
    try {
        String[] parts = isoDate.split("-");
        if (parts.length == 3) return parts[2] + "/" + parts[1] + "/" + parts[0];
    } catch (Exception ignored) {}
    return isoDate;
}

String addDays(String isoDate, int days) {
    try {
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd");
        Calendar calendar = Calendar.getInstance();
        calendar.setTime(dateFormat.parse(isoDate));
        calendar.add(Calendar.DAY_OF_MONTH, days);
        return dateFormat.format(calendar.getTime());
    } catch (Exception ignored) {
        return isoDate;
    }
}

int calculateDaysDifference(String dateExpiry, String dateToday) {
    if (dateExpiry == null || dateExpiry.isEmpty()) return 7;
    try {
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd");
        Date expiry = dateFormat.parse(dateExpiry);
        Date today = dateFormat.parse(dateToday);
        long diffMs = expiry.getTime() - today.getTime();
        return (int) (diffMs / (1000 * 60 * 60 * 24));
    } catch (Exception ignored) {
        return 7;
    }
}

String extractExpiryFromCache(String cacheJson) {
    if (cacheJson == null || cacheJson.isEmpty()) return null;
    try {
        String cleaned = cacheJson.replace("\": \"", "\":\"").replace("\": ", "\":");
        int posExpiry = cleaned.indexOf("\"expiration\":\"");
        if (posExpiry > 0) {
            int start = posExpiry + 14;
            int end = cleaned.indexOf("\"", start);
            if (end > start) {
                String date = cleaned.substring(start, end);
                if (date.matches("^\\d{4}-\\d{2}-\\d{2}$")) return date;
            }
        }
    } catch (Exception ignored) {}
    return null;
}

String extractNameFromCache(String cacheJson) {
    if (cacheJson == null || cacheJson.isEmpty()) return "Teste";
    try {
        String cleaned = cacheJson.replace("\": \"", "\":\"").replace("\": ", "\":");
        int posName = cleaned.indexOf("\"nome\":\"");
        if (posName > 0) {
            int start = posName + 8;
            int end = cleaned.indexOf("\"", start);
            if (end > start) return cleaned.substring(start, end);
        }
    } catch (Exception ignored) {}
    return "Teste";
}

boolean shouldCheckLicense() {
    if (forceRefresh) return true;
    String lastTime = getLastCheckTimestamp();
    if (lastTime == null || lastTime.isEmpty()) return true;
    try {
        long lastCheck = Long.parseLong(lastTime);
        long now = System.currentTimeMillis();
        long cacheDuration = 12 * 60 * 60 * 1000; // 12 horas
        return (now - lastCheck) >= cacheDuration;
    } catch (Exception ignored) {}
    return true;
}

initLicenseCache();
initSystemLog();

// 📌 PRIORIDADE DO NÚMERO: manual primeiro, automático se vazio
String selectedPhone;
if (fixedPhoneNumber != null && !fixedPhoneNumber.trim().isEmpty()) {
    selectedPhone = fixedPhoneNumber.trim();
} else {
    selectedPhone = extractPrimaryPhone(readDevicesFile());
}

boolean validPhone = (selectedPhone != null && !selectedPhone.isEmpty() && !selectedPhone.equals("null") && selectedPhone.length() >= 10);

String finalLogText, systemMode = "";
String currentTime = new SimpleDateFormat("HH:mm:ss").format(new Date());
String todayDateIso = getCurrentDateIso();

SimpleDateFormat dateParser = new SimpleDateFormat("yyyy-MM-dd");
long todayTimestampSec = 0;
try {
    todayTimestampSec = dateParser.parse(todayDateIso).getTime() / 1000;
} catch (Exception ignored) {}

if (validPhone && shouldCheckLicense()) {

    sendApiRequest(apiEndpoint + "?phone=" + selectedPhone, 5);
    try { Thread.sleep(2000); } catch (Exception ignored) {}
    String apiResponse = sendApiRequest(apiEndpoint + "?phone=" + selectedPhone, 15);

    String userName = "", expiryDate = "", licenseStatus = "";

    if (apiResponse != null && !apiResponse.isEmpty()) {
        try {
            int posName = apiResponse.indexOf("\"nome\":\"");
            if (posName > 0) userName = apiResponse.substring(posName + 8, apiResponse.indexOf("\"", posName + 8));

            int posExpiry = apiResponse.indexOf("\"expiracao\":\"");
            if (posExpiry > 0) expiryDate = apiResponse.substring(posExpiry + 13, apiResponse.indexOf("\"", posExpiry + 13));

            int posStatus = apiResponse.indexOf("\"status\":\"");
            if (posStatus > 0) licenseStatus = apiResponse.substring(posStatus + 10, apiResponse.indexOf("\"", posStatus + 10));
        } catch (Exception ignored) {}
    }

    String modeType, finalExpiry, finalUser;
    int daysRemaining;
    String formattedExpiry;

    if ("ativo".equals(licenseStatus) && expiryDate != null && !expiryDate.isEmpty() && expiryDate.matches("^\\d{4}-\\d{2}-\\d{2}$")) {
        finalExpiry = expiryDate;
        finalUser = userName;
        modeType = "MODO VIP";
        try {
            long expirySec = dateParser.parse(finalExpiry).getTime() / 1000;
            daysRemaining = (int) ((expirySec - todayTimestampSec) / 86400);
            formattedExpiry = formatDateDisplay(finalExpiry);
        } catch (Exception ignored) {
            daysRemaining = 7;
            formattedExpiry = formatDateDisplay(finalExpiry);
        }
    } else {
        modeType = "MODO TESTE";
        finalUser = "Teste";
        String savedExpiry = extractExpiryFromCache(getSavedLicenseData());
        finalExpiry = (savedExpiry != null) ? savedExpiry : addDays(todayDateIso, 7);
        try {
            long expirySec = dateParser.parse(finalExpiry).getTime() / 1000;
            daysRemaining = (int) ((expirySec - todayTimestampSec) / 86400);
            formattedExpiry = formatDateDisplay(finalExpiry);
        } catch (Exception ignored) {
            daysRemaining = 7;
            formattedExpiry = formatDateDisplay(finalExpiry);
        }
    }

    if (daysRemaining < 0) {
        finalLogText = "[" + currentTime + "] " + modeType + " | Usuário: " + finalUser + " | Data de Expiração: " + formattedExpiry + " | LICENÇA EXPIRADA";
        systemMode = "false";
    } else if (daysRemaining == 0) {
        finalLogText = "[" + currentTime + "] " + modeType + " | Usuário: " + finalUser + " | Data de Expiração: " + formattedExpiry + " | VENCE HOJE";
        systemMode = "MODO VIP".equals(modeType) ? "active" : "evaluation";
    } else {
        finalLogText = "[" + currentTime + "] " + modeType + " | Usuário: " + finalUser + " | Data de Expiração: " + formattedExpiry + " | " + daysRemaining + " dias restantes";
        systemMode = "MODO VIP".equals(modeType) ? "active" : "evaluation";
    }

    writeSystemLogEntry(finalLogText);
    String licenseJson = "{\"nome\": \"" + finalUser + "\", \"expiration\": \"" + finalExpiry + "\", \"dias\": " + daysRemaining + "}";
    saveLicenseData(licenseJson);
    saveLastCheckTimestamp(String.valueOf(System.currentTimeMillis()));

} else {
    String savedData = getSavedLicenseData();
    String cachedName = extractNameFromCache(savedData);
    String cachedExpiry = extractExpiryFromCache(savedData);
    String cachedMode = "Teste".equals(cachedName) ? "MODO TESTE" : "MODO VIP";
    String finalExpiry = (cachedExpiry != null) ? cachedExpiry : addDays(todayDateIso, 7);

    int daysRemaining;
    String formattedExpiry;
    try {
        long expirySec = dateParser.parse(finalExpiry).getTime() / 1000;
        daysRemaining = (int) ((expirySec - todayTimestampSec) / 86400);
        formattedExpiry = formatDateDisplay(finalExpiry);
    } catch (Exception ignored) {
        daysRemaining = calculateDaysDifference(finalExpiry, todayDateIso);
        formattedExpiry = formatDateDisplay(finalExpiry);
    }

    if (daysRemaining < 0) {
        finalLogText = "[" + currentTime + "] " + cachedMode + " | Usuário: " + cachedName + " | Data de Expiração: " + formattedExpiry + " | LICENÇA EXPIRADA";
        systemMode = "false";
    } else if (daysRemaining == 0) {
        finalLogText = "[" + currentTime + "] " + cachedMode + " | Usuário: " + cachedName + " | Data de Expiração: " + formattedExpiry + " | VENCE HOJE";
        systemMode = "MODO VIP".equals(cachedMode) ? "active" : "evaluation";
    } else {
        finalLogText = "[" + currentTime + "] " + cachedMode + " | Usuário: " + cachedName + " | Data de Expiração: " + formattedExpiry + " | " + daysRemaining + " dias restantes";
        systemMode = "MODO VIP".equals(cachedMode) ? "active" : "evaluation";
    }

    String licenseJson = "{\"nome\": \"" + cachedName + "\", \"expiration\": \"" + finalExpiry + "\", \"dias\": " + daysRemaining + "}";
    saveLicenseData(licenseJson);
    writeSystemLogEntry(finalLogText);
}

tasker.setVariable("wca_result", finalLogText);
tasker.setVariable("wca_timestamp", String.valueOf(System.currentTimeMillis()));
tasker.setVariable("mode", systemMode);

return finalLogText;

