String jsonValue = tasker.getVariable("json");
if (jsonValue == null || jsonValue.equals("")) {
    jsonValue = "";
}
tasker.setVariable("temp_json", jsonValue);

OkHttpClient client = new OkHttpClient();

String releaseJson = null;
try {
    Request request = new Request.Builder().url(urlApi).build();
    Response response = client.newCall(request).execute();
    if (response.isSuccessful()) {
        releaseJson = response.body().string();
    } else {
        tasker.showToast("Erro ao buscar release: " + response.code());
        return "Error: Falha ao buscar release";
    }
    response.close();
} catch (Exception e) {
    tasker.showToast("Erro na requisição: " + e.getMessage());
    return "Error: " + e.getMessage();
}

JSONObject release = new JSONObject(releaseJson);
JSONArray assets = release.getJSONArray("assets");

String url1 = null;
String url2 = null;
String url3 = null;

for (int i = 0; i < assets.length(); i++) {
    JSONObject asset = assets.getJSONObject(i);
    String name = asset.getString("name");
    String downloadUrl = asset.getString("browser_download_url");

    if (name.equals("go_port_wca-aarch64.bin")) {
        url1 = downloadUrl;
    } else if (name.equals("whatsapp-wca-aarch64.bin")) {
        url2 = downloadUrl;
    } else if (name.equals("ffmpeg-wca-aarch64.bin")) {
        url3 = downloadUrl;
    }
}

if (url1 == null || url2 == null || url3 == null) {
