        for (i = 0; i < results.size(); i++) {
            d = (Map) results.get(i);
            if (d.containsKey("jid")) {
                jid = (String) d.get("jid");
                if (jid != null) {
                    parts = jid.split("@");
                    if (parts.length > 0) {
                        jidPhone = parts[0].replaceAll("\\D", "");
                        if (jidPhone.equals(phone)) {
                            result = (String) d.get("id");
                            break;
                        }
                    }
                }
            }
        }
    }
}

if (result == null || result.isEmpty()) {
