        android.provider.ContactsContract.Contacts.HAS_PHONE_NUMBER,
        android.provider.ContactsContract.Contacts.STARRED
    };

    contactCursor = context.getContentResolver().query(
        lookupUri,
        projection,
        null,
        null,
        null
    );

    if (contactCursor != null && contactCursor.moveToFirst()) {
        lookupKey = contactCursor.getString(
            contactCursor.getColumnIndex(android.provider.ContactsContract.Contacts.LOOKUP_KEY)
        );
        hasPhone = contactCursor.getInt(
            contactCursor.getColumnIndex(android.provider.ContactsContract.Contacts.HAS_PHONE_NUMBER)
        ) > 0;
        starred = contactCursor.getInt(
            contactCursor.getColumnIndex(android.provider.ContactsContract.Contacts.STARRED)
        ) > 0;
    }
} catch (Exception e) {
