                company = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
            } else if (mimeType.equals("vnd.android.cursor.item/postal-address_v2")) {
                address = dataCursor.getString(
