                addressMap.put("type", String.valueOf(addressType));
                addressesList.add(addressMap);
            } else if (mimeType.equals("vnd.android.cursor.item/contact_event")) {
                birthday = dataCursor.getString(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
                );
                eventType = dataCursor.getInt(
                    dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA2)
                );
                if (eventType == 3) {
                    birthday = dataCursor.getString(
                        dataCursor.getColumnIndex(android.provider.ContactsContract.Data.DATA1)
