cleanBrazilianNumber(number) {
    cleaned = number.replaceAll("[^0-9]", "");

    tasker.log("Cleaning number: " + cleaned);

    if (cleaned.startsWith("0") && cleaned.length() >= 11) {
        if (cleaned.substring(0, 3).matches("0[0-9]{2}")) {
            cleaned = cleaned.substring(3);
            tasker.log("Removed interurban prefix (0+DDD): " + cleaned);
        } else if (cleaned.substring(0, 4).matches("0[0-9]{3}")) {
            cleaned = cleaned.substring(4);
            tasker.log("Removed interurban prefix (0+DDD): " + cleaned);
        } else {
            cleaned = cleaned.substring(1);
            tasker.log("Removed leading 0: " + cleaned);
        }
    }

    if (cleaned.startsWith("55") && cleaned.length() >= 10) {
        return cleaned;
    }

    if ((cleaned.length() == 10 || cleaned.length() == 11) && !cleaned.startsWith("55")) {
        cleaned = "55" + cleaned;
        tasker.log("Added 55: " + cleaned);
        return cleaned;
    }

    if ((cleaned.length() == 12 || cleaned.length() == 13) && !cleaned.startsWith("55")) {
        ddd = cleaned.substring(0, 2);
        rest = cleaned.substring(2);

        if (rest.length() == 11 && rest.substring(0, 1).equals("9")) {
            rest = rest.substring(1);
            cleaned = "55" + ddd + rest;
        } else if (rest.length() == 10) {
            cleaned = "55" + ddd + rest;
        } else {
            cleaned = "55" + cleaned;
        }
        tasker.log("Extracted DDD: " + ddd + " -> " + cleaned);
        return cleaned;
    }

    return cleaned;
}

generatePhoneVariations(phoneNumber) {
    cleaned = cleanBrazilianNumber(phoneNumber);

    tasker.log("Generating variations for: " + cleaned);

    variations = new java.util.ArrayList();

    if (cleaned.startsWith("55") && cleaned.length() >= 12) {
        without55 = cleaned.substring(2);
        ddd = without55.substring(0, 2);
        numberPart = without55.substring(2);

        tasker.log("DDD: " + ddd + ", Number: " + numberPart);

        if (numberPart.length() == 8) {
            variations.add("55" + ddd + numberPart);
            with9 = "9" + numberPart;
            variations.add("55" + ddd + with9);
        } else if (numberPart.length() == 9) {
            without9 = numberPart.substring(1);
            variations.add("55" + ddd + without9);
            variations.add("55" + ddd + numberPart);
        } else {
            variations.add(cleaned);
        }
    } else if (cleaned.length() >= 10 && cleaned.length() <= 11 && !cleaned.startsWith("55")) {
        ddd = cleaned.substring(0, 2);
        rest = cleaned.substring(2);

        if (rest.length() == 8) {
            variations.add("55" + ddd + rest);
            variations.add("55" + ddd + "9" + rest);
        } else if (rest.length() == 9) {
            variations.add("55" + ddd + rest.substring(1));
            variations.add("55" + ddd + rest);
        } else {
            variations.add("55" + cleaned);
        }
    } else {
        variations.add(cleaned);
    }

    uniqueVariations = new java.util.ArrayList();
    for (i = 0; i < variations.size(); i++) {
        num = (String) variations.get(i);
        if (!uniqueVariations.contains(num)) {
            uniqueVariations.add(num);
        }
    }

    tasker.log("Generated " + uniqueVariations.size() + " variation(s), in try-order:");
    for (i = 0; i < uniqueVariations.size(); i++) {
        tasker.log("  [" + i + "] " + (String) uniqueVariations.get(i));
    }

    return uniqueVariations;
}

hasContactPhoto(contactId) {
    rawIds = new java.util.ArrayList();

    rawContactCursor = context.getContentResolver().query(
        ContactsContract.RawContacts.CONTENT_URI,
        new String[]{ContactsContract.RawContacts._ID},
        ContactsContract.RawContacts.CONTACT_ID + " = ?",
        new String[]{String.valueOf(contactId)},
        null
    );

    if (rawContactCursor != null) {
        while (rawContactCursor.moveToNext()) {
            rawIds.add(rawContactCursor.getLong(0));
        }
        rawContactCursor.close();
    }

    hasPhoto = false;
    for (i = 0; i < rawIds.size() && !hasPhoto; i++) {
        rawId = (Long) rawIds.get(i);

        photoCursor = context.getContentResolver().query(
            ContactsContract.Data.CONTENT_URI,
            new String[]{ContactsContract.Data._ID, ContactsContract.Data.DATA15},
            ContactsContract.Data.RAW_CONTACT_ID + "=? AND " + ContactsContract.Data.MIMETYPE + "=?",
            new String[]{String.valueOf(rawId), CommonDataKinds.Photo.CONTENT_ITEM_TYPE},
            null
        );

        if (photoCursor != null) {
            if (photoCursor.moveToFirst()) {
                try {
                    photoData = photoCursor.getBlob(photoCursor.getColumnIndex(ContactsContract.Data.DATA15));
                    if (photoData != null && photoData.length > 0) {
                        hasPhoto = true;
                        tasker.log("Found photo data with size: " + photoData.length + " bytes");
                    } else {
                        tasker.log("Photo record found but data is empty (size: 0)");
                    }
                } catch (Exception e) {
                    tasker.log("Error reading photo data: " + e.getMessage());
                }
            }
            photoCursor.close();
        }
    }

    return hasPhoto;
}

