import android.view.accessibility.AccessibilityEvent;
import android.view.accessibility.AccessibilityNodeInfo;
import android.accessibilityservice.AccessibilityService;
import java.util.List;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

// Validação da ativação do serviço de acessibilidade
AccessibilityService service = tasker.getAccessibilityService();
if (service == null) {
    throw new JavaCodeException("Serviço de Acessibilidade não ativo.");
}

// Aguarda 1200 milissegundos antes de iniciar as ações de clique
android.os.SystemClock.sleep(1200);

// Configuração de retorno padrão e tempo limite de monitoramento (30 segundos)
String result = "timeout";
long endTime = System.currentTimeMillis() + 30000; 

tasker.log("Iniciando monitoramento multi-idioma...");

// Loop principal de execução até o tempo limite ser atingido
while (System.currentTimeMillis() < endTime) {
    AccessibilityNodeInfo root = service.getRootInActiveWindow();

    if (root != null) {
        // Captura de todos os elementos da interface atual
        List nodes = service.getChildrenRecursive(root);
        boolean dialogoAtivo = false;
        boolean clicouNestaPassada = false;

        for (int i = 0; i < nodes.size(); i++) {
            AccessibilityNodeInfo node = (AccessibilityNodeInfo) nodes.get(i);
            if (node == null) continue;

            // Identificação e clique via ID de recurso (padrão de sistema Android para botões positivos)
            String viewId = node.getViewIdResourceName();
            if (viewId != null && (viewId.contains("button1") || viewId.contains("button_positive"))) {
                if (node.isClickable()) {
                    node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                    clicouNestaPassada = true;
                    tasker.log("Clique por ID Universal efetuado.");
                }
            }

            // Identificação e clique via texto (mapeamento multi-idioma)
            if (node.getText() != null) {
                String t = node.getText().toString().toUpperCase().trim();

                // Verificação de termos que indicam a presença do diálogo de importação
                if (t.contains("TASKER") || t.contains("IMPORT") || t.contains("PROJET")) {
                    dialogoAtivo = true;
                }

                // Lista de termos para cliques de confirmação em múltiplos idiomas
                if (t.equals("SIM") || t.equals("YES") || t.equals("OK") || t.equals("SÍ") || 
                    t.equals("ДА") || t.equals("SÍ") || t.equals("SÌ") || t.equals("是") || t.equals("确定") ||
                    t.equals("SUBSTITUIR") || t.equals("REPLACE") || t.equals("OVERWRITE") ||
                    t.equals("CONTINUAR") || t.equals("CONTINUE")) {

                    if (node.isClickable()) {
                        node.performAction(AccessibilityNodeInfo.ACTION_CLICK);
                        clicouNestaPassada = true;
                        tasker.log("Clique por texto efetuado: " + t);
                    }
                }

                // Detecção de retorno à tela principal para definir conclusão
                if (t.contains("PROJECTS") || t.contains("PROJETOS") || t.contains("TASKS") || t.contains("TAREFAS")) {
                    if (!clicouNestaPassada) {
                        result = "imported";
                    }
                }
            }
        }

        // Finalização do loop após sucesso detectado e ausência de novos cliques
        if (result.equals("imported") && !clicouNestaPassada) {
            android.os.SystemClock.sleep(1000); 
            break; 
        }
    }
    // Intervalo de varredura para controle de consumo de CPU
    android.os.SystemClock.sleep(400); 
}

return result;

import org.json.JSONObject;
import org.json.JSONArray;
import com.joaomgcd.taskerm.action.java.JavaCodeException;

httpRequestBody = tasker.getVariable("http_request_body");

try {
    data = new JSONObject(httpRequestBody);

    // Campos principais do nível raiz
    if (data.has("recebido_em")) {
        tasker.setVariable("recebido_em", data.optString("recebido_em", ""));
    } else {
        tasker.setVariable("recebido_em", "");
    }

    if (data.has("origem")) {
        tasker.setVariable("origem", data.optString("origem", ""));
    } else {
        tasker.setVariable("origem", "");
    }

    if (data.has("metodo")) {
        tasker.setVariable("metodo", data.optString("metodo", ""));
    } else {
        tasker.setVariable("metodo", "");
    }

    if (data.has("url_original")) {
        tasker.setVariable("url_original", data.optString("url_original", ""));
    } else {
        tasker.setVariable("url_original", "");
    }

    if (data.has("porta_origem")) {
        tasker.setVariable("porta_origem", data.optString("porta_origem", ""));
    } else {
        tasker.setVariable("porta_origem", "");
    }

    if (data.has("porta_destino")) {
        tasker.setVariable("porta_destino", data.optString("porta_destino", ""));
    } else {
        tasker.setVariable("porta_destino", "");
    }

    // Processa o body principal
    if (data.has("body")) {
        body = data.optJSONObject("body");
        if (body != null) {

            // DeviceID
            if (body.has("DeviceID")) {
                String rawDeviceId = body.optString("DeviceID", "");
                String cleanDeviceId = rawDeviceId;
                if (rawDeviceId.contains("@")) {
                    cleanDeviceId = rawDeviceId.substring(0, rawDeviceId.indexOf("@"));
                }
                tasker.setVariable("device_id", cleanDeviceId);
                tasker.setVariable("phone", cleanDeviceId);
            } else {
                tasker.setVariable("device_id", "");
                tasker.setVariable("phone", "");
            }

            // Event
            event = body.optString("Event", "");
            if (body.has("Event")) {
                tasker.setVariable("event", event);
            } else {
                tasker.setVariable("event", "");
            }

            // Timestamp do body
            if (body.has("Timestamp")) {
                tasker.setVariable("timestamp_body", body.optString("Timestamp", ""));
            } else {
                tasker.setVariable("timestamp_body", "");
            }

            // Processa o payload
            if (body.has("Payload")) {
                p = body.optJSONObject("Payload");
                if (p != null) {

                    // ChatID
                    if (p.has("ChatID")) {
                        String chatIdValue = p.optString("ChatID", "");
                        tasker.setVariable("chat_id", chatIdValue);

                        String recipientNumberRaw = chatIdValue;
                        if (recipientNumberRaw.endsWith("@s.whatsapp.net")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (recipientNumberRaw.endsWith("@g.us")) {
                            recipientNumberRaw = recipientNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("recipient_number", recipientNumberRaw);
                    } else {
                        tasker.setVariable("chat_id", "");
                        tasker.setVariable("recipient_number", "");
                    }

                    // ChatLid / FromLid
                    if (p.has("ChatLid")) {
                        tasker.setVariable("from_lid", p.optString("ChatLid", ""));
                    } else if (p.has("FromLid")) {
                        tasker.setVariable("from_lid", p.optString("FromLid", ""));
                    } else {
                        tasker.setVariable("from_lid", "");
                    }

                    // From
                    if (p.has("From")) {
                        String fromRaw = p.optString("From", "");
                        String senderNumberRaw = fromRaw;
                        if (senderNumberRaw.endsWith("@s.whatsapp.net")) {
                            senderNumberRaw = senderNumberRaw.replace("@s.whatsapp.net", "");
                        } else if (senderNumberRaw.endsWith("@g.us")) {
                            senderNumberRaw = senderNumberRaw.replace("@g.us", "");
                        }
                        tasker.setVariable("sender_number", senderNumberRaw);
                    } else {
                        tasker.setVariable("sender_number", "");
                    }

                    // FromName
                    if (p.has("FromName")) {
