youtubePackageNames.add("com.github.libretube");
youtubePackageNames.add("free.youtubemusic.player");
youtubePackageNames.add("com.yt.music.player");
youtubePackageNames.add("com.music.youtube.player");
youtubePackageNames.add("com.smart.tube");
youtubePackageNames.add("com.smart.tube.beta");
youtubePackageNames.add("com.liskovsoft.smarttubetv");
youtubePackageNames.add("com.liskovsoft.smarttubetv.beta");
youtubePackageNames.add("com.ogmods.yt");
youtubePackageNames.add("com.mods.youtube");
youtubePackageNames.add("com.protube.android");
youtubePackageNames.add("com.youtube.premium.mod");

/* Query for all activities that can handle this intent. */
/* Removed PackageManager.MATCH_DEFAULT_ONLY to find all matching apps, not just default ones. */
List allResolveInfoList = packageManager.queryIntentActivities(viewIntent, 0);

/* Prepare lists for the dialog, filtered by our desired YouTube packages. */
List filteredAppNames = new ArrayList();
List filteredYoutubeApps = new ArrayList();

/* Populate the lists with app names and their ResolveInfo, if they are in our desired list. */
if (allResolveInfoList != null) {
    for (int i = 0; i < allResolveInfoList.size(); i++) {
        ResolveInfo info = (ResolveInfo) allResolveInfoList.get(i);
        String packageName = info.activityInfo.packageName;

        /* Get the app label and package name in lowercase for case-insensitive search. */
        String appLabel = info.loadLabel(packageManager).toString().toLowerCase();
        String appPackageName = packageName.toLowerCase();

        /* Check if the package is in our predefined list or if its label/package name contains "youtube" or "mod". */
        boolean isYoutubeRelated = youtubePackageNames.contains(packageName) ||
                                   appLabel.contains("youtube") ||
                                   appLabel.contains("mod") ||
                                   appPackageName.contains("youtube") ||
                                   appPackageName.contains("mod");

        if (isYoutubeRelated) {
            /* Get the application label for display in the dialog. */
            filteredAppNames.add(info.loadLabel(packageManager).toString());
            filteredYoutubeApps.add(info);
        }
    }
}

/* Check if any desired YouTube apps were found. */
if (filteredYoutubeApps.isEmpty()) {
    /* No desired YouTube apps found, try to open in Chrome. */
    Intent chromeIntent = new Intent(Intent.ACTION_VIEW, videoUri);
    chromeIntent.setPackage("com.android.chrome");
    chromeIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);

    /* Check if Chrome can handle the intent. */
    List chromeResolveInfo = packageManager.queryIntentActivities(chromeIntent, PackageManager.MATCH_DEFAULT_ONLY);

    if (chromeResolveInfo != null && !chromeResolveInfo.isEmpty()) {
        /* Chrome is available, launch it. */
        context.startActivity(chromeIntent);
        return "chrome";
    } else {
        /* Neither desired YouTube apps nor Chrome found. */
        throw new JavaCodeException("Nenhum aplicativo de YouTube ou Chrome encontrado para abrir o link.");
    }
}

/* Create a SingleSubject to get the result from the dialog. */
/* It will emit the package name of the selected app or "canceled" or "timeout". */
resultSignal = SingleSubject.create();

/* Create a Consumer to build and show the dialog using the Activity. */
myActivityConsumer = new Consumer() {
    accept(Object activity) {
        /* Cast the raw Object to Activity. */
        final Activity currentActivity = (Activity) activity;

        /* Convert the list of app names to a CharSequence array for the dialog. */
        CharSequence[] items = (CharSequence[]) filteredAppNames.toArray(new CharSequence[filteredAppNames.size()]);

        /* Disposable for the timeout timer. Use array for final reference. */
        final Disposable[] timeoutDisposable = new Disposable[1];

        /* Define what happens when the user clicks an item in the dialog. */
        onItemClickListener = new DialogInterface.OnClickListener() {
            onClick(DialogInterface dialog, int which) {
                /* Dispose of the timeout timer if it's still active. */
                if (timeoutDisposable[0] != null && !timeoutDisposable[0].isDisposed()) {
                    timeoutDisposable[0].dispose();
                }

                /* Get the selected ResolveInfo. */
                ResolveInfo selectedInfo = (ResolveInfo) filteredYoutubeApps.get(which);

                /* Get the package name of the selected app. */
                String packageName = selectedInfo.activityInfo.packageName;

                /* Create a new intent specifically for the selected package. */
                /* Setting only the package name allows the app to choose its preferred activity for ACTION_VIEW. */
                Intent launchIntent = new Intent(Intent.ACTION_VIEW, videoUri);
                launchIntent.setPackage(packageName);
                /* FLAG_ACTIVITY_NEW_TASK is good practice when launching from a non-Activity context. */
                launchIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK); 

                /* Launch the selected app. */
                currentActivity.startActivity(launchIntent);

                /* Signal the waiting script with the package name. */
                resultSignal.onSuccess(packageName);

                /* CRITICAL: Finish the activity now that the UI is done. */
                currentActivity.finish();
            }
        };

        /* Define what happens if the user cancels the dialog. */
        onCancelListener = new DialogInterface.OnClickListener() {
            onClick(DialogInterface dialog, int which) {
                /* Dispose of the timeout timer if it's still active. */
                if (timeoutDisposable[0] != null && !timeoutDisposable[0].isDisposed()) {
                    timeoutDisposable[0].dispose();
                }
                /* Signal the waiting script that the action was canceled. */
                resultSignal.onSuccess("canceled");
                /* CRITICAL: Finish the activity. */
                currentActivity.finish();
            }
        };

        /* Build the AlertDialog. */
        AlertDialog.Builder builder = new AlertDialog.Builder(currentActivity);
        builder.setTitle("Abrir vídeo do YouTube com:");
        builder.setItems(items, onItemClickListener);
        builder.setNegativeButton("Cancelar", onCancelListener);
        builder.setCancelable(false); /* Prevent dismissing without a choice or cancel. */
        final AlertDialog dialog = builder.create(); /* Store dialog reference */
        dialog.show();

        /* Start a timeout timer (20 seconds). */
        timeoutDisposable[0] = Completable.timer(20, TimeUnit.SECONDS)
            .subscribe(new Action() {
                run() {
                    /* This runs if the timer expires before a choice is made. */
                    /* Dismiss the dialog if it's still showing. */
                    if (dialog != null && dialog.isShowing()) {
                        dialog.dismiss();
                    }
                    /* Signal timeout to the waiting script. */
                    resultSignal.onSuccess("timeout");
                    /* Finish the activity. */
                    currentActivity.finish();
                }
            });
    }
};

/* Execute the consumer to show the dialog on the main thread. */
tasker.doWithActivity(myActivityConsumer);

/* Block the script and wait for the signal from the dialog listener or timeout. */
selectedPackage = resultSignal.blockingGet();

/* Return the package name of the selected app, "canceled", or "timeout". */
return selectedPackage;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;
import java.util.ArrayList;
import java.util.Map;
import java.util.HashMap;
import org.json.JSONArray;
import org.json.JSONObject;

String basePath = "/storage/emulated/0/Tasker/projects_task/projects/whats-connect-api/system/broadcast-master/";
String jsonStatusPath = basePath + "json-status.json";

String readJsonFile(String filePath) {
    try {
        File file = new File(filePath);
        if (file.exists()) {
            return new String(Files.readAllBytes(Paths.get(filePath)));
        }
    } catch (Exception e) {
        tasker.log("Error reading file: " + filePath + " - " + e.getMessage());
    }
    return null;
}

void writeJsonFile(String filePath, String content) {
    try {
        Files.write(Paths.get(filePath), content.getBytes());
    } catch (Exception e) {
        tasker.log("Error writing file: " + filePath + " - " + e.getMessage());
    }
}

String jsonContent = readJsonFile(jsonStatusPath);
Map rootData = new HashMap();
List itemsList = new ArrayList();

if (jsonContent != null && jsonContent.length() > 0) {
    try {
        JSONObject jsonObject = new JSONObject(jsonContent);

        if (jsonObject.has("devices")) {
            JSONArray devicesArray = jsonObject.getJSONArray("devices");
            List devicesList = new ArrayList();
            for (int i = 0; i < devicesArray.length(); i++) {
                JSONObject deviceObj = devicesArray.getJSONObject(i);
                Map deviceMap = new HashMap();
                if (deviceObj.has("device_id")) deviceMap.put("device_id", deviceObj.getString("device_id"));
                if (deviceObj.has("device_phone")) deviceMap.put("device_phone", deviceObj.getString("device_phone"));
                devicesList.add(deviceMap);
            }
            rootData.put("devices", devicesList);
        } else {
            rootData.put("devices", new ArrayList());
        }

        if (jsonObject.has("items")) {
            JSONArray itemsArray = jsonObject.getJSONArray("items");
            for (int i = 0; i < itemsArray.length(); i++) {
                JSONObject itemObj = itemsArray.getJSONObject(i);
                Map itemMap = new HashMap();

                if (itemObj.has("type")) itemMap.put("type", itemObj.getString("type"));

                if (itemObj.has("schedule")) {
                    JSONObject scheduleObj = itemObj.getJSONObject("schedule");
                    Map scheduleMap = new HashMap();

                    if (scheduleObj.has("days")) {
                        JSONArray daysArray = scheduleObj.getJSONArray("days");
                        List daysList = new ArrayList();
                        for (int j = 0; j < daysArray.length(); j++) {
                            daysList.add(daysArray.getString(j));
                        }
                        scheduleMap.put("days", daysList);
                    } else {
                        scheduleMap.put("days", new ArrayList());
                    }

                    if (scheduleObj.has("times")) {
                        JSONArray timesArray = scheduleObj.getJSONArray("times");
                        List timesList = new ArrayList();
                        for (int j = 0; j < timesArray.length(); j++) {
                            timesList.add(timesArray.getString(j));
                        }
                        scheduleMap.put("times", timesList);
                    } else {
                        scheduleMap.put("times", new ArrayList());
                    }

                    itemMap.put("schedule", scheduleMap);
                } else {
                    Map scheduleMap = new HashMap();
                    scheduleMap.put("days", new ArrayList());
                    scheduleMap.put("times", new ArrayList());
                    itemMap.put("schedule", scheduleMap);
                }

                String type = itemObj.has("type") ? itemObj.getString("type") : "";

                if (type.equals("text")) {
                    if (itemObj.has("message")) itemMap.put("message", itemObj.getString("message"));
                } else if (type.equals("video")) {
                    if (itemObj.has("path")) itemMap.put("path", itemObj.getString("path"));
                    if (itemObj.has("caption")) itemMap.put("caption", itemObj.getString("caption"));
                } else if (type.equals("image")) {
                    // Keep image items but don't modify them
                    if (itemObj.has("path")) itemMap.put("path", itemObj.getString("path"));
                    if (itemObj.has("caption")) itemMap.put("caption", itemObj.getString("caption"));
                }

                itemsList.add(itemMap);
            }
        }

    } catch (Exception e) {
        tasker.log("Error parsing JSON: " + e.getMessage());
        rootData.put("devices", new ArrayList());
        itemsList = new ArrayList();
    }
} else {
    rootData.put("devices", new ArrayList());
    itemsList = new ArrayList();
}

String inputPathsString = tasker.getVariable("input");
String inputCaption = tasker.getVariable("caption");

if (inputCaption == null) inputCaption = "";

if (inputPathsString != null && inputPathsString.length() > 0) {
    String[] newPaths = inputPathsString.split(",");

    for (int i = 0; i < newPaths.length; i++) {
        String path = newPaths[i].trim();
        if (path.length() == 0) {
            continue;
        }

        // Validate video extension (only MP4 or 3GP)
        String lowerPath = path.toLowerCase();
        boolean isValidVideo = lowerPath.endsWith(".mp4") || lowerPath.endsWith(".3gp");

        if (!isValidVideo) {
            tasker.log("Invalid video format (only MP4 or 3GP): " + path);
            continue;
        }

        boolean pathExists = false;
        for (int j = 0; j < itemsList.size(); j++) {
            Map existingItem = (Map) itemsList.get(j);
            String existingPath = (String) existingItem.get("path");
            if (existingPath != null && path.equals(existingPath)) {
                pathExists = true;
                break;
            }
        }

        if (!pathExists) {
            Map newItem = new HashMap();
            newItem.put("type", "video");

            Map schedule = new HashMap();
            schedule.put("days", new ArrayList());
            schedule.put("times", new ArrayList());
            newItem.put("schedule", schedule);

            newItem.put("path", path);
            newItem.put("caption", inputCaption);

            itemsList.add(newItem);
            tasker.log("New video added: " + path);
        } else {
            tasker.log("Video already exists, ignored: " + path);
        }
    }
}

rootData.put("items", itemsList);

String updatedJson = tasker.toJson(rootData, true);

writeJsonFile(jsonStatusPath, updatedJson);

return "Video(s) added successfully! Total items: " + itemsList.size();

