        Request headReq = new Request.Builder().url(url).head().build();
        Response headRes = client.newCall(headReq).execute();
        if (headRes.isSuccessful()) totalBytes = headRes.body().contentLength();
        headRes.close();
    } catch (Exception e) {}
}

if (totalBytes <= 0) {
    totalBytes = 10 * 1024 * 1024;
}

boolean downloadFile(String urlStr, String filePathStr, String displayName, long[] downloaded, int[] lastPct, long totalBytes, long fileSize) {
    File destFile = new File(filePathStr);
    File parentDir = destFile.getParentFile();
    if (parentDir != null && !parentDir.exists()) parentDir.mkdirs();
    if (destFile.exists()) destFile.delete();

    Request request = new Request.Builder().url(urlStr).build();
    Response response = null;
    InputStream inputStream = null;
    FileOutputStream outputStream = null;

    try {
        response = client.newCall(request).execute();
        if (!response.isSuccessful()) {
            tasker.showToast("HTTP Error " + response.code() + ": " + displayName);
            return false;
        }
        ResponseBody body = response.body();
        if (body == null) {
            tasker.showToast("Response body null: " + displayName);
            return false;
        }
        inputStream = body.byteStream();
        outputStream = new FileOutputStream(destFile);

        byte[] buffer = new byte[1024 * 5];
        int bytesRead;
        long fileDownloaded = 0;
        int partCount = 0;

        while ((bytesRead = inputStream.read(buffer)) != -1) {
            if (bytesRead == 0) continue;
            outputStream.write(buffer, 0, bytesRead);
            fileDownloaded += bytesRead;
            downloaded[0] += bytesRead;
            partCount++;

            int currentPercent = (int) ((downloaded[0] * 100L) / totalBytes);
            if (currentPercent > 100) currentPercent = 100;
            if (currentPercent < 0) currentPercent = 0;

            if ((currentPercent >= lastPct[0] + 1 || partCount % 2 == 0) && currentPercent != lastPct[0] && currentPercent < 100) {
                lastPct[0] = currentPercent;
                String percentStr = String.valueOf(currentPercent);
                tasker.setVariable("progress_install", percentStr);
                tasker.setVariable("par1", "installation_upgrade");

                HashMap taskArgs = new HashMap();
                taskArgs.put("progress_install", percentStr);
                taskArgs.put("par1", "installation_upgrade");
                tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgs);

                try {
                    Thread.sleep(50);
                } catch (InterruptedException e) {}
            }
        }
        outputStream.flush();

        if (fileSize > 0 && fileDownloaded < fileSize) {
            tasker.showToast("Tamanho incorreto: " + displayName);
            return false;
        }

        return true;
    } catch (IOException e) {
        tasker.showToast("Download error: " + e.getMessage() + " - " + displayName);
        if (destFile.exists()) destFile.delete();
        return false;
    } finally {
        try { if (inputStream != null) inputStream.close(); } catch (IOException e) {}
        try { if (outputStream != null) outputStream.close(); } catch (IOException e) {}
        try { if (response != null) response.close(); } catch (IOException e) {}
    }
}

long[] downloadedBytes = new long[]{0};
int[] lastPercent = new int[]{-1};

HashMap taskArgsStart = new HashMap();
taskArgsStart.put("progress_install", "0");
taskArgsStart.put("par1", "installation_upgrade");
tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgsStart);

boolean success = downloadFile(url, filePath, "W_C_A_API.prj.xml", downloadedBytes, lastPercent, totalBytes, fileSize);

if (success) {
    String finalJson = tasker.getVariable("temp_json");
    if (finalJson == null || finalJson.equals("")) {
        finalJson = "";
    }

    HashMap taskArgsFinal = new HashMap();
    taskArgsFinal.put("progress_install", "100");
    taskArgsFinal.put("json", finalJson);
    taskArgsFinal.put("par1", "installation_upgrade");
    tasker.callTask("006-CONFIGURAR_SISTEMA [wca]", taskArgsFinal);
    return "Success: File downloaded";
} else {
    tasker.showToast("Error: Download failed");
    return "Error: Download failed";
}
